head.script:
// 세션정보 가져오기
scwin.sUserId = $c.data.getMemInfo("userId");
scwin.sUserNm = $c.data.getMemInfo("userNm");
scwin.sLobranCd = $c.data.getMemInfo("lobranCd");

// 사용자 가져오기 
scwin.sUserMpNo = $c.data.getMemInfo("userMpNo"); // UserDTO 에서 갖고온다. 


// 현재일자 
scwin.strCurDate = $c.date.getServerDateTime();

scwin.odrKndCd = "";   // 오더종류코드 - 오더종류콤보 onSelChange이벤트에서 값 세팅
scwin.impExpClsCd = "";   // 수출입내수구분코드 - 오더종류콤보 onSelChange이벤트에서 값 세팅
scwin.statusFlag = "";   // 수정/등록 Flag(C:Regist, U:Update)
scwin.chkInputQtyYn = "N";  // 컨테이너 입력 여부 - 수입본선인 경우, 본선관리번호로 컨테이너정보 가져왔을 때 컨테이너정보프로세스(tr_retrieveCntrBasisInfo)를 태우지 않기 위한 flag
scwin.retrieveYn = "N";  // 조회여부
scwin.btnPos = "";   // 어느 버튼을 클릭했는지 체크(A:AddRow, D:DeleteRow, U:UndoRow)
scwin.orgCommVal = "";   // 품명그리드에서 size,type,FE콤보에서 dropdown이벤트 발생시 값세팅하기 위한 변수, 이 변수를 closeUp이벤트에서 사용
scwin.bookingNoYn = "N";  // bookingNo입력 여부
scwin.bkCommInfoRows = 0;    // 오더번호로 조회한 후, bookingNo에 해당하는 품명정보 row수
scwin.selfClsCd = "";   // 자가구분코드 - 자가구분콤보 onSelChange이벤트에서 값 세팅
scwin.assgnWhouseCd = "";   // 수입일반인 경우 : bl팝업에서 배정구분코드의 첫째자리가 'B'인 경우, 배정창고코드를 가져온다.
scwin.assgnWhouseNm = "";   // 수입일반인 경우 : bl팝업에서 배정구분코드의 첫째자리가 'B'인 경우, 배정창고코드명을 가져온다.
scwin.orgLineCd = "";   // 수정하기 전의 Line코드값 세팅(수출일반인 경우, booking정보 가져올 때 사용)
scwin.orgBookingNo = "";   // 수정하기 전의 BookingNo값 세팅(수출일반인 경우, booking정보 가져올 때 사용)
scwin.mgntTrgtClntYn = 0;    // 거래처 관리대상여부
scwin.excelUploadYn = 0;    // EXCEL UPLOAD (C3) 여부 
scwin.odrCtrlClsCd = "";   // TS구분 -01적하,02비적하
scwin.cntrLoadGubun = "";   // 컨테이너 적재 구분
scwin.MSG_CM_CRM_199 = "컨테이너 마스터를 CHECK 하지 않겠습니까?"; // 오타 교정: 않겠습니까?
scwin.first_YN = 0;
scwin.first_bilgClntNo = "";

// hidden 
// scwin.ed_alloccarPicNm2 = "";  //배차담당 
// scwin.ed_alloccarPicNm3 = "";  //배차담당 
// scwin.ed_alloccarPicNm4 = "";  //배차담당 
// scwin.ed_alloccarPicNm5 = "";  //배차담당 

scwin.hid_chkReterieve = "";
scwin.hid_chkMode = "";
scwin.hid_alloccarPicId1 = "";
scwin.hid_alloccarPicId2 = "";
scwin.hid_alloccarPicId3 = "";
scwin.hid_alloccarPicId4 = "";
scwin.hid_alloccarPicId5 = "";

scwin.sellBilgPNoDataCloseTF = "";

// 그리드 팝업 공통 변수
scwin.ds = "";
scwin.row = "";
scwin.cdColid = ""; 
scwin.nmColid = "";

// 그리드별로 직전 인덱스를 저장할 변수 생성
scwin.gr_commInfo_lastRowIndex = -1;

scwin.gr_commInfo_validConfig = [];
scwin.gr_cntrInfo_validConfig = [];

scwin.onpageload = function () {
    //그리드에서 필요한 공통코드 조회(Size, Type, Full/Empty, B/O)
    scwin.f_retrieveGridLookup();
};

scwin.onUdcCompleted = function () {
    // 복사대상selectBox 초기화
    lc_cntrItemRow.setSelectedIndex(-1);

    // udc_search 가 UDC의 ID이고, 그 안에 ed_lineCd가 있는 경우
    //var comp = udc_lineCd.getComponent("ed_lineCd");
    var comp = $p.getComponentById('ed_lineCd');

    if (comp) {
        comp.bind("onfocus", function(e) {
            scwin.orgLineCd = ed_lineCd.getValue();
        });
    }
};

scwin.ondataload = function () {
    let dltStr = "";
    let dlt = "";

    dltStr = "dlt_commonCodeSD113"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd3 == '1'");  //$c.data.dataListFilter 함수를 이용해서 필터

    $c.gus.cfCopyDataSet(dlt, ds_odrKndCd);

    dltStr = "dlt_commonCodeSD114"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd1 == 'C' || fltrCd1 == 'A'");  //$c.data.dataListFilter 함수를 이용해서 필터

    dltStr = "dlt_commonCodeSD125"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd1 == '1'");  //$c.data.dataListFilter 함수를 이용해서 필터

    if ($p.parent().tac_cont.activeStatus == 'active') {
        $p.parent().scwin.f_selectTabMenu(0); // 상위 Tab 페이지의 초기화가 완료되었을때

        if ($p.parent().scwin.hid_odrNo == "" && $p.parent().scwin.hid_chkReterieve.trim() != "create") {
            // $p.setTimeout(function() {
                scwin.f_set("INIT", "CREATE"); //초기화

                ed_alloccarPicId.hide();
            // }, {"delay" : 300});
    	}
    }
};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_retrieveGridLookup = function () {
    const codeOptions = [
        {grpCd: "SD113", compID: "acb_odrKndCd, acb_cnd_odrKndCd", opt: { "range": "1, C" }},
        {grpCd: "OP101", compID: "gr_commInfo:cntrSizCd, gr_cntrInfo:cntrSizCd"},
        {grpCd: "OP102", compID: "gr_commInfo:cntrTypCd, gr_cntrInfo:cntrTypCd"},
        {grpCd: "OP171", compID: "gr_commInfo:fullEmptyClsCd, gr_cntrInfo:fullEmptyClsCd"},
        {grpCd: "OP196", compID: "gr_cntrInfo:impCntrWrkKndCd"},
        {grpCd: "SD114", compID: "acb_selfClsCd"},
        {grpCd: "SD133", compID: "gr_cntrInfo:offRtrnClsCd"},
        {grpCd: "SD102", compID: "gr_cntrInfo:cntrWtCondCd"},
        {grpCd: "SD165", compID: "gr_cntrInfo:cntrWrkClsCd"},
        {grpCd: "SD125", compID: "lc_odrClsCd"},
        {grpCd: "SD144", compID: "lc_mcomAssgnClsCd"},
        {grpCd: "SD101", compID: "lc_transCondCd"},
        {grpCd: "SD102", compID: "lc_cntrWtCondCd"},
        {grpCd: "SD132", compID: "lc_chClsCd"},
        {grpCd: "SD158", compID: "acb_odrCtrlClsCd"},
        {grpCd: "SD106", compID: "lc_bk_transShapeCd"},
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.f_openCommonPopUp = async function (gubun1, gubun2, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    var pCode = "";
    var pName = "";
    var pWhere = "";
    var pWtitleSearch = "";
    var pSelectID = "";
    var pWhere = "";
    var rtnList = new Array();
    scwin.sellBilgPNoDataCloseTF = "";

    switch (gubun1) {
        case 1: // 거래처 팝업
            if (gubun2 == "CTRT") { // 계약처
                pCode = ed_ctrtClntNo.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    ed_reqClntNo.setValue(pCode);
                }
                pName = ed_ctrtClntNm.getValue();
                pWtitleSearch = "계약 거래처,거래처코드,거래처명";
                pWhere = ",CTRT,CTRT";
                await udc_ctrtClntNo.cfCommonPopUpAsync(
                                                            scwin.udc_ctrtClntNo_callBackFunc,
                                                            pCode,							//pCode
                                                            pName,							//pName
                                                            pWinCloseTF,					//pWinCloseTF
                                                            '9',							//pDispCnt
                                                            "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",							//pTitle
                                                            '100,100,0,120,100,0,100,100,100,0',							//pWidth
                                                            "3,10",							//pHidden
                                                            pWhere,							//pWhere
                                                            '800',							//pW
                                                            '600',							//pH
                                                             null,							//pTop
                                                            null,							//pLeft
                                                            null,							//pExistTF - 중복체크여부	("F")
                                                            pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                            pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            pNoDataCloseTF,					//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                                            null
                                                        );
            } else if (gubun2 == "REQ") { // 요청처

                pCode = ed_reqClntNo.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    ed_reqClntNo.setValue(pCode);
                    lc_reqClntNm.setSelectedIndex(-1);
                }
                pName = lc_reqClntNm.getValue();
                pWtitleSearch = "요청 거래처,거래처코드,거래처명";
                pWhere = ",,CTRT";

                await udc_reqClntNo.cfCommonPopUpAsync(
                                                            scwin.udc_reqClntNo_callBackFunc,
                                                            pCode,							//pCode
                                                            pName,							//pName
                                                            pWinCloseTF,					//pWinCloseTF
                                                            '9',							//pDispCnt
                                                            "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",							//pTitle
                                                            '100,100,0,120,100,0,100,100,100,0',							//pWidth
                                                            "3,10",							//pHidden
                                                            pWhere,							//pWhere
                                                            '800',							//pW
                                                            '600',							//pH
                                                            null,							//pTop
                                                            null,							//pLeft
                                                            null,							//pExistTF - 중복체크여부	("F")
                                                            pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                            pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            pNoDataCloseTF,					//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                                            null
                                                        );
            } else if (gubun2 == "BILG") { // 청구처
                pCode = ed_bilgClntNo.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    ed_bilgClntNo.setValue(pCode);
                    lc_bilgClntNm.setSelectedIndex(-1);
                }
                pName = lc_bilgClntNm.getValue();
                pWtitleSearch = "청구 거래처,거래처코드,거래처명";
                pWhere = ",,CTRT";

                await udc_bilgClntNo.cfCommonPopUpAsync(
                                                            scwin.udc_bilgClntNo_callBackFunc,
                                                            pCode,							//pCode
                                                            pName,							//pName
                                                            pWinCloseTF,					//pWinCloseTF
                                                            '9',							//pDispCnt
                                                            "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",							//pTitle
                                                            '100,100,0,120,100,0,100,100,100,0',							//pWidth
                                                            "3,10",							//pHidden
                                                            pWhere,							//pWhere
                                                            '800',							//pW
                                                            '600',							//pH
                                                            null,							//pTop
                                                            null,							//pLeft
                                                            null,							//pExistTF - 중복체크여부	("F")
                                                            pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                            pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            pNoDataCloseTF,					//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                                            null
                                                        );
            } else if (gubun2 == "REAL") { //실화주
                pCode = ed_realMchtClntNo.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    ed_realMchtClntNo.setValue(pCode);
                    lc_realMchtClntNm.setSelectedIndex(-1);
                }
                pName = lc_realMchtClntNm.getValue();
                pWtitleSearch = "실화주 거래처,거래처코드,거래처명";
                pWhere = ",,CTRT";

                await udc_realMchtClntNo.cfCommonPopUpAsync(
                                                                scwin.udc_realMchtClntNo_callBackFunc,
                                                                pCode,							//pCode
                                                                pName,							//pName
                                                                pWinCloseTF,					//pWinCloseTF
                                                                '9',							//pDispCnt
                                                                "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",							//pTitle
                                                                '100,100,0,120,100,0,100,100,100,0',							//pWidth
                                                                "3,10",							//pHidden
                                                                pWhere,							//pWhere
                                                                '800',							//pW
                                                                '600',							//pH
                                                                null,							//pTop
                                                                null,							//pLeft
                                                                null,							//pExistTF - 중복체크여부	("F")
                                                                pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                                pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                                pNoDataCloseTF,					//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                                                null
                                                            );
            }
        break;
        case 2: // 매출 / 청구부서	
            // 물류점소구분코드 : LO120 - 팀(T), 지점(A), 사업소(B), CY(C), CFS(F)
            if (gubun2 == "SELL") { // 매출부서
                pCode = ed_sellLodeptCd.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    ed_sellLodeptCd.setValue(pCode);
                    ed_sellLodeptNm.setValue("");
                    pWhere = "T,J,,,T,T,1";
                } else {
                    pWhere = "T,J,,,,T,1";
                }
                if (pCode == null || pCode == "") {
                    pName = ed_sellLodeptNm.getValue();
                } else {
                    pName = "";
                }
                pWtitleSearch = "매출부서,부서코드,부서명";
                scwin.sellBilgPNoDataCloseTF = pNoDataCloseTF;
                await udc_sellLodeptCd.cfCommonPopUpAsync(
                                                            scwin.udc_sellLodeptCd_callBackFunc,
                                                            pCode,							//pCode
                                                            pName,							//pName
                                                            pWinCloseTF,					//pWinCloseTF
                                                            null,							//pDispCnt
                                                            null,							//pTitle
                                                            null,							//pWidth
                                                            null,							//pHidden
                                                            pWhere,							//pWhere
                                                            null,							//pW
                                                            null,							//pH
                                                            null,							//pTop
                                                            null,							//pLeft
                                                            null,							//pExistTF - 중복체크여부	("F")
                                                            pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                            pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            pNoDataCloseTF,					//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                                            null
                                                        );
            } else if (gubun2 == "BILG") { // 청구부서	
                pCode = ed_bilgLodeptCd.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    ed_bilgLodeptCd.setValue(pCode);
                    ed_bilgLodeptNm.setValue("");
                    pWhere = "T,J,,,T,,,1";
                } else {
                    pWhere = "T,J,,,,,,1";
                }
                if (pCode == null || pCode == "") {
                    pName = ed_bilgLodeptNm.getValue();
                } else {
                    pName = "";
                }
                pWtitleSearch = "청구부서,부서코드,부서명";
                scwin.sellBilgPNoDataCloseTF = pNoDataCloseTF;
                await udc_bilgLodeptCd.cfCommonPopUpAsync(
                                                            scwin.udc_bilgLodeptCd_callBackFunc,
                                                            pCode,							//pCode
                                                            pName,							//pName
                                                            pWinCloseTF,					//pWinCloseTF
                                                            null,							//pDispCnt
                                                            null,							//pTitle
                                                            null,							//pWidth
                                                            null,							//pHidden
                                                            pWhere,							//pWhere
                                                            null,							//pW
                                                            null,							//pH
                                                            null,							//pTop
                                                            null,							//pLeft
                                                            null,							//pExistTF - 중복체크여부	("F")
                                                            pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                            pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            pNoDataCloseTF,					//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                                            null
                                                        );
            }
        break;
		case 3: // Line조회 - Line코드, Line명, 선사코드, 선사코드명	
			pCode = ed_lineCd.getValue().trim();
			if (pNoDataCloseTF == "T") {
				ed_lineCd.setValue(pCode);
				$c.gus.cfInitObjects([ed_lineNm, ed_shpCoClntNm]);
				$c.gus.cfInitHidVal([ed_lineNm, ed_shpCoClntNm]);
				ds_odrInfo.setCellData(0, "shpCoClntNo", "");
				pWhere = "T";
			}
			pName = ed_lineNm.getValue();	
			pWtitleSearch = "LINE,LINE코드,LINE명";	
            await udc_lineCd.cfCommonPopUpAsync(
                                                    scwin.udc_lineCd_callBackFunc,
                                                    pCode,							//pCode
                                                    pName,							//pName
                                                    pWinCloseTF,					//pWinCloseTF
                                                    null,							//pDispCnt
                                                    null,							//pTitle
                                                    null,							//pWidth
                                                    null,							//pHidden
                                                    pWhere,							//pWhere
                                                    null,							//pW
                                                    null,							//pH
                                                    null,							//pTop
