// 조회조건 Clear
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_cndArea, null);
    ed_odrNo.setValue("");
    ed_cnd_cntrNo.setValue("");
    acb_cnd_odrKndCd.setValue("");
};

scwin.f_Retrieve = async function () {
    scwin.first_YN = 0;
    scwin.first_bilgClntNo = "";

    if (await $c.gus.cfValidate([tbl_cndArea])) {
        scwin.retrieveYn = "Y";

        scwin.f_clearDataSet();
        scwin.mgntTrgtClntYn = 0;

        ds_cndOdrNo.setCellData(ds_cndOdrNo.getRowPosition(), "odrNo", ed_odrNo.getValue().trim());

        let e = await $c.sbm.execute(sbm_retrieve);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieve_submitdone(e);
        } else if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
            scwin.sbm_retrieve_submiterror(e);
        }
    }
};

// 데이터셋 지우기
scwin.f_clearDataSet = async function () {
    if (ds_cndCtrtNo.getRowCount() > 0)
        ds_cndCtrtNo.removeAll();

    if (ds_ctrtNo.getRowCount() > 0) {
        ds_ctrtNo.removeAll();
    }
    if (ds_reqClntNo.getRowCount() > 0) ds_reqClntNo.removeAll();
    if (ds_bilgClntNo.getRowCount() > 0) ds_bilgClntNo.removeAll();
    if (ds_realMchtClntNo.getRowCount() > 0) ds_realMchtClntNo.removeAll();
    if (ds_commInfo.getRowCount() > 0) ds_commInfo.removeAll();
    if (ds_cntrInfo.getRowCount() > 0) ds_cntrInfo.removeAll();
    if (ds_blInfo.getRowCount() > 0) ds_blInfo.removeAll();
    if (ds_bookingInfo.getRowCount() > 0) ds_bookingInfo.removeAll();
    if (ds_sellInfo.getRowCount() > 0) ds_sellInfo.removeAll();
    if (ds_deleteOrderCond.getRowCount() > 0) ds_deleteOrderCond.removeAll();
    if (ds_orgCommInfo.getRowCount() > 0) ds_orgCommInfo.removeAll();
    if (ds_orgCntrInfo.getRowCount() > 0) ds_orgCntrInfo.removeAll();
    if (ds_orgBlInfo.getRowCount() > 0) ds_orgBlInfo.removeAll();
    if (ds_commQtyCalByCommSizTyp.getRowCount() > 0) ds_commQtyCalByCommSizTyp.removeAll();

    // 검색조건 - 오더번호
    ds_cndOdrNo.removeAll();
    ds_cndOdrNo.insertRow();
    ds_cndOdrNo.setRowPosition(0);

    // 오더정보
    ds_odrInfo.removeAll();
    ds_odrInfo.insertRow();
    ds_odrInfo.setRowPosition(0);

    // 총건수 세팅
    commTotalRows.setValue(ds_commInfo.getRowCount());
    sellTotalRows.setValue(ds_sellInfo.getRowCount());
    cntrTotalRows.setValue(ds_cntrInfo.getRowCount());

    scwin.f_setHidValues(2);
};

