        // ed_vsslNm.hidVal		= ed_vsslNm.Text;
        // ed_tsVsslCd.hidVal		= ed_tsVsslCd.Text;
        // ed_tsVsslNm.hidVal		= ed_tsVsslNm.Text;
    } else if (gubun == 2) {

     //   ed_ctrtClntNo.setValue(""); // 계약처코드
   //    ed_ctrtClntNm.setValue(""); // 계약처명
