        ed_realMchtClntNo.setValue(""); // 실화주코드
        ed_sellLodeptCd.setValue(""); // 매출부서코드
        ed_sellLodeptNm.setValue("");  // 매출부서명
        ed_bilgLodeptCd.setValue(""); // 청구부서코드 
        ed_bilgLodeptNm.setValue(""); // 청구부서명
        ed_lineCd.setValue(""); // Line 코드
