};

// 팝업버튼활성/비활성화
scwin.f_setActiveImgPopUp = function (gubun) {
    if (gubun == "E") { // 활성
        $c.gus.cfEnableObjects([
                                    btn_ctrtClntNo,     btn_reqClntNo,  btn_bilgClntNo,     btn_realMchtClntNo,     btn_sellLodeptCd,
                                    btn_bilgLodeptCd,   btn_lineCd,     btn_cvsslMgntNo,    btn_vsslCd,             btn_tsCvsslMgntNo,
                                    btn_tsVsslCd,       btn_dptWrkPlCd, btn_arvWrkPlCd,     btn_destPortCd,         btn_blNo,
                                    btn_alloccarPicId
                                ]);
    } else if (gubun == "D") { //비활성
        $c.gus.cfDisableObjects([
                                    btn_ctrtClntNo,     btn_reqClntNo,  btn_bilgClntNo,     btn_realMchtClntNo,     btn_sellLodeptCd,
                                    btn_bilgLodeptCd,   btn_lineCd,     btn_cvsslMgntNo,    btn_vsslCd,             btn_tsCvsslMgntNo,
                                    btn_tsVsslCd,       btn_dptWrkPlCd, btn_arvWrkPlCd,     btn_destPortCd,         btn_blNo,
                                    btn_alloccarPicId
        ]);
    }
};

// 그리드활성/비활성화
scwin.f_setActiveGrid = function (gubun) {
    if (gubun == "E") { // 활성
        for (var i = 0; i < gr_commInfo.getColumnCount(); i++) {
            var colId = gr_commInfo.getColumnID(i);
            if(gr_commInfo.getCellInfo(colId).options.userData1 == "Y"){
                gr_commInfo.setColumnReadOnly(colId, true);
            } else {
                gr_commInfo.setColumnReadOnly(colId, false);
            }
        }

        for (var i = 0; i < gr_cntrInfo.getColumnCount(); i++) {
            var colId = gr_cntrInfo.getColumnID(i);
            if(gr_cntrInfo.getCellInfo(colId).options.userData1 == "Y"){
                gr_cntrInfo.setColumnReadOnly(colId, true);
            } else {
                gr_cntrInfo.setColumnReadOnly(colId, false);
            }
        }
    } else if (gubun == "D") { // 비활성
        for (var i = 0; i< gr_commInfo.getColumnCount(); i++) {
            var colId = gr_commInfo.getColumnID(i);
            gr_commInfo.setColumnReadOnly(colId, true);
        }

        for (var i = 0; i < gr_cntrInfo.getColumnCount(); i++) {
            var colId = gr_cntrInfo.getColumnID(i);
            gr_cntrInfo.setColumnReadOnly(colId, true);
        }
    }
};

// 화면 onLoad시 초기 데이타 setting
// gubun1 : INIT(초기화), RETRIEVE(조회모드), UPDATE(수정모드), COPY(복사모드)
// gubun2 : INIT(초기화), CREATE(신규모드), ODRKNDCD(오더종류 변경되는 경우)
// 1.초기화,신규모드,오더종류변경되는 경우 : 오더기본정보 세팅(f_setDefaultValue()참조)
// 오더정보 조회후에 hidValue들 값 세팅하기(팝업 닫기 버튼 클릭시 undefined라고 쓰여지는 것을 막기 위함)
scwin.f_set = async function (gubun1, gubun2) {
    switch (gubun1) {
        case "INIT": // 초기화/신규      			
            if (gubun2 == "INIT") { // 초기화모드
                scwin.f_clearDataSet();
                $c.gus.cfDisableKeyData();
                $c.gus.cfDisableAllBtn();
                $c.gus.cfEnableBtnOnly([btn_retrieve, btn_create, btn_create1]);
                $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2, btn_updateCntrInfo, btn_chgCntrNoInfo, btn_updateRepWrkInfo,
                    btn_dcSc, btn_unitySelling, btn_copyOdr, btn_tmlEdiIfno]);

                scwin.f_setActiveImgPopUp("D"); // 팝업버튼 비활성화
                scwin.f_setActiveGrid("D");     // 그리드 비활성화

                $c.gus.cfInitObjects([tbl_cndArea, scwin.hid_chkReterieve], [tbl_odrInfoArea]);
                $c.gus.cfInitHidVal([tbl_odrInfoArea]);
                $c.gus.cfInitObjects(acb_odrCtrlClsCd);

                acb_odrKndCd.setValue(DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR);
                acb_odrCtrlClsCd.setValue("1");

                scwin.odrCtrlClsCd = acb_odrCtrlClsCd.getValue();
                scwin.statusFlag = "C"; // 수정등록 flag
                scwin.f_clearTabOrderInfo(); // Tab 오더정보 초기화
                scwin.mgntTrgtClntYn = 0;	// 계약거래처 관리구분여부 초기화
                scwin.excelUploadYn = 0;	//EXCEL UPLOAD (C3) 여부 


            } else if (gubun2 == "CREATE") { // 신규모드
                var odrKndCd = $p.parent().scwin.odrKndCd.trim();  //저장한 오더종류로 다시 세팅

                scwin.f_clearDataSet();
                $c.gus.cfEnableKeyData();
                $c.gus.cfDisableKey();
                $c.gus.cfEnableAllBtn();
                $c.gus.cfDisableBtnOnly([btn_update, btn_delete]);
                $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2, btn_updateCntrInfo, btn_chgCntrNoInfo, btn_updateRepWrkInfo, btn_dcSc, btn_unitySelling, btn_copyOdr, btn_tmlEdiIfno]);

                scwin.f_setActiveImgPopUp("E"); // 팝업버튼 활성화
                scwin.f_setActiveGrid("E");     // 그리드활성화

                acb_odrKndCd.focus();

                $c.gus.cfInitObjects([tbl_cndArea, tbl_odrInfoArea, scwin.hid_chkReterieve]);
                $c.gus.cfInitHidVal([tbl_odrInfoArea]);

                scwin.mgntTrgtClntYn = 0;	// 계약거래처 관리구분여부 초기화	
                scwin.excelUploadYn = 0;	// EXCEL UPLOAD (C3) 여부 

                if (odrKndCd != "") {
                    acb_odrKndCd.setValue(odrKndCd);
                } else {
                    acb_odrKndCd.setValue(DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR);
                }

                acb_odrCtrlClsCd.setValue("1");
                scwin.odrCtrlClsCd = acb_odrCtrlClsCd.getValue();

                scwin.statusFlag = "C";      // 수정등록 flag	
                scwin.f_clearTabOrderInfo(); // Tab 오더정보 초기화

                // $p.setTimeout(function() {
                //     scwin.acb_odrKndCd_onchange();
                // }, {"delay" : 100});

            } else if (gubun2 == "ODRKNDCD") { // 오더종류 변경되는 경우
                if (ds_cndCtrtNo.getRowCount() > 0)
                    ds_cndCtrtNo.removeAll();
                if (ds_ctrtNo.getRowCount() > 0) {
                    ds_ctrtNo.removeAll();
                }

                if (ds_reqClntNo.getRowCount() > 0) ds_reqClntNo.removeAll();
                if (ds_bilgClntNo.getRowCount() > 0) ds_bilgClntNo.removeAll();
                if (ds_realMchtClntNo.getRowCount() > 0) ds_realMchtClntNo.removeAll();
                if (ds_commInfo.getRowCount() > 0) ds_commInfo.removeAll();
                if (ds_cntrInfo.getRowCount() > 0) ds_cntrInfo.removeAll();
                if (ds_blInfo.getRowCount() > 0) ds_blInfo.removeAll();
                if (ds_bookingInfo.getRowCount() > 0) ds_bookingInfo.removeAll();
                if (ds_sellInfo.getRowCount() > 0) ds_sellInfo.removeAll();
                if (ds_orgCommInfo.getRowCount() > 0) ds_orgCommInfo.removeAll();
                if (ds_orgCntrInfo.getRowCount() > 0) ds_orgCntrInfo.removeAll();
                if (ds_orgBlInfo.getRowCount() > 0) ds_orgBlInfo.removeAll();
                if (ds_commQtyCalByCommSizTyp.getRowCount() > 0) ds_commQtyCalByCommSizTyp.removeAll();

                // 총건수 세팅
                commTotalRows.setValue(ds_commInfo.getRowCount());
                cntrTotalRows.setValue(ds_cntrInfo.getRowCount());
                sellTotalRows.setValue(ds_sellInfo.getRowCount());

                // 초기화
                $c.gus.cfInitObjects(tbl_odrInfoArea, [acb_odrKndCd, scwin.hid_chkReterieve]);
                scwin.mgntTrgtClntYn = 0;	// 계약거래처 관리구분여부 초기화
                scwin.excelUploadYn = 0;	// EXCEL UPLOAD (C3) 여부 

                acb_odrCtrlClsCd.setValue("1");
                scwin.odrCtrlClsCd = acb_odrCtrlClsCd.getValue();
            }

            // 매출부서, 청구부서 세팅
            scwin.f_setSellAndBilgDept("A");

            scwin.bkCommInfoRows = 0;
            scwin.bookingNoYn = "N";
            scwin.assgnWhouseCd = "";
            scwin.assgnWhouseNm = "";

            // 오더별 자가구분코드 LuxeCombo CBData 세팅
            scwin.f_setLuxeComboCBDataSelfClsCd();
            acb_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS);

            scwin.f_setDefaultValue(); // 기본정보세팅 

            // Booking정보 및 Booking품명정보 그리드 숨기기
            tbl_bkInfoTitleArea.hide();
            tbl_bkCommInfoTitleArea.hide();

            scwin.f_hideOdrSelItem(1);
            scwin.f_hideOdrSelItem(2);
            scwin.hid_chkMode = "create";
        break;
        case "RETRIEVE": //조회모드
            var odrDcsnYn = ds_odrInfo.getCellData(0, "odrDcsnYn");		// 확정여부
            var odrWrkPathCnt = ds_odrInfo.getCellData(0, "odrWrkPathCnt");	// 작업경로
            var odrDelYn = ds_odrInfo.getCellData(0, "odrDelYn");		// 삭제여부
            var odrCompleteYn = ds_odrInfo.getCellData(0, "odrCompleteYn");	// 오더완료여부
            var autoOdrYn = ds_odrInfo.getCellData(0, "autoOdrYn");		// 자동오더여부

            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableAllBtn();
            $c.gus.cfDisableObjects([btn_updateCntrInfo, btn_chgCntrNoInfo, btn_updateRepWrkInfo]);
            $c.gus.cfEnableBtnOnly([btn_retrieve, btn_create, btn_create1, btn_update]);

            scwin.f_setActiveImgPopUp("D"); // 팝업버튼 비활성화
            scwin.f_setActiveGrid("D");     // 그리드 활성화

            $c.gus.cfEnableObjects([btn_dcSc, btn_unitySelling, btn_copyOdr, btn_tmlEdiIfno]);

            // 수입일반이고, 도착지가 "43D"인 경우, 대표착지 팝업 활성시키기
            scwin.f_enableBtnUpdateRepWrkInfo();

            // 수입본선일반이면 팝업 활성시키기
            scwin.f_enableBtnChgCntrNoInfo();

            // 확정버튼 control
            if (autoOdrYn == 1) { // 자동오더인 경우 모두 비활성
                $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2, btn_copyOdr]);
                $c.gus.cfDisableBtnOnly([btn_update]);
            } else {
                if (odrWrkPathCnt > 0 && odrWrkPathCnt == ds_cntrInfo.getRowCount() && odrDelYn == 0) {
                    // 작업경로가 지정된 경우
                    if (odrDcsnYn != DsConstants.YN_YES) { // 오더가 확정되지 않은 경우
                        $c.gus.cfEnableObjects([btn_confirmOdr1, btn_confirmOdr2]);
                        $c.gus.cfEnableBtnOnly([btn_update]);
                    } else { // 오더가 확정된 경우
                        $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2]);
                        $c.gus.cfEnableBtnOnly([btn_update]);

                        if (odrCompleteYn == DsConstants.YN_YES) {
                            $c.gus.cfDisableBtnOnly([btn_update]);
                            $c.gus.cfDisableObjects([btn_tmlEdiIfno]);
                        }
                    }
                } else { // 작업경로가 지정되지 않은 경우
                    $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2]);
                }
            }

            scwin.excelUploadYn = 0;	//EXCEL UPLOAD (C3) 여부 
        break;
        case "UPDATE": //수정모드
            scwin.odrKndCd = acb_odrKndCd.getValue(); // 오더종류코드
            scwin.impExpClsCd = ds_odrKndCd.getCellData(acb_odrKndCd.getSelectedIndex(), "fltrCd2"); // 수출입구분코드

            var cntrInfoRows = ds_cntrInfo.getRowCount();
            var odrDcsnYn = ds_odrInfo.getCellData(0, "odrDcsnYn");		//확정여부
            var odrWrkPathCnt = ds_odrInfo.getCellData(0, "odrWrkPathCnt");	//작업경로
            var odrDelYn = ds_odrInfo.getCellData(0, "odrDelYn");		//삭제여부
            var odrCompleteYn = ds_odrInfo.getCellData(0, "odrCompleteYn");	//오더완료여부
            var autoOdrYn = ds_odrInfo.getCellData(0, "autoOdrYn");		//자동오더여부

            $c.gus.cfEnableKeyData();
            $c.gus.cfDisableKey();
            $c.gus.cfEnableAllBtn();
            $c.gus.cfEnableObjects([btn_updateCntrInfo]);
            $c.gus.cfDisableBtnOnly([btn_update]);

            scwin.f_setActiveImgPopUp("E"); // 팝업버튼 활성화
            scwin.f_setActiveGrid("E");     // 그리드 활성화

            // 비활성화
            $c.gus.cfEnableObj(acb_odrKndCd, false);	    // 오더종류코드
            $c.gus.cfEnableObj(ed_ctrtClntNo, false);	// 계약거래처코드
            $c.gus.cfEnableObj(ed_ctrtClntNm, false);	// 계약거래처명	
            $c.gus.cfEnableObj(lc_ctrtNo, false);		// 계약번호 비활성화
            $c.gus.cfEnableObj(btn_ctrtClntNo, false);	// 계약거래처 PopUp버튼       		
            $c.gus.cfEnableObj(acb_odrCtrlClsCd, false);	// 조정

            scwin.statusFlag = "U";
            scwin.f_setInterfaceByOdrOnUpdate();

            // 작업경로 생성시, 매출여부, 왕복여부 비활성화
            if (odrWrkPathCnt > 0) {
                $c.gus.cfEnableObj(lc_transCondCd, false);
                $c.gus.cfEnableObj(rd_sellYn, false);
            } else { // 작업경로가 지정되지 않은 경우
                $c.gus.cfEnableObj(lc_transCondCd, true);
                $c.gus.cfEnableObj(rd_sellYn, true);
            }

            // 실적 발생여부를 조회하여 수정항목을 설정
            if (scwin.f_chkResultsConfirmation()) {
                // 수정불가 항목을 Disable 한다.
                // 수정 불가항목 : 오더번호, 오더종류, 계약거래처, 계약번호, 대표거래처
                //			  , 출발작업장, 도착작업장, 작업시작일자, 작업시작시간, 작업종료일자, 작업종료시간
                //			  , 자가구분, 작업유형, 합적여부 (벌크오더 화면에는 해당되지 않는다.
                $c.gus.cfDisableObjects([	
                                            ed_dptWrkPlCd,		ed_dptWrkPlNm,		btn_dptWrkPlCd, 
                                            ed_arvWrkPlCd,		ed_arvWrkPlNm,		btn_arvWrkPlCd,
                                            ed_wrkStDt,			ed_wrkStHh,
                                            ed_wrkEndDt,		ed_wrkEndHh,
                                            ed_alloccarPicId,	ed_alloccarPicNm1,	btn_alloccarPicId,  rd_sellYn
                					    ]);
                $c.gus.cfDisableBtnOnly([btn_delete]);

                scwin.f_setLineCd("D");
                scwin.f_setBookingNo("D");
                scwin.f_setSelfClsCd("D");
            } else {
                // 자가영업(수출일반,Empty Position)이고 실적발생하지 않은 경우, lineCd를 활성화
                if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) //수출일반(자가영업)
                    || (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) //EMPTY POSITION(자가영업)
                ) {
                    // 자가영업(수출일반, Empty Position)인 경우, booking품명정보가 없는 경우에만, LineCd 및 bookingNo 수정 가능하게 해놓았음, 
                    // 만약 이때 bookingNo를 수정한 후, booking품명정보가 존재하면 error메시지 띄우기
                    if (scwin.bkCommInfoRows == 0) {
                        scwin.f_setLineCd("E");
                        scwin.f_setBookingNo("E");
                    } else {
                        scwin.f_setLineCd("D");	
                        scwin.f_setBookingNo("D");
                    }				
                } else {
                    scwin.f_setLineCd("D");
                    scwin.f_setBookingNo("D");
                }

                // 컨테이너를 지정하지 않은 경우 , 자가구분코드 활성화 
                var cntrAssgnYn = "N";
                for (var i = 0; i < cntrInfoRows; i++) {
                    if (ds_cntrInfo.getCellData(i, "cntrNo").trim() != "") {
                        cntrAssgnYn = "Y";
                        break;
                    }
                }

                if (cntrAssgnYn == "N") {
                    scwin.f_setSelfClsCd("E");
                } else {
                    scwin.f_setSelfClsCd("D");
                }				

                if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR  ||
                    scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR		 ||
                    scwin.odrKndCd == DsConstants.ODR_KND_CD_PORT_CHANGE_ODR	 ||
                    scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		 ||
                    scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR        ||
                    scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) { // 수출본선(C3), 수출TS(CW), PORT CHANGE(CP), ON-HIRE(C5), OFF-HIRE(C6), POSITION(C7)

                    // EXCEL UPLOAD 버튼 활성화
                    //$c.gus.cfEnableObjects([img_excel_up]);
                    udc_gr_cntrInfo.setDisabledBtn("btn_excelUp",false);
                    // 일괄복사
                    $c.gus.cfEnableObjects([lc_cntrItemRow, btnCopy]);
                }			
            }

            // 그리드에서 실적발생한 컨테이너는 수정 불가하게 함
            if (cntrInfoRows > 0) {
            	scwin.f_setGridCntrInfoByWrkRslts(ds_cntrInfo.getRowPosition());
            }

