scwin.f_setInterfaceByOdr = function () {
    if (ds_odrInfo.getCellData(0, "odrNo").trim() == "" && ds_odrInfo.getRowCount() > 0) {
        scwin.f_set("INIT", "ODRKNDCD"); //초기화	ODRKNDCD
    }
    scwin.f_setInterfaceByOdr2(scwin.odrKndCd, scwin.impExpClsCd);
};

