scwin.f_displayGridColumn = function (gridObj, colIdArr, mode, status) {
    for (var i = 0; i < colIdArr.length; i++) {
        var colId = colIdArr[i];
        var colIdx = gridObj.getColumnIndex(colId);
        if (colIdx == -1) continue;
        if (mode == "show") {
            var isVisible = (String(status) === "true");
            gridObj.setColumnVisible(colIdx, isVisible);
            gridObj.getCellInfo(colIdx).options["hidden"] = status === "true" ? "false" : "true";
        } else if (mode == "edit") {
            if (status == "none") {
                gridObj.setColumnReadOnly(colIdx, true);
                gridObj.getCellInfo(colId).options.userData1 = "Y";
            } else {
                gridObj.setColumnReadOnly(colIdx, false);
                gridObj.getCellInfo(colId).options.userData1 = "";
            }
        }
    }
};

