    ds_reqClntNo.removeAll();
    ds_bilgClntNo.removeAll();
    ds_realMchtClntNo.removeAll();

    $c.gus.cfInitObjects([ed_reqClntNo, ed_bilgClntNo, ed_realMchtClntNo]);
