// 계약번호에 해당 되는 청구/요청거래처/실화주거래처 정보 조회
scwin.f_retrieveClntList = async function () {
    var ctrtNo = lc_ctrtNo.getValue();
    if (ctrtNo == "선택") {
        // 청구/요청거래처/실화주거래처 정보 clear	
        scwin.f_clearDataByClntNos();
    } else {
        $c.sbm.setAction(sbm_retrieveClntNo, "/ds.sd.odrmgnt.odrreg.RetrieveContractBasisCMD.do?contractNumber=" + ctrtNo);
        let e = await $c.sbm.execute(sbm_retrieveClntNo);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieveClntNo_submitdone(e);
        } else if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
            scwin.sbm_retrieveClntNo_submiterror(e);
        }
    }
};

/* 설명 : 매출부서, 청구부서 세팅
 * 처리규칙 : 오더등록자의 등록점소의 첫째 둘째자리 + 오더종류의 끝자리
 * 1.수출/수입하역 : 매출부서 - 미지정,	청구부서 - 지정
 * 2.수출/수입본선 : 매출부서 - 미지정,	청구부서 - 지정
 * 3.그외		: 매출부서 - 지정,	청구부서 - 지정 
 */
scwin.f_setSellAndBilgDept = function (gubun) {
    if (gubun == "A") { // 지정인 경우
        var deptCd1 = scwin.sLobranCd // 등록점소 - 사용자 설정 물류점소
        var orgdeptCd1 = deptCd1;
        var deptCd2 = ""; // 오더종류에 따른 셋째자리 결정
        var deptCd = "";  // 부서코드

        if (deptCd1.length > 2) {
            deptCd1 = deptCd1.substr(0, 2);
        } else {
            return;
        }

        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR		        // 수입본선컨테이너오더
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR		    // 수출본선컨테이너오더
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR		    // 수입하역컨테이너오더
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR		    // 수출하역컨테이너오더
        ) {
            if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR			// 수입하역컨테이너오더
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR		// 수출하역컨테이너오더
            ) {
                deptCd2 = "4";
            } else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	// 수입본선컨테이너오더
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR	// 수출본선컨테이너오더
            ) {
                deptCd2 = "3";
            }

            deptCd = deptCd1 + deptCd2;

            // 청구부서 세팅
            if (orgdeptCd1 == "6AA") {
                if (deptCd2 == "4") {
                    ed_bilgLodeptCd.setValue(deptCd);
                } else {
                    ed_bilgLodeptCd.setValue("6A1");
                }
            } else {
                ed_bilgLodeptCd.setValue(deptCd);
            }
            scwin.f_openCommonPopUp(2, 'BILG', 'T', 'F', 'T');

        } else {
            deptCd2 = "2";
            deptCd = deptCd1 + deptCd2;

            // 매출부서 세팅
            ed_sellLodeptCd.setValue(deptCd);
            scwin.f_openCommonPopUp(2, 'SELL', 'T', 'F', 'T');

            //청구부서 세팅 - 부산은 6A3셋팅함.
            if (orgdeptCd1 == "6AA") {
                if (deptCd2 == "4") {
                    ed_bilgLodeptCd.setValue(deptCd);
                } else {
                    ed_bilgLodeptCd.setValue("6A1");
                }
            } else {
                ed_bilgLodeptCd.setValue(deptCd);
            }
            scwin.f_openCommonPopUp(2, 'BILG', 'T', 'F', 'T');
        }

    } else if (gubun == "N") { //미지정인 경우	
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR		// 수입본선컨테이너오더
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR	// 수출본선컨테이너오더
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR	// 수입하역컨테이너오더
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR	// 수출하역컨테이너오더
        ) {
            // 매출부서 세팅
            ed_sellLodeptCd.setValue(ed_dptWrkPlCd.getValue().trim());
            scwin.f_openCommonPopUp(2, 'SELL', 'T', 'F', 'T');
        }
    }
};

// 오더별 자가구분코드 LuxeCombo CBData 세팅
// 당사운송					: empty position, port change, return, 컨테이너수입TS, 부두간TS, 수출TS
// 당사운송, 자가반출입			: on/off-hire
// 당사운송, 자가반출, 자가영업	: 그 외 오더
scwin.f_setLuxeComboCBDataSelfClsCd = function () {

    var dlt = $c.gus.object("dlt_commonCodeSD114"); // 데이터 리스트 객체
    var sbx = acb_selfClsCd; // SelectBox 객체

    dlt.removeColumnFilterAll();
    acb_selfClsCd.removeAll();

    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		// on-hire
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR	// off-hire
    ) {
        sbx.setNodeSet("data:ds_selfClsCd");
    } else {
        sbx.setNodeSet("data:dlt_commonCodeSD114");
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_PORT_CHANGE_ODR	// port change
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_RETURN_ODR	    // return
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR	// 컨테이너수입TS
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR		    // 부두간TS
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR	// 수출TS
        ) {
            $c.data.dataListFilter(dlt, "fltrCd1 == 'A'");  //$c.data.dataListFilter 함수를 이용해서 필터
        } else {
            $c.data.dataListFilter(dlt, "fltrCd1 == 'C' || fltrCd1 == 'A'");  //$c.data.dataListFilter 함수를 이용해서 필터
        }
    }
};


/* 오더기본정보 세팅
 * 매출여부,		    컨테이너지정여부,	자가구분코드,	  		작업유형코드, 		등록점소
 * 운송화물구분코드, 수입수출내수구분코드,	수출입구분코드, 		과세구분코드, 		CH구분코드
 * 컨테이너중량조건, 운송조건,			출발일자(현재일자),	도착일자(현재일자)
 */
scwin.f_setDefaultValue = function () {
  	// 오더 담당 정보 설정
  	ed_odrPicNm.setValue(scwin.sUserNm);
  	ed_odrPicTelNo.setValue(scwin.sUserMpNo); //(확할것)
    //cf_IgnoreSpaces(DCheckIf.isNull(userDTO.getUserMpNo())? "":userDTO.getUserMpNo());

	ds_odrInfo.setCellData(0, "sellYn", 1);		                                                                // 매출여부	
	ds_odrInfo.setCellData(0, "cntrDsgYn", 1);		                                                            // 컨테이너지정여부
	ds_odrInfo.setCellData(0, "selfClsCd", DsConstants.SELF_CLS_CD_MCOM_TRANS);                                 // 자가구분코드 - 당사운송
	ds_odrInfo.setCellData(0, "wrkPatternCd", "00");		                                                    // 작업유형코드
	ds_odrInfo.setCellData(0, "regBranCd", scwin.sLobranCd);                                                    // 등록점소 - 사용자 설정 물류점소	 	
	ds_odrInfo.setCellData(0, "transCargoClsCd", "C");		                                                    // 운송화물구분코드	
	ds_odrInfo.setCellData(0, "impExpDomesticClsCd", scwin.impExpClsCd);                                        // 수입수출내수구분코드	
    ds_odrInfo.setCellData(0, "taxnClsCd", ds_ctrtNo.getCellData(lc_ctrtNo.getSelectedIndex(), "taxnClsCd"));   // 과세구분코드

	// 오더별 기본값 세팅
	switch (scwin.odrKndCd) {
        case DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR: 	// 수입본선컨테이너오더
			ds_odrInfo.setCellData(0, "chClsCd", "");       // CH구분코드
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "");  // 컨테이너중량조건	
        break;

        case DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR:		// 수출본선컨테이너오더
			ds_odrInfo.setCellData(0, "chClsCd", "");       // CH구분코드
			ds_odrInfo.setCellData(0, "transCondCd", "");   // 운송조건
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "");  // 컨테이너중량조건	
        break;

        case DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR:		// 수입하역컨테이너오더
			ds_odrInfo.setCellData(0, "chClsCd", "");       // CH구분코드
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "");  // 컨테이너중량조건	
        break;

        case DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR:		// 수출하역컨테이너오더
			ds_odrInfo.setCellData(0, "chClsCd", "");       // CH구분코드
			ds_odrInfo.setCellData(0, "transCondCd", "");   // 운송조건
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "");  // 컨테이너중량조건	
        break;

        case DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR:	    // 수입일반컨테이너오더
			ds_odrInfo.setCellData(0, "chClsCd", "0");      // CH구분코드
			ds_odrInfo.setCellData(0, "transCondCd", "2");  // 운송구분코드
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "H"); // 컨테이너중량조건코드				

		  	// 출발일자, 도착일자 초기값 설정
		  	ed_wrkStDt.setValue(scwin.strCurDate);
		  	ed_wrkEndDt.setValue(scwin.strCurDate);
        break;

        case DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR:		// 수출일반컨테이너오더
			ds_odrInfo.setCellData(0, "chClsCd", "");       // CH구분코드
			ds_odrInfo.setCellData(0, "transCondCd", "2");	// 운송구분코드
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "H");	// 컨테이너중량조건코드	

		  	// 출발일자, 도착일자 초기값 설정
		  	ed_wrkStDt.setValue(scwin.strCurDate);
		  	ed_wrkEndDt.setValue(scwin.strCurDate);
        break;

		case DsConstants.ODR_KND_CD_EXAMINE_ODR: // 검색기 오더
			ds_odrInfo.setCellData(0, "taxnClsCd", SdConstants.TAXN_CLS_CD_TAXN); // 과세구분코드 : 과세(01)

		default: // 그외 셔틀컨테이너오더 
			ds_odrInfo.setCellData(0, "chClsCd", "");       // CH구분코드
			ds_odrInfo.setCellData(0, "transCondCd", "");   // 운송조건
			ds_odrInfo.setCellData(0, "cntrWtCondCd", "H"); // 컨테이너중량조건	
			ds_odrInfo.setCellData(0, "dispPchsClsCd", "0");
			if (scwin.odrKndCd != DsConstants.ODR_KND_CD_CY_IMP_TS_ODR && scwin.odrKndCd != DsConstants.ODR_KND_CD_TS_ODR) {
			  	// 출발일자, 도착일자 초기값 설정
                ed_wrkStDt.setValue(scwin.strCurDate);
                ed_wrkEndDt.setValue(scwin.strCurDate);
			}	
        break;
	}
};

