// 그리드 활성/비활성
scwin.f_setCommGrid = function (gubun) {
	if (gubun == "E") { // 그리드활성화 
        gr_commInfo.setGridReadOnly(false); // 전체 잠금부터 해제
        for (var i = 0; i < gr_commInfo.getColumnCount(); i++) {
            var colId = gr_commInfo.getColumnID(i);
            if (gr_commInfo.getCellInfo(colId).options.userData1 == "Y") {
                gr_commInfo.setColumnReadOnly(colId, true);
            } else {
                gr_commInfo.setColumnReadOnly(colId, false);
            }
        }

        gr_commInfo.setColumnReadOnly("cntrSizCd", false);
        gr_commInfo.setColumnReadOnly("fullEmptyClsCd", false);
		$c.gus.cfEnableBtnOnly([btn_addRow1, btn_deleteRow1, btn_undoRow1]);
	} else if (gubun == "D") {
        gr_commInfo.setReadOnly("grid", true); // 그리드 비활성화
        for (var i = 0; i < gr_commInfo.getColumnCount(); i++) {
            var colId = gr_commInfo.getColumnID(i);
            gr_commInfo.setColumnReadOnly(colId, true);
        }

		$c.gus.cfDisableBtnOnly([btn_addRow1, btn_deleteRow1, btn_undoRow1]); 
	} else if (gubun == "O") { // 수입/수출하역인 경우, 수량만 입력 가능하게 해야 함
        for (var i = 0; i< gr_commInfo.getColumnCount(); i++) {
            var colId = gr_commInfo.getColumnID(i);
            gr_commInfo.setColumnReadOnly(colId, true);
        }

        gr_commInfo.setColumnReadOnly("cntrSizCd", true);
        gr_commInfo.setColumnReadOnly("fullEmptyClsCd", true);
        gr_commInfo.setColumnReadOnly("qty", false);
		$c.gus.cfEnableBtnOnly([btn_addRow1, btn_deleteRow1, btn_undoRow1]); 
	}
};

