// 자가구분코드 LuxeCombo에서 OnSelChange이벤트 발생시 실행
//  1.수입일반 : 자가영업인 경우, 자가영업이 아닌 경우 
//  2.수출일반 : 자가영업인 경우, 자가영업이 아닌 경우
scwin.f_onSelChangeSelfClsCd = function() {
	scwin.selfClsCd = ds_odrInfo.getCellData(0, "selfClsCd");

	/******* 수입일반인 경우 *******/
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) {		
		if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) { // 자가영업인 경우
			// mandatory표시 보이기(본선관리번호, 선박명, 항차)	
			scwin.f_showMandatoryMark("E");
			scwin.f_showBlNoAndCvsslMgntNoPopUp("S");

			// validation세팅
            var validSettings = [
                { id: "ed_blNo",            exp: "BL번호:yes" },
                { id: "ed_cvsslMgntNo",     exp: "" },
                { id: "ed_vsslCd",          exp: "" },
                { id: "ed_portcnt",         exp: "" }
            ];

            // 공통 함수 실행
            scwin.setValidations(validSettings);

		} else { // 자가영업이 아닌 경우
			// mandatory표시 보이기(본선관리번호, 선박명, 항차)	
			scwin.f_showMandatoryMark("S");
			scwin.f_showBlNoAndCvsslMgntNoPopUp("S");

			//validation세팅
            var validSettings = [
                { id: "ed_blNo",            exp: "BL번호:yes" },
                { id: "ed_cvsslMgntNo",     exp: "본번:yes" },
                { id: "ed_vsslCd",          exp: "선박명:yes" },
                { id: "ed_portcnt",         exp: "항차:yes" }
            ];

            // 공통 함수 실행
            scwin.setValidations(validSettings);
		}
	/******* 수출일반인 경우 *******/
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) {
        var isSelfSales = (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES);

        if (isSelfSales) { // 자가영업인 경우
            scwin.f_setCntrGridForSizTypFE("E");
            scwin.f_displayGridColumn(gr_cntrInfo, ["currPosCd"], "edit", "upper"); 
            scwin.f_displayGridColumn(gr_cntrInfo, ["fullEmptyClsCd"], "edit", "none"); 
        } else { // 자가영업이 아닌 경우
            scwin.f_setCntrGridForSizTypFE("D");
            scwin.f_displayGridColumn(gr_cntrInfo, ["currPosCd"], "edit", "none");
        }

        // 유효성 설정은 한 번에 처리
        scwin.setValidations([
            { id: "ed_lineCd", exp: isSelfSales ? "" : "Line코드:yes" }
        ]);
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR) {	// off-hire
        var expVal = ""; // 기본값 설정

        if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_CRRYOUT) { // 자가반출인 경우
            expVal = "관련번호:yes";
        }

        // 공통 실행부
        scwin.setValidations([{ id: "ed_clntMgntNo", exp: expVal }]);
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) { // empty position	
        var clntExp = "";

        if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_CRRYOUT) {
            clntExp = "관련번호:yes";
        }

        scwin.setValidations([{ id: "ed_clntMgntNo", exp: clntExp }]);

		if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) {	// 자가영업인 경우
			// 활성/비활성시키기			
			scwin.f_setCntrGridForSizTypFE("E");

		} else { // 자가영업이 아닌 경우
			// 활성/비활성시키기	
			scwin.f_setCntrGridForSizTypFE("D");
		}
	}		
};

scwin.myDisplayFormatter = function(value) {
    if (!value) return "";
    return value.replace(/^(\d{1,2})(\d*)$/, function(match, p1, p2) {
        return p2 ? p1 + ":" + p2 : p1 + ":";
    });
};

