/* function 설명 : f_calInputQty()하기전에 유효성 확인
 * (처리규칙)
 * 1.수출일반
 *   1.1.size,type,fullEmpty,중량,온도,dry를 체크
 *   1.2.type이 'RF'인 경우 : 온도 또는 dry 중 하나를 꼭 체크해야함
 * 2.그 외 오더
 *   2.1.sie,type,fullEmpty 체크
 *   2.2.컨테이너번호 필수항목 체크
 *     2.2.1.필수항목 체크 제외 - on-hire, off-hire, empty position(컨테이너 미지정 가능한 오더)
 * PARAM : commInfoRows	= ds_commInfo.CountRow
 * PARAM : cntrInfoRows	= ds_cntrInfo.CountRow
 */
scwin.f_validateCommAndCntr = async function() {
	var commInfoRows = ds_commInfo.getRowCount();
	var cntrInfoRows = ds_cntrInfo.getRowCount();

	/************** 수출일반인 경우 **************/
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { 
		/******* 품명정보 - 중복 체크, RF체크 *******/
		for (var i= 0; i < commInfoRows; i++) {		
			if (ds_commInfo.getRowStatus(i) != "D") { // 삭제건이 아닌 경우만 해당
				var sizeTypeFE = ds_commInfo.getCellData(i, "cntrSizCd").trim() 
									+ ds_commInfo.getCellData(i, "cntrTypCd").trim()
									+ ds_commInfo.getCellData(i, "fullEmptyClsCd").trim()
									+ ds_commInfo.getCellData(i, "grossWt")
									+ ds_commInfo.getCellData(i, "temper")
									+ ds_commInfo.getCellData(i, "dryYn");

				for (var j = 0; j < commInfoRows; j++) {
					if (i != j) { //같은 row인 경우는 제외
						if (ds_commInfo.getRowStatus(j) != "D") { //삭제건이 아닌 경우만 해당 
							var tempSizeTypeFE = ds_commInfo.getCellData(j, "cntrSizCd").trim()
												 + ds_commInfo.getCellData(j, "cntrTypCd").trim() 
												 + ds_commInfo.getCellData(j, "fullEmptyClsCd").trim()
												 + ds_commInfo.getCellData(j, "grossWt")
												 + ds_commInfo.getCellData(j, "temper")
												 + ds_commInfo.getCellData(j, "dryYn");
							// 품명 중복 체크							
							var strAlert = "";
							if (ds_commInfo.getCellData(i, "wt") != 0)
                                strAlert = ", 중량(" + ds_commInfo.getCellData(i, "wt") + ")";

							if (!$c.gus.cfIsNull(ds_commInfo.getCellData(i, "temper"))) {
                                strAlert = ", 온도(" + ds_commInfo.getCellData(i, "temper") + ")";
                            } else {
                                strAlert = ",온도";
                            }

							if (ds_commInfo.getCellData(i, "dryYn") != 0)
                                strAlert = ", DRY";

							if (sizeTypeFE == tempSizeTypeFE) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032.replace("%1", "%3"), ["품명목록", (j + 1), "Size,Type,F/E" + strAlert]); //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
								return false;
							}
						}
					}
				}

				// 중량 체크
				var wt = ds_commInfo.getCellData(i, "grossWt");
				if (Number(wt) < 0) {
					await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_057.replace("%1", "%3").replace("%2", "%4"), ["품명목록", (i + 1), "중량", "0"]); //@의 @번째 데이터에서 @은(는) @ 보다 큰 값으로 입력하십시오.
					return false;
				}

				// 품명 type이 RF/RH인 경우, 온도 또는 dry 체크
				var commType = ds_commInfo.getCellData(i, "cntrTypCd").trim();
				var temper   = ds_commInfo.getCellData(i, "temper").trim();
				var dryYn    = ds_commInfo.getCellData(i, "dryYn");

				if (commType == DsConstants.CNTR_TYP_CD_RF || commType == DsConstants.CNTR_TYP_CD_RH) {
					// 온도 또는 dry 중 하나라도 입력했는지 체크
					if ($c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_NO) {
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3").replace("%2", "%4"), ["품명목록", (i + 1), "TYPE이 RF/RH인 경우, 온도 또는 DRY"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
						return false;						
					}

					// 온도 또는 dry 모두 입력했는지 체크					
					if (!$c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_YES) {
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_041.replace("%1", "%3").replace("%2", "%4"), ["품명목록", (i + 1), "TYPE이 RF/RH인 경우, 온도와 DRY 모두 입력"]); //@의 @번째 데이터에서 @은(는) @할 수 없습니다.
						return false;						
					}
				}
			}
		}

		/******* 컨테이너정보 - 중복 체크, RF체크 *******/
		for (var i = 0; i < cntrInfoRows; i++) {		
			if (ds_cntrInfo.getRowStatus(i) != 'D') { // 삭제건이 아닌 경우만 해당
				var cntrNo = ds_cntrInfo.getCellData(i, "cntrNo").trim();

				for (var j = 0; j < cntrInfoRows; j++) {
					if (i != j) { // 같은 row인 경우는 제외
						if (ds_cntrInfo.getRowStatus(j) != "D") { // 삭제건이 아닌 경우만 해당 
							var tempCntrNo = ds_cntrInfo.getCellData(j, "cntrNo").trim();
							if (!$c.gus.cfIsNull(cntrNo)) {
								// 컨테이너 중복 체크
								if (cntrNo == tempCntrNo) { 
									await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032.replace("%1", "%3"), ["컨테이너목록", (j + 1), "컨테이너번호"]); //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
									return false;
								}
							}
						}
					}
				}

				// 중량 체크
				var wt = ds_cntrInfo.getCellData(i, "wt");
				if (wt < 0) {
					await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_057.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", (i + 1), "중량", "0"]); //@의 @번째 데이터에서 @은(는) @ 보다 큰 값으로 입력하십시오.
					return false;
				}

				// 컨테이너 type이 RF/RH인 경우, 온도 또는 dry 체크
				var cntrType = ds_cntrInfo.getCellData(i, "cntrTypCd").trim();
				var temper   = ds_cntrInfo.getCellData(i, "temper").trim();
				var dryYn    = ds_cntrInfo.getCellData(i, "dryYn");

				if (cntrType == DsConstants.CNTR_TYP_CD_RF || cntrType == DsConstants.CNTR_TYP_CD_RH) {
					//온도 또는 dry 중 하나라도 입력했는지 체크
					if ($c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_NO) {
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", (i + 1), "TYPE이 RF/RH인 경우, 온도 또는 DRY"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
						return false;						
					}

					// 온도 또는 dry 모두 입력했는지 체크
					if (!$c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_YES) {
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_041.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", (i + 1), "TYPE이 RF/RH인 경우, 온도와 DRY 모두 입력"]); //@의 @번째 데이터에서 @은(는) @할 수 없습니다.
						return false;						
					}
				}
			}
		}
	/************** 그외 오더 **************/
	} else {
		/******* 품명정보 - 중복 체크 *******/
		for (var i = 0; i < commInfoRows; i++) {		
			if (ds_commInfo.getRowStatus(i) != "D") { //삭제건이 아닌 경우만 해당
				var sizeTypeFE = ds_commInfo.getCellData(i, "cntrSizCd").trim() 
									+ ds_commInfo.getCellData(i, "cntrTypCd").trim()
									+ ds_commInfo.getCellData(i, "fullEmptyClsCd").trim();

				for (var j = 0; j < commInfoRows; j++) {
					if (i != j) { //같은 row인 경우는 제외
						if (ds_commInfo.getRowStatus(j) != "D") { //삭제건이 아닌 경우만 해당 
							var tempSizeTypeFE = ds_commInfo.getCellData(j, "cntrSizCd").trim()
												 + ds_commInfo.getCellData(j, "cntrTypCd").trim() 
												 + ds_commInfo.getCellData(j, "fullEmptyClsCd").trim();
							// 품명 중복 체크
							if (sizeTypeFE == tempSizeTypeFE) { 
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032.replace("%1", "%3"), ["품명목록", (j + 1), "Size,Type,F/E"]); //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
								return false;
							}
						}
					}
				}
			}
		}
		/******* 컨테이너정보 - 중복 체크 *******/
		for (var i = 0; i < cntrInfoRows; i++) {		
			// 삭제건이 아닌 경우만 해당
			if (ds_cntrInfo.getRowStatus(i) != "D") { 
				var cntrNo         = ds_cntrInfo.getCellData(i, "cntrNo").trim();
				var cntrSizCd      = ds_cntrInfo.getCellData(i, "cntrSizCd").trim();
				var cntrTypCd      = ds_cntrInfo.getCellData(i, "cntrTypCd").trim();
				var fullEmptyClsCd = ds_cntrInfo.getCellData(i, "fullEmptyClsCd").trim();

				/* 컨테이너번호 필수항목 체크
				 * 필수항목 체크 제외 - on-hire, off-hire, empty position(컨테이너 미지정 가능한 오더)
				 */
				if ($c.gus.cfIsNull(cntrNo)) { 
					// 컨테이너 미지정하는 오더 : 수입하역, 수출하역
					if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR       // 수입하역 
						|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR    // 수출하역
					) {	
						if ($c.gus.cfIsNull(cntrSizCd) || $c.gus.cfIsNull(fullEmptyClsCd)) {
							if ($c.gus.cfIsNull(cntrSizCd)) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", (i + 1), "SIZE"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
								return false;	
							} else if ($c.gus.cfIsNull(fullEmptyClsCd)) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", (i + 1), "F/E"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
								return false;	
							}
						}											

					//컨테이너 미지정하는 오더 : ON-HIRE, OFF-HIRE, EMPTY POSTION
					} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		// On-hire 
						|| scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR		// Off-hire 
						|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR	// Empty Position
					) {	
						if ($c.gus.cfIsNull(cntrSizCd) || $c.gus.cfIsNull(cntrTypCd) || $c.gus.cfIsNull(fullEmptyClsCd)) {
							if ($c.gus.cfIsNull(cntrSizCd)) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", (i + 1), "SIZE"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
								return false;	
							} else if ($c.gus.cfIsNull(cntrTypCd)) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", (i + 1), "TYPE"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
								return false;	
							} else if ($c.gus.cfIsNull(fullEmptyClsCd)) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", (i + 1), "F/E"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
								return false;	
							}
						}
					} else { // 컨테이너번호 지정해야하는 오더					
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", (i + 1), "컨테이너번호"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
						return false;	
					}	
				}

				// 컨테이너번호 중복 체크
				for (var j = 0; j < cntrInfoRows; j++) {
					if (i != j) { //같은 row인 경우는 제외
						if (ds_cntrInfo.getRowStatus(j) != "D") { //삭제건이 아닌 경우만 해당 
							var tempCntrNo = ds_cntrInfo.getCellData(j, "cntrNo").trim();

							// 컨테이너 중복 체크
							if (!$c.gus.cfIsNull(cntrNo)) {
								if (cntrNo == tempCntrNo) { 
									await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032.replace("%1", "%3"), ["컨테이너목록", (j + 1), "컨테이너번호"]); //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
									return false;
								}
							}
						}
					}
				}
			}
		}
	}
	return true;
}

// retrieve후에 품명정보의 입력수량 계산하기
// gubun == "Y" 인 경우, return false를 날림
// gubun == "N" 인 경우, 조회후, 수량계산하기 위하여 사용, validation체크하지 않고, 오류메세지 나타나지 않게 함.
scwin.f_calInputQty = async function(gubun) {
	// 수량계산하기 전에 validation 체크
	if (gubun != "N") {
		if (!await scwin.f_validateCommAndCntr()) return;
	}

	var cntrRows = ds_cntrInfo.getRowCount();
	var commRows = ds_commInfo.getRowCount();

	// 수입/수출하역이 아닌 경우
	if (!(scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR)) {
		/* 수입본선/일반,부두간TS,하선지경유TS(부두-->CY)오더인 경우 : 품명목록에 없는 종류인 경우, 자동으로 품명목록에 세팅하고, 수량,입력수량도 세팅
		 * 수입일반인 경우 : FullEmpty구분할필요없음
		 * 그 외의 경우 : 품명목록에 있는 경우, 수량/입력수량 세팅, 만약 품명목록에 없는 경우, 알림메시지 띄우기
		 */
		if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR 		// 수입본선
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR					// 부두간 TS
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR			// 하선지경유TS(부두-->CY)
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR		// 수입일반
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 	// CFS셔틀
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR	// 세관검사
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR			    // 검색기
		) {
			// 품명목록의 입력수량을 '0'으로 초기화
			for (var i = 0; i < commRows; i++) {
				// 품명목록의 수량과 입력수량의 값이 '0'이 아닌 경우 삭제된 상태를 취소하기
				if (ds_commInfo.getRowStatus(i) == "D" && ds_commInfo.getCellData(i, "qty") > 0 && ds_commInfo.getCellData(i, "inputQty") > 0) {
					ds_commInfo.undoRow(i);
				}

				ds_commInfo.setCellData(i, "qty", 0);
				ds_commInfo.setCellData(i, "inputQty", 0);
			}

			// 품명목록의 입력수량 계산
			for (var i = 0; i < cntrRows; i++) {
				if (ds_cntrInfo.getRowStatus(i) != "D") { // 삭제건이 아닌 경우		
					var sameYn = "N";
					var cntrSizCd = ds_cntrInfo.getCellData(i, "cntrSizCd");
					var cntrTypCd = ds_cntrInfo.getCellData(i, "cntrTypCd");
					var fullEmptyClsCd = ds_cntrInfo.getCellData(i, "fullEmptyClsCd");

					if (ds_commInfo.getRowCount() > 0) {			
						for (var j = 0; j < ds_commInfo.getRowCount(); j++) {				
							var idx = 0;
							if (cntrSizCd == ds_commInfo.getCellData(j, "cntrSizCd")
								&& cntrTypCd == ds_commInfo.getCellData(j, "cntrTypCd")
								&& fullEmptyClsCd == ds_commInfo.getCellData(j, "fullEmptyClsCd")
							) {
								sameYn = "Y";	
								idx = j;
								break;
							}
						}

						if (sameYn == "N") {
							if (cntrSizCd != "" && cntrTypCd != "" && fullEmptyClsCd != "") {
								var rowIndex = ds_commInfo.insertRow();
								ds_commInfo.setCellData(rowIndex, "cntrSizCd", cntrSizCd);
								ds_commInfo.setCellData(rowIndex, "cntrTypCd", cntrTypCd);
								ds_commInfo.setCellData(rowIndex, "fullEmptyClsCd", fullEmptyClsCd);
								ds_commInfo.setCellData(rowIndex, "qty", 1);
								ds_commInfo.setCellData(rowIndex, "inputQty", 1);
							}
						} else {
							ds_commInfo.setCellData(idx, "qty", Number(ds_commInfo.getCellData(idx, "qty")) + 1);		
							ds_commInfo.setCellData(idx, "inputQty", Number(ds_commInfo.getCellData(idx, "inputQty")) + 1);				
						}	
					} else {
						if (cntrSizCd != "" && cntrTypCd != "" && fullEmptyClsCd != "") {
                            var rowIndex = ds_commInfo.insertRow();
							ds_commInfo.setCellData(rowIndex, "cntrSizCd", cntrSizCd);
							ds_commInfo.setCellData(rowIndex, "cntrTypCd", cntrTypCd);
							ds_commInfo.setCellData(rowIndex, "fullEmptyClsCd", fullEmptyClsCd);
							ds_commInfo.setCellData(rowIndex, "qty", 1);
							ds_commInfo.setCellData(rowIndex, "inputQty", 1);
						}
					}
				}
			}

            for (var i = ds_commInfo.getRowCount(); i >= 0; i--) {
				if (Number(ds_commInfo.getCellData(i, "qty")) == 0 &&  Number(ds_commInfo.getCellData(i, "inputQty")) == 0) {
                    ds_commInfo.removeRow(i);
					//ds_commInfo.DeleteRow(i);(확인할것)
                  //  ds_commInfo.deleteRow(i);
				}
			}
		} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반인 경우 : FullEmpty구분할필요없음
			// 품명목록의 입력수량을 '0'으로 초기화
			for (var i = 0; i < commRows; i++) {
				ds_commInfo.setCellData(i, "inputQty", 0);
			}

			// 품명목록의 입력수량 계산
			for (var i = 0; i < cntrRows; i++) {
				if (ds_cntrInfo.getRowStatus(i) != "D") { // 삭제건이 아닌 경우		
					var sameYn = "N";
					if (commRows > 0) {
						for (var j = 0; j < commRows; j++) {
							var idx = 0;			
							if (ds_cntrInfo.getCellData(i, "cntrSizCd")		  == ds_commInfo.getCellData(j, "cntrSizCd")
								&& ds_cntrInfo.getCellData(i, "cntrTypCd")	  == ds_commInfo.getCellData(j, "cntrTypCd")
								&& ds_cntrInfo.getCellData(i, "temper")		  == ds_commInfo.getCellData(j, "temper")
								&& ds_cntrInfo.getCellData(i, "dryYn")		  == ds_commInfo.getCellData(j, "dryYn")
							) {
								sameYn = "Y";	
								idx = j;
								break;					
							}
						}

						var strAlert = "";
						if (ds_cntrInfo.getCellData(i, "wt") != 0)
                            strAlert = ", 중량(" + ds_cntrInfo.getCellData(i, "wt") + ")";

						if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "temper")))
                            strAlert = ", 온도(" + ds_cntrInfo.getCellData(i, "temper") + ")";

						if (ds_cntrInfo.getCellData(i, "dryYn") != 0)
                            strAlert = ", DRY";

						if (sameYn == "N") {
							if (gubun != "N") {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + " 컨테이너는 "
											+ ds_cntrInfo.getCellData(i, "cntrSizCd") 
											+ ds_cntrInfo.getCellData(i, "cntrTypCd") 
											+ ds_cntrInfo.getCellData(i, "fullEmptyClsCd") 
											+ strAlert
											+ "입니다. 컨테이너번호를 확인하세요.", ["컨테이너목록", i+1]); //@의 @번째 데이터에서	
							}

							if (gubun == "Y")
                                return false;
						} else {
							ds_commInfo.setCellData(idx, "inputQty", Number(ds_commInfo.getCellData(idx, "inputQty")) + 1);
						}	
					} else {
						var strAlert = "";
						if (ds_cntrInfo.getCellData(i, "wt") != 0)
                            strAlert = ", 중량(" + ds_cntrInfo.getCellData(i, "wt") + ")";

						if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "temper")))
                            strAlert = ", 온도(" + ds_cntrInfo.getCellData(i, "temper") + ")";
						if (ds_cntrInfo.getCellData(i, "dryYn") != 0)
                            strAlert = ", DRY";

						if (gubun != "N") {
							await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + " 컨테이너는 "
										+ ds_cntrInfo.getCellData(i, "cntrSizCd") 
										+ ds_cntrInfo.getCellData(i, "cntrTypCd") 
										+ ds_cntrInfo.getCellData(i, "fullEmptyClsCd") 
										+ strAlert
										+ "입니다. 컨테이너번호를 확인하세요.", ["컨테이너목록", i+1]); //@의 @번째 데이터에서	
						}

						if (gubun == "Y")
                            return false;	
					}	
				}
			}
		} else { // 그 외의 경우에 해당
			// 품명목록의 입력수량을 '0'으로 초기화
			for (var i = 0; i < commRows; i++) {
				ds_commInfo.setCellData(i, "inputQty", 0);
			}

			// 품명목록의 입력수량 계산
			for (var i = 0; i < cntrRows; i++) {	
				if (ds_cntrInfo.getRowStatus(i) != "D") { // 삭제건이 아닌 경우
					var sameYn = "N";
					if (commRows > 0) {
						for (var j = 0; j < commRows; j++) {
							var idx = 0;			
							if (ds_cntrInfo.getCellData(i, "cntrSizCd") == ds_commInfo.getCellData(j, "cntrSizCd")
								&& ds_cntrInfo.getCellData(i, "cntrTypCd") == ds_commInfo.getCellData(j, "cntrTypCd")
								&& ds_cntrInfo.getCellData(i, "fullEmptyClsCd") == ds_commInfo.getCellData(j, "fullEmptyClsCd")
							) {
								sameYn = "Y";	
								idx = j;
								break;					
							}
						}

						if (sameYn == "N") {
							if (gubun != "N") {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + " 컨테이너는 "
											+ ds_cntrInfo.getCellData(i, "cntrSizCd") 
											+ ds_cntrInfo.getCellData(i, "cntrTypCd") 
											+ ds_cntrInfo.getCellData(i, "fullEmptyClsCd")
											+ "입니다. 컨테이너번호를 확인하세요.", ["컨테이너목록", i+1]); //@의 @번째 데이터에서	
							}

							if (gubun == "Y")
                                return false;
						} else {
							ds_commInfo.setCellData(idx, "inputQty", Number(ds_commInfo.getCellData(idx, "inputQty")) + 1);
						}	
					} else {
						if (gubun != "N") {
							await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + " 컨테이너는 "
										+ ds_cntrInfo.getCellData(i, "cntrSizCd") 
										+ ds_cntrInfo.getCellData(i, "cntrTypCd") 
										+ ds_cntrInfo.getCellData(i, "fullEmptyClsCd")
										+ "입니다. 컨테이너번호를 확인하세요.", ["컨테이너목록", i+1]); //@의 @번째 데이터에서	
						}

						if (gubun == "Y")
                            return false;	
					}	
				}
			}
		}
	} // 수입/수출하역이 아닌 경우, if의 끝	
	return true;
};

