		var odrNo           = ds_odrInfo.getCellData(ds_odrInfo.getRowPosition(), "odrNo");
	  	var odrDcsnYn		= ds_odrInfo.getCellData(0, "odrDcsnYn");		// 확정여부d
       	var odrWrkPathCnt	= ds_odrInfo.getCellData(0, "odrWrkPathCnt");	// 작업경로
       	var odrDelYn		= ds_odrInfo.getCellData(0, "odrDelYn");		// 삭제여부
       	var odrCompleteYn	= ds_odrInfo.getCellData(0, "odrCompleteYn");	// 오더완료여부
       	var autoOdrYn		= ds_odrInfo.getCellData(0, "autoOdrYn");		// 자동오더여부

	  	if (odrWrkPathCnt > 0 && odrWrkPathCnt == ds_cntrInfo.getRowCount() && odrDelYn == 0) {
			// 작업경로가 지정된 경우
		  	if ($c.gus.cfIsNull(odrNo)) {
		  		await $c.gus.cfAlertMsg(MSG_CM_ERR_049, new Array("오더정보"));  	
		  		return false;
		  	}

		  	var	arrParam = new Array(10);
			arrParam[0] = odrNo; //오더번호

            if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR			                         // 수입하역컨테이너오더
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR		                         // 수출하역컨테이너오더
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR		                             // CW
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR		                                     // TS
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR		                         // C3
