// Excel등록(확인할것)
scwin.f_upload = async function () {
	var i;
	scwin.cntrLoadGubun = "Y";
	// inputF.Value = "";

	// inputF.Open();	

	// if (inputF.Value == "") {
	// 	return;
	// }

	// Import파일의 확장자 확인
	// var inputFileName		= inputF.Value;
	// var inputFileLength		= inputFileName.length;
	// var fileExtendNameCheck = inputFileName.substring((inputFileLength-3), inputFileLength);

	// if (fileExtendNameCheck.toUpperCase() != "CSV") {
	// 	cfAlertMsg("파일이 CSV인 것만 Import가 가능합니다.<br>엑셀 파일을 CSV로 변환 하시어 Import하시기 바랍니다.");
	// }

	// ds_up_cntr.DataId="";
	// ds_up_cntr.DataId="file://" + inputF.Value;

	ds_up_cntr.removeAll();
	ds_tmp_cntr.removeAll();

	// ds_up_cntr.Reset();
	// ds_tmp_cntr.ImportData(ds_up_cntr.ExportData(1, ds_up_cntr.CountRow, true));

	scwin.excelUploadYn = 1;

	var cntrRow = ds_cntrInfo.getRowCount();

	// EXCEL 로 UPLOAD 된 컨테이너 정보를 설정
	for (var i_cntr = 0; i_cntr < ds_tmp_cntr.getRowCount(); i_cntr++) {
		var colid = "cntrNo";
		var row = ds_cntrInfo.getRowPosition();

		// 컨테이너 정보 설정	- 칸테이너 번호가 존재하는 경우 행추가 / 아닌경우 컨테이너 번호 대체	
		if (row == 0 || ds_cntrInfo.getCellData(row, "cntrNo") != "") {
			ds_cntrInfo.insertRow();
			row = ds_cntrInfo.getRowCount();
		}

		ds_cntrInfo.setCellData(row, "odrNo", ds_odrInfo.getCellData(1, "odrNo"));
		ds_cntrInfo.setCellData(row, colid, ds_tmp_cntr.getCellData(i_cntr, colid));

		// 컨테이너번호 유효성체크
		scwin.f_checkCntrNo(ds_cntrInfo.getCellData(row, colid));

		for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
			if (ds_cntrInfo.getCellData(i, "cntrNo") == ds_cntrInfo.getCellData(row, colid)) {
				if (row != i && ds_cntrInfo.getRowStatus(i) != "D") {
					if (await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032.replace("%1", "%3"), ["컨테이너목록", (i + 1), "컨테이너번호"])) { //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
                        ds_cntrInfo.setCellData(row, "cntrNo", "");
                        return;
                    } 
				}
			}
		}

		// 수출본선인 경우			
		ds_cntrInfo.setCellData(row, "wrkStDt", ed_wrkStDt.getValue().trim());
		ds_cntrInfo.setCellData(row, "wrkStHh", ed_wrkStHh.getValue().trim());
		ds_cntrInfo.setCellData(row, "wrkEndDt", ed_wrkEndDt.getValue().trim());
		ds_cntrInfo.setCellData(row, "wrkEndHh", ed_wrkEndHh.getValue().trim());

		if (scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR) {		// ON-HIRE(C5)
			ds_cntrInfo.setCellData(row, "cntrSizCd", ds_tmp_cntr.getCellData(i_cntr, "cntrSizCd"));	
			ds_cntrInfo.setCellData(row, "cntrTypCd", ds_tmp_cntr.getCellData(i_cntr, "cntrTypCd"));	
			ds_cntrInfo.setCellData(row, "fullEmptyClsCd", ds_tmp_cntr.getCellData(i_cntr, "fullEmptyClsCd"));
			ds_cntrInfo.setCellData(row, "wt",ds_tmp_cntr.getCellData(i_cntr, "wt"));
			ds_cntrInfo.setCellData(row, "temper", ds_tmp_cntr.getCellData(i_cntr, "temper"));
		} else { 
           scwin.f_retrieveCntrBasisInfo(ds_cntrInfo.getCellData(row, colid));

           if (scwin.odrKndCd == DsConstants.ODR_KND_CD_PORT_CHANGE_ODR) {
			    ds_cntrInfo.setCellData(row, "cntrSizCd", ds_tmp_cntr.getCellData(i_cntr, "cntrSizCd"));	
			    ds_cntrInfo.setCellData(row, "cntrTypCd", ds_tmp_cntr.getCellData(i_cntr, "cntrTypCd"));	
			    ds_cntrInfo.setCellData(row, "fullEmptyClsCd", ds_tmp_cntr.getCellData(i_cntr, "fullEmptyClsCd"));	
				ds_cntrInfo.setCellData(row, "portCd", ds_tmp_cntr.getCellData(i_cntr, "portCd"));	
				ds_cntrInfo.setCellData(row, "wt", ds_tmp_cntr.getCellData(i_cntr, "wt"));	
				ds_cntrInfo.setCellData(row, "expSealNo", ds_tmp_cntr.getCellData(i_cntr, "expSealNo"));
				ds_cntrInfo.setCellData(row, "lineCd", ds_odrInfo.getCellData(1, "lineCd"));	
			} else {
				ds_cntrInfo.setCellData(row, "expSealNo", ds_tmp_cntr.getCellData(i_cntr, "expSealNo"));	
				ds_cntrInfo.setCellData(row, "portCd", ds_tmp_cntr.getCellData(i_cntr, "portCd"));	
				ds_cntrInfo.setCellData(row, "term", ds_tmp_cntr.getCellData(i_cntr, "term"));
			}	
		}
		// 컨테이너 품명목록 정보 설정
		scwin.f_calInputQtyUpload(row);
	}

    // 총건수 세팅
    commTotalRows.setValue(ds_commInfo.getRowCount());
    sellTotalRows.setValue(ds_sellInfo.getRowCount());
    cntrTotalRows.setValue(ds_cntrInfo.getRowCount());

	scwin.excelUploadYn = 0;  // EXCEL UPLOAD (C3) 여부 
	scwin.cntrLoadGubun = "";
} 

// Excel Upload 적용후 컨테이너 품명 목록 정보 설정
scwin.f_calInputQtyUpload = async function (row) {
	var cntrRows = ds_cntrInfo.getRowCount();
	var commRows = ds_commInfo.getRowCount();

	// 품명목록의 입력수량 계산
	for (var i = row; i < cntrRows; i++) {	
		var sameYn = "N";
		if (ds_cntrInfo.getCellData(row, "cntrNo") == "")	
            return false;	// 컨테이너 번호가 존재하지 않는 경우 

		for (var j = 1; j < commRows; j++) {
			var idx = 0;			
			if (ds_cntrInfo.getCellData(i, "cntrSizCd")	   == ds_commInfo.getCellData(j, "cntrSizCd")			&& 
				ds_cntrInfo.getCellData(i, "cntrTypCd")	   == ds_commInfo.getCellData(j, "cntrTypCd")			&& 
				ds_cntrInfo.getCellData(i, "fullEmptyClsCd") == ds_commInfo.getCellData(j, "fullEmptyClsCd")
			) {
				sameYn = "Y";	
				idx = j;
				break;					
			}
		}

		if (sameYn == "N") {	
			var rowIndex = ds_commInfo.insertRow();
			if (commRows > 0) {
				ds_commInfo.setCellData(rowIndex, "wrkStDt", ds_commInfo.getCellData(commRows-1, "wrkStDt"));
				ds_commInfo.setCellData(rowIndex, "wrkStHh", ds_commInfo.getCellData(commRows-1, "wrkStHh"));
				ds_commInfo.setCellData(rowIndex, "wrkEndDt", ds_commInfo.getCellData(commRows-1, "wrkEndDt"));
				ds_commInfo.setCellData(rowIndex, "wrkEndHh", ds_commInfo.getCellData(commRows-1, "wrkEndHh"));
			} else {
				ds_commInfo.setCellData(rowIndex, "wrkStDt", ed_wrkStDt.getValue().trim());
				ds_commInfo.setCellData(rowIndex, "wrkStHh", ed_wrkStHh.getValue().trim());
				ds_commInfo.setCellData(rowIndex, "wrkEndDt", ed_wrkEndDt.getValue().trim());
				ds_commInfo.setCellData(rowIndex, "wrkEndHh", ed_wrkEndHh.getValue().trim());
			}

			ds_commInfo.setCellData(rowIndex, "cntrSizCd", ds_cntrInfo.getCellData(i, "cntrSizCd"));
			ds_commInfo.setCellData(rowIndex, "cntrTypCd", ds_cntrInfo.getCellData(i, "cntrTypCd"));
			ds_commInfo.setCellData(rowIndex, "fullEmptyClsCd", ds_cntrInfo.getCellData(i, "fullEmptyClsCd"));
			ds_commInfo.setCellData(rowIndex, "grossWt", ds_cntrInfo.getCellData(i, "wt"));
			ds_commInfo.setCellData(rowIndex, "temper", ds_cntrInfo.getCellData(i, "temper"));
			ds_commInfo.setCellData(rowIndex, "dryYn", ds_cntrInfo.getCellData(i, "dryYn"));
			ds_commInfo.setCellData(rowIndex, "qty", 1);	
			ds_commInfo.setCellData(rowIndex, "inputQty", 1);	
		} else {
