                            ds_cntrInfo.setCellData(i, "cntrWrkClsCd", ds_cntrInfo.getCellData(0, "cntrWrkClsCd"));
                            ds_cntrInfo.setCellData(i, "chk", 0);
                        }             
                    }
                }
            }

            if (lc_sizClsCd.getText() != "ALL" && lc_typClsCd.getText() == "ALL" && lc_efClsCd.getText() != "ALL") {
                for (var i = 1; i < ds_cntrInfo.getRowCount(); i++) {
                    if (ds_cntrInfo.getCellData(i, "chk") == true) {
                        if (lc_sizClsCd.getText() == ds_cntrInfo.getCellData(i, "cntrSizCd") && lc_efClsCd.getText() == ds_cntrInfo.getCellData(i, "fullEmptyClsCd")) {
                            ds_cntrInfo.setCellData(i, "cntrWrkClsCd", ds_cntrInfo.getCellData(0, "cntrWrkClsCd"));
                            ds_cntrInfo.setCellData(i, "chk", 0);
                        }             
                    }
                }
            }
        }
		for (var i = 1; i < ds_cntrInfo.getRowCount(); i++) {
			if (ds_cntrInfo.getCellData(i, "chk") == true) {
				ds_cntrInfo.setCellData(i, "chk", 0);
			}
		}

	} else {
		await $c.gus.cfAlertMsg("복사할 항목을 선택하여 주세요.");
	}
};

