	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR) { // 수입하역컨테이너오더
		// 활성/비활성시키기
		scwin.f_setBlNo("E");
		scwin.f_setCvsslMgntNo("D");		
		scwin.f_setBookingNo("E");
		scwin.f_setDptWrkPlCd("E");
		scwin.f_setCommGrid("E");	
		scwin.f_setVsslCd("D");
		scwin.f_setPortcnt("E"); 		
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR) { // 수출하역컨테이너오더			
		// 활성/비활성시키기
		scwin.f_setBlNo("E");
		scwin.f_setCvsslMgntNo("E");	
		scwin.f_setBookingNo("E");
		scwin.f_setDptWrkPlCd("E");
		scwin.f_setCommGrid("E");	
		scwin.f_setVsslCd("D");
		scwin.f_setPortcnt("E"); 			
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR 		 // 수입일반컨테이너오더
			  || scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 	 // CFS셔틀
			  || scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR  // 세관검사 
