		if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) { // 수입일반컨테이너오더
			// 자가영업인경우, 아닌 경우
			if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) {	
				// 활성/비활성		
				scwin.f_setCvsslMgntNo("E");				
				scwin.f_setVsslCd("E");
				scwin.f_setPortcnt("E"); 

				// mandatory표시 보이기(본선관리번호, 선박명, 항차)	
