                    { id: "ed_vsslCd",          exp: "" },
                    { id: "ed_portcnt",         exp: "" }
                ]);
			} else {
				// 활성/비활성	
				scwin.f_setCvsslMgntNo("D");					
				scwin.f_setVsslCd("D");
				scwin.f_setPortcnt("D");

				// mandatory표시 보이기(본선관리번호, 선박명, 항차)	
