			scwin.f_displayGridColumn(gr_cntrInfo, ["impCntrWrkKndCd", "impMgsetYn", "dcsnYn", "temper"], "edit", "any");
			scwin.f_displayGridColumn(gr_cntrInfo, ["wrkStDt","wrkStHh", "wrkEndDt", "wrkEndHh"], "edit", "numeric");
		}
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR	 	//수출일반컨테이너오더
			  || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR			//On-hire
			  || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR			//Off-hire 
			  || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR	//Empty Position
	) {		
		if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반컨테이너오더(C4)	
			// 활성/비활성시키기
			scwin.f_setBlNo("E");
			scwin.f_setCvsslMgntNo("E");	
			scwin.f_setBookingNo("D");
			scwin.f_setDptWrkPlCd("E");
			scwin.f_setCommGrid("E");
			scwin.f_setCommGridForFE("D");

			scwin.f_setCntrGridForSizTypFE("D");
			scwin.f_setVsslCd("E");
