				scwin.f_setCntrGridForSizTypFE("D");
				scwin.f_displayGridColumn(gr_cntrInfo, ["currPosCd"], "edit", "none"); 	
                scwin.setValidations([
                    { id: "ed_lineCd", exp: "Line코드:yes" }
                ]);
			}

			// 그리드 edit가능
			scwin.f_displayGridColumn(gr_cntrInfo, ["portCd", "destPortCd"], "edit", "upper"); 
			scwin.f_displayGridColumn(gr_cntrInfo, ["leaseYn", "socYn", "offRtrnClsCd", "temper", "dryYn"], "edit", "any"); 
			scwin.f_displayGridColumn(gr_cntrInfo, ["wt","wrkStDt","wrkStHh","wrkEndDt","wrkEndHh"], "edit", "numeric"); 	

		} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR	// Empty Position(오더기본정보부분은 셔틀과 같음)	
				  || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		// On-hire(오더기본정보부분은 셔틀과 같음) 
				  || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR		// Off-hire 
		) {		
			// 활성/비활성시키기
			scwin.f_setBlNo("E");	
			scwin.f_setBookingNo("D");
			scwin.f_setCvsslMgntNo("E");		
			scwin.f_setDptWrkPlCd("E");
			scwin.f_setCommGrid("E");
			scwin.f_setVsslCd("E");
			scwin.f_setPortcnt("E"); 

			// 그리드 edit불가
			scwin.f_displayGridColumn(gr_cntrInfo, ["currPosCd"], "edit", "none"); 
			scwin.f_displayGridColumn(gr_cntrInfo, ["portCd"], "edit", "upper"); 	
			scwin.f_displayGridColumn(gr_cntrInfo, ["temper", "wrkStDt","wrkStHh","wrkEndDt","wrkEndHh"], "edit", "any"); 	

			if (scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR) {					
				scwin.f_setCommGridForFE("E");
				scwin.f_setCntrGridForSizTypFE("E");	

			} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR) { // OFF-HIRE오더인 경우, 품명목록의 F/E항목 체크불가	
				scwin.f_setCommGridForFE("E");
				scwin.f_setCntrGridForSizTypFE("EC");

				// off반납구분코드 보이게 함
                gr_cntrInfo.setColumnVisible("offRtrnClsCd", true);

				// 그리드 edit 불가 				
                gr_cntrInfo.setColumnReadOnly("offRtrnClsCd", true);
			} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) { //Empty Position오더인 경우									
				scwin.f_setCommGridForFE("E");

				// 자가영업인 경우/아닌 경우
				if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) {
					scwin.f_setCntrGridForSizTypFE("E");
				} else {
					scwin.f_setCntrGridForSizTypFE("EC");
				}
			}
		}
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) { // 부두간TS셔틀컨테이너인 경우
	    if (scwin.odrCtrlClsCd == "1") {				
			// 활성/비활성시키기
			scwin.f_setBlNo("E");
			scwin.f_setDptWrkPlCd("D");
			scwin.f_setCommGrid("D");	
			scwin.f_setCntrGridForSizTypFE("D");
			scwin.f_setCvsslMgntNo("D");	
			scwin.f_setVsslCd("D");
			scwin.f_setPortcnt("E"); 
			scwin.f_setBookingNo("E");

			// 그리드 edit 불가
			scwin.f_displayGridColumn(gr_cntrInfo, ["currPosCd"], "edit", "none"); 
			scwin.f_displayGridColumn(gr_cntrInfo, ["arvWrkPlCd", "portCd", "destPortCd"], "edit", "upper"); 
			scwin.f_displayGridColumn(gr_cntrInfo, ["temper"], "edit", "any"); 	
	   } else {
            //활성/비활성시키기
            scwin.f_setBlNo("E");
            scwin.f_setDptWrkPlCd("D");
            scwin.f_setCommGrid("E");
            scwin.f_setCntrGridForSizTypFE("E");	
            scwin.f_setCvsslMgntNo("D");	
            scwin.f_setVsslCd("D");
            scwin.f_setPortcnt("E"); 
            scwin.f_setBookingNo("E");

            //그리드 edit 불가
            scwin.f_displayGridColumn(gr_cntrInfo, ["currPosCd"], "edit", "none"); 
            scwin.f_displayGridColumn(gr_cntrInfo, ["arvWrkPlCd", "portCd", "destPortCd"], "edit", "upper"); 
            scwin.f_displayGridColumn(gr_cntrInfo, ["temper"], "edit", "any"); 		
        }	
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR) { // 하선지(CY간)TS셔틀컨테이너인 경우(부두-->TS)
		// 활성/비활성시키기
		scwin.f_setBlNo("E");
		scwin.f_setDptWrkPlCd("D");
		scwin.f_setCommGrid("D");	

		scwin.f_setCntrGridForSizTypFE("D");
