// 실적 발생여부를 확인
scwin.f_chkResultsConfirmation = function(gubun) {
	var cntrTotalRows = ds_cntrInfo.getRowCount();
	if (gubun == "CNTR_ROW") {
	  	if (cntrTotalRows > 0) {
	  		if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "wrkRsltsNo")))	
                return true; // 실적이 존재하는 경우
	  	}
	} else {	
	  	if (cntrTotalRows > 0) {
	  		for (var i = 0; i < cntrTotalRows; i++) {
                if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo")))	
                    return true; // 실적이 존재하는 경우
	  		}
	  	}  
	}	
  	return false;	// 실적이 존재하지 않는 경우
};

// 그리드에서 컨테이너의 실적여부에 따라 입력여부 판정
scwin.f_setGridCntrInfoByWrkRslts = function(row) {
	var cntrInfoRows = ds_cntrInfo.getRowCount();
	if (cntrInfoRows > 0 && btn_update.getDisabled()) {
		if (scwin.f_chkResultsConfirmation("CNTR_ROW")) { // 실적발생한 경우

            for(var i = 0; i < gr_cntrInfo.getColumnCount(); i++) {
                var colId = gr_cntrInfo.getColumnID(i);
                gr_cntrInfo.setColumnReadOnly(colId, true);
            } 
		} else { // 실적발생하지 않은 경우
            for (var i = 0; i < gr_cntrInfo.getColumnCount(); i++) {
                var colId = gr_cntrInfo.getColumnID(i);
                if(gr_cntrInfo.getCellInfo(colId).options.userData1 == "Y"){
                    gr_cntrInfo.setColumnReadOnly(colId, true);
                } else {
                    gr_cntrInfo.setColumnReadOnly(colId, false);
                }
            }

			if (ds_cntrInfo.getRowStatus(row) == "C") { // insert인 경우
				scwin.f_displayGridColumn(gr_cntrInfo, ["cntrNo"], "edit", "upper"); 

				//오더별 세팅
				if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR) { // 수출본선, 수출TS			
					scwin.f_setCntrGridForSizTypFE("EC");
				} else if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) // 수출일반(자가영업)
						  || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR	       // on-hire
						  || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR	       // off-hire
						  || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR   // empty position
						  || (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "2")
				) { 	
					if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd != DsConstants.SELF_CLS_CD_SELF_SALES)	// empty position(자가영업이 아닌경우)
						|| scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR   //off-hire
					) {
						scwin.f_setCntrGridForSizTypFE("EC");
					} else {
						scwin.f_setCntrGridForSizTypFE("E");
					}
				} else {
					scwin.f_setCntrGridForSizTypFE("D");
				}
			} else { 
				// 현재 컨테이너번호 또는 org컨테이너번호가 미지정인 경우(update인 경우)
				if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(row, "cntrNo")) || $c.gus.cfIsNull(ds_cntrInfo.getOriginalCellData(row, "cntrNo"))) { 
					scwin.f_displayGridColumn(gr_cntrInfo, ["cntrNo"], "edit", "upper");

					// 오더별 세팅
					if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR) { // 수출본선, 수출TS			
						scwin.f_setCntrGridForSizTypFE("EC");

					} else if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) // 수출일반(자가영업)
							  || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		   // on-hire
					 		  || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR	       // off-hire
							  || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR   // empty position
					) { 	
						if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd != DsConstants.SELF_CLS_CD_SELF_SALES	// empty position(자가영업이 아닌경우)
							|| scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR   // off-hire
						) {
							scwin.f_setCntrGridForSizTypFE("EC");
						} else {
							scwin.f_setCntrGridForSizTypFE("E");
						}
					} else {
						scwin.f_setCntrGridForSizTypFE("D");					
					}
				} else {
					scwin.f_displayGridColumn(gr_cntrInfo, ["cntrNo"], "edit", "none");
					scwin.f_setCntrGridForSizTypFE("D");
				}	
			}

			// 수출일반인 경우  - 컨테이너 type이 RF인 경우, 온도 또는 dry 체크
			scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, row);
		}
	}
};

// 품명 또는 컨테이너의 type이 RF인 경우, 온도 또는 DRY 필드의 EDIT여부 체크
scwin.f_setTemperDryByRFCntr = function(ds, gr, row) {
    // 품명 또는 컨테이너  type이 RF인 경우, 온도 또는 dry 체크
    var type   = ds.getCellData(row, "cntrTypCd");
    var temper = ds.getCellData(row, "temper");
    var dryYn  = ds.getCellData(row, "dryYn");

    // 오더별 체크
    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR		//수입하역
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR	//수출하역
    ) {
        if (scwin.statusFlag == "C") { // 신규등록시
            scwin.f_setCommGrid("E");
        } else if (scwin.statusFlag == "U") { // 수정시
            if (ds.getRowStatus(row) == "C") { // 행추가인 경우
                scwin.f_setCommGrid("E");
            } else {
                scwin.f_setCommGrid("O");
            }
        }
    } else { // 그외 오더
        if (type == DsConstants.CNTR_TYP_CD_RF || type == DsConstants.CNTR_TYP_CD_RH) {
            if (!$c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_NO) {
                gr.setColumnReadOnly("temper", false);
                gr.setColumnReadOnly("dryYn", true);
            } else if ($c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_YES) {
                gr.setColumnReadOnly("temper", true);
                gr.setColumnReadOnly("dryYn", false);
            } else {
                gr.setColumnReadOnly("temper", false);
                gr.setColumnReadOnly("dryYn", false);
            }
        } else {
            ds.setCellData(row, "temper", "");
            ds.setCellData(row, "dryYn", 0);
            gr.setColumnReadOnly("temper", true);
            gr.setColumnReadOnly("dryYn", true);
        }
    }
};

