        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId3);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm3.getValue());		
	}

	if (ed_alloccarPicNm4.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm4.getValue())) {
	    k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId4);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm4.getValue());		
	}

	if (ed_alloccarPicNm5.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm5.getValue())) {
	    k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId5);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm5.getValue());		
	}

	if (scwin.statusFlag == "U") { // 수정
		if (ds_odrInfo.getModifiedIndex().length > 0 || 
            ds_commInfo.getModifiedIndex().length > 0 || 
            ds_cntrInfo.getModifiedIndex().length > 0 || 
            ds_blInfo.getModifiedIndex().length > 0 || 
            ds_orderallocarpicnm.getModifiedIndex().length > 0 || 
            scwin.bookingNoYn == "Y"
		) {
			scwin.f_setValueBeforeValidation(); // validation하기 전에 꼭 세팅되어야 할 값들을 세팅
		    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) {
		        var gv_currDate = scwin.strCurDate;
		        if ((ica_closeDt.getValue() != null && ica_closeDt.getValue() != "")) {
			        if (ica_closeDt.getValue() < gv_currDate) {
						var diffObj = $c.gus.cfDifferBetween(ica_closeDt.getValue(), gv_currDate);

						// 마감일자가 1달 이상인경우 확인
						if (diffObj.year > 0 || diffObj.month > 0) {
                            if (await !$c.win.confirm("마감일자가 1개월이 넘습니다.등록하시겠습니까?")) {
                                ica_closeDt.focus();
								return false;
                            }
						}	
					}
				}

				// 출발일자 도착일자 한달 이전 일 못들어 가게
		        if ((ed_wrkStDt.getValue() != null && ed_wrkStDt.getValue() != "")) {
			        if (ed_wrkStDt.getValue() < gv_currDate) {
						var diffObj = $c.gus.cfDifferBetween(ed_wrkStDt.getValue(), gv_currDate);

						// 마감일자가 1달 이상인경우 확인
						if (diffObj.year > 0 || diffObj.month > 0) {
                            if (await !$c.win.confirm("입항일시가 1개월이 넘습니다.등록하시겠습니까?")) {
								ed_wrkStDt.focus();
								return false;
							}
						}	
					}
				}

		        if ((ed_wrkEndDt.getValue() != null && ed_wrkEndDt.getValue() != "")) {
			        if (ed_wrkEndDt.getValue() < gv_currDate) {
						var diffObj = $c.gus.cfDifferBetween(ed_wrkEndDt.getValue(), gv_currDate);

						// 마감일자가 1달 이상인경우 확인
						if (diffObj.year > 0 || diffObj.month > 0) {
                            if (await !$c.win.confirm("출항일시가 1개월이 넘습니다.등록하시겠습니까?")) {
								ed_wrkEndDt.Focus();
								return false;
							}
						}	
					}
				}
            }			

            if ($c.util.isEmpty(lc_ctrtNo.getValue())) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약번호"]); // @은(는) 필수 입력 항목입니다
                return false;
            }
            chkVal = await $c.gus.cfValidate([tbl_odrInfoArea]);
            if (chkVal) {
                chkVal = await $c.gus.cfValidate([gr_commInfo, gr_cntrInfo]); 
                if (chkVal) {
                    // 품명정보 validation체크
                    for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
                        if (ds_commInfo.getRowStatus(i) != "D") { //삭제건이 아닌 경우 		

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "cntrSizCd"))) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["품명목록", i+1, "Size"]); 
                                gr_commInfo.setFocusedCell(i, "cntrSizCd", true);
                                return false;
                            }

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "cntrTypCd"))) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["품명목록", i+1, "Type"]);
                                gr_commInfo.setFocusedCell(i, "cntrTypCd", true);
                                return false;
                            }

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "fullEmptyClsCd"))) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["품명목록", i+1, "F/E"]);
                                gr_commInfo.setFocusedCell(i, "fullEmptyClsCd", true);
                                return false;
                            }

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "qty")) || Number(ds_commInfo.getCellData(i, "qty")) < 1) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + " 수량은 1 이상으로 입력하십시오.", ["품명목록", i+1]);
                                gr_commInfo.setFocusedCell(i, "qty", true);
                                return false;
                            }
                        }
                    }

                    // 품명목록과 컨테이너목록의 수량 체크
                    if (!await scwin.f_calInputQty("Y"))
                        return;	

                    if (!await scwin.f_validate())
                        return;

                    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR			// 수입하역컨테이너오더
                        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR		// 수출하역컨테이너오더
                    ) {
                        if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                            scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                            scwin.f_updateByOdrKndCd();     // 오더종류별 저장
                        }
                    } else {
                        var gv_currDate = scwin.strCurDate;
                        if (gv_currDate < "20080814" && scwin.sUserId != "pchang") {
                                if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                                    scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                                    scwin.f_updateByOdrKndCd();     // 오더종류별 저장
                                }				
                        } else {
                            if (scwin.sUserId == "pchang") {
                                if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                                    scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                                    scwin.f_updateByOdrKndCd();     // 오더종류별 저장
                                }						        
                            } else {
                                await $c.gus.cfAlertMsg("2008년8월6일부터는 엔콜 트럭을 이용하여 오더등록을 진행하시기 바랍니다.");		
                            }
                        }			  
                    }

                    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                        scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                        scwin.f_updateByOdrKndCd();     // 오더종류별 저장
                    }
                }
            }
		} else {
			await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); // 은(는) 변경된 사항이 없습니다.	
		}  
	} else if (scwin.statusFlag == "C") { // 신규
		if (ds_odrInfo.getModifiedJSON().length > 0) {
			scwin.f_setValueBeforeValidation(); // validation하기 전에 꼭 세팅되어야 할 값들을 세팅
		    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) {
		        var gv_currDate =  scwin.strCurDate;
		        if ((ica_closeDt.getValue() != null && ica_closeDt.getValue() != "")) {
			        if (ica_closeDt.getValue() < gv_currDate) {
						var diffObj = $c.gus.cfDifferBetween(ica_closeDt.getValue(), gv_currDate);

						// 마감일자가 1달 이상인경우 확인
						if (diffObj.year > 0 || diffObj.month > 0) {
                            if (await !$c.win.confirm("마감일자가 1개월이 넘습니다.등록하시겠습니까?")) {
								ica_closeDt.focus();
								return false;
							}
						}	
					}
				}

				// 출발일자 도착일자 한달 이전 일 못들어 가게
		        if ((ed_wrkStDt.getValue() != null && ed_wrkStDt.getValue() != "")) {
			        if (ed_wrkStDt.getValue() < gv_currDate) {
						var diffObj = $c.gus.cfDifferBetween(ed_wrkStDt.getValue(), gv_currDate);

						// 마감일자가 1달 이상인경우 확인
						if (diffObj.year > 0 || diffObj.month > 0) {
                            if (await !$c.win.confirm("입항일시가 1개월이 넘습니다.등록하시겠습니까?")) {
								ed_wrkStDt.focus();
								return false;
							}
						}	
					}
				}
		        if ((ed_wrkEndDt.getValue() != null && ed_wrkEndDt.getValue() != "")) {
			        if (ed_wrkEndDt.getValue() < gv_currDate) {
						var diffObj = $c.gus.cfDifferBetween(ed_wrkEndDt.getValue(), gv_currDate);

						// 마감일자가 1달 이상인경우 확인
						if (diffObj.year > 0 || diffObj.month > 0) {
                            if (await !$c.win.confirm("출항일시가 1개월이 넘습니다.등록하시겠습니까?")) {
								ed_wrkEndDt.focus();
								return false;
							}
						}	
					}
				}
		    }			

            if (lc_ctrtNo.getValue() == "선택") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약번호"]); // @은(는) 필수 입력 항목입니다
                return false;
            }
            chkVal = await $c.gus.cfValidate([tbl_odrInfoArea]);
            if (chkVal) {
                chkVal = await $c.gus.cfValidate([gr_commInfo, gr_cntrInfo]); 
                if (chkVal) {
                    // 품명정보 validation체크
                    for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
                        if (ds_commInfo.getRowStatus(i) != "D") { //삭제건이 아닌 경우 		

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "cntrSizCd"))) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["품명목록", i+1, "Size"]); 
                                gr_commInfo.setFocusedCell(i, "cntrSizCd", true);
                                return false;
                            }

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "cntrTypCd"))) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["품명목록", i+1, "Type"]);
                                gr_commInfo.setFocusedCell(i, "cntrTypCd", true);
                                return false;
                            }

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "fullEmptyClsCd"))) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["품명목록", i+1, "F/E"]);
                                gr_commInfo.setFocusedCell(i, "fullEmptyClsCd", true);
                                return false;
                            }

                            if ($c.util.isEmpty(ds_commInfo.getCellData(i, "qty")) || Number(ds_commInfo.getCellData(i, "qty")) < 1) {
                                await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + " 수량은 1 이상으로 입력하십시오.", ["품명목록", i+1]);
                                gr_commInfo.setFocusedCell(i, "qty", true);
                                return false;
                            }
                        }
                    }
                    // 품명목록과 컨테이너목록의 Validation 체크 및 수량 체크
                    if (!await scwin.f_calInputQty("Y")) 
                        return;
                    if (!await scwin.f_validate())	
                        return;

                    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR			//수입하역컨테이너오더
                        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR		//수출하역컨테이너오더
                    ) {
                        if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                            scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                            scwin.f_registByOdrKndCd();     // 오더종류별 저장
                        }				
                    } else {
                        var gv_currDate = scwin.strCurDate;
                        if (gv_currDate < "20080826" && scwin.sUserId != "pchang") {	
                            if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                                scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                                scwin.f_registByOdrKndCd();     // 오더종류별 저장
                            }				
                        } else {
                            if (scwin.sUserId == "pchang") {
                                if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                                    scwin.f_setValueBeforeSave();   // 저장하기전 데이터 세팅
                                    scwin.f_registByOdrKndCd();     // 오더종류별 저장
                                }	
                            } else {
                                await $c.gus.cfAlertMsg("2008년8월6일부터는 엔콜 트럭을 이용하여 오더등록을 진행하시기 바랍니다.");							               
                            }
                        }
                    }	
                }
            }
		} else {
			if (ds_commInfo.getModifiedJSON().length > 0 || ds_cntrInfo.getModifiedJSON().length > 0) {
                if (await $c.gus.cfValidate([tbl_odrInfoArea])) {
                    return;
                }
			} else {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); //@은(는) 변경된 사항이 없습니다.
			}
		}  
	}
};

// 품명목록 행추가
scwin.f_addRow1 = async function () {


	var commRows = ds_commInfo.getRowCount();
	var cntrNo   = ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "cntrNo");

    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR		// 수출일반인 경우
        || (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "2")
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		    // On-hire
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR		// Off-hire 
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR	// Empty Postion 
    ) {
        if(await $c.gus.cfValidateGrid(gr_commInfo, null, null, scwin.gr_commInfo_validConfig, "품명목록")) {
            if( await scwin.f_validateCommAndCntr() ){

            } else {
                return;
            }
        } else {
            return;
        }

        var rowIndex = ds_commInfo.insertRow();
        ds_commInfo.setRowPosition(rowIndex);
        scwin.gr_commInfo_lastRowIndex = rowIndex;
        if (commRows > 0) {
            ds_commInfo.setCellData(rowIndex, "wrkStDt", ds_commInfo.getCellData(commRows-1, "wrkStDt"));
            ds_commInfo.setCellData(rowIndex, "wrkStHh", ds_commInfo.getCellData(commRows-1, "wrkStHh"));
            ds_commInfo.setCellData(rowIndex, "wrkEndDt", ds_commInfo.getCellData(commRows-1, "wrkEndDt"));
            ds_commInfo.setCellData(rowIndex, "wrkEndHh", ds_commInfo.getCellData(commRows-1, "wrkEndHh"));
        } else {
            ds_commInfo.setCellData(rowIndex, "wrkStDt", ed_wrkStDt.getValue().trim());
            ds_commInfo.setCellData(rowIndex, "wrkStHh", ed_wrkStHh.getValue().trim());
            ds_commInfo.setCellData(rowIndex, "wrkEndDt", ed_wrkEndDt.getValue().trim());
            ds_commInfo.setCellData(rowIndex, "wrkEndHh", ed_wrkEndHh.getValue().trim());
        }

        // F/E를 항상 E로 세팅 - Empty Position, Off-hire
        // F/E를 항상 F로 세팅 - 수출일반
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR  // Empty Position
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR 	 // OFF-HIRE
        ) {
            ds_commInfo.setCellData(rowIndex, "fullEmptyClsCd", "E");

        } else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) {
            ds_commInfo.setCellData(rowIndex, "fullEmptyClsCd", "F");
        }
    } else {
        if(await $c.gus.cfValidateGrid(gr_commInfo, null, null, scwin.gr_commInfo_validConfig, "품명목록")) {
            if( await scwin.f_validateCommAndCntr() ){

            } else {
                return;
            }
        } else {
            return;
        }

        var rowIndex = ds_commInfo.insertRow();
        ds_commInfo.setRowPosition(rowIndex);
        scwin.gr_commInfo_lastRowIndex = rowIndex;
        ds_commInfo.setCellData(rowIndex, "wrkStDt", ed_wrkStDt.getValue().trim());
        ds_commInfo.setCellData(rowIndex, "wrkStHh", ed_wrkStHh.getValue().trim());
        ds_commInfo.setCellData(rowIndex, "wrkEndDt", ed_wrkEndDt.getValue().trim());
        ds_commInfo.setCellData(rowIndex, "wrkEndHh", ed_wrkEndHh.getValue().trim());
    }
};

// 품명목록 행삭제
scwin.f_deleteRow1 = async function () {
    var commInfoRows = ds_commInfo.getRowCount();
	var cntrInfoRows = ds_cntrInfo.getRowCount();
	scwin.btnPos = "D1";

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반인 경우 : FullEmpty구분할필요없음
        if (commInfoRows > 0) {
            var cntrSizCd	= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrSizCd");
            var cntrTypCd	= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrTypCd");
            var grossWt		= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "grossWt");
            var temper		= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "temper");
            var dryYn		= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "dryYn"); 
            var sameYn 		= "N";
            var wrkRsltsYn	= "N";

            for (var i = cntrInfoRows - 1; i >= 0; i--) {
                if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { // 실적일어나지 않은 경우만 해당
                    if (ds_cntrInfo.getCellData(i, "cntrSizCd") 	== cntrSizCd
                        && ds_cntrInfo.getCellData(i, "cntrTypCd") 	== cntrTypCd
                        && ds_cntrInfo.getCellData(i, "wt") 		== grossWt
                        && ds_cntrInfo.getCellData(i, "temper")		== temper
                        && ds_cntrInfo.getCellData(i, "dryYn") 		== dryYn
                    ) {
                        // ds_cntrInfo.DeleteRow(i); (확인할것)
                        ds_cntrInfo.deleteRow(i);
                        sameYn = "Y";
                    }
                } else {
                    if (ds_cntrInfo.getCellData(i, "cntrSizCd") 	== cntrSizCd
                        && ds_cntrInfo.getCellData(i, "cntrTypCd") 	== cntrTypCd
                        && ds_cntrInfo.getCellData(i, "wt") 		== grossWt
                        && ds_cntrInfo.getCellData(i, "temper")		== temper
                        && ds_cntrInfo.getCellData(i, "dryYn") 		== dryYn
                    ) {   
                        wrkRsltsYn = "Y";
                    }
                }
            }

            if (sameYn == "Y")
                scwin.f_calInputQty();

            // 실적체크
            if (wrkRsltsYn == "Y") {
                await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_002, ["품명"]); //"실적이 발생한 @은 삭제할 수 없습니다."
            } else {
                scwin.fn_deleteGridRowByStatus(ds_commInfo, gr_commInfo, ds_commInfo.getRowPosition());
            }
        }    
	} else {	
        if (commInfoRows > 0) {
            var cntrSizCd	= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrSizCd");
            var cntrTypCd	= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrTypCd");
            var fullEmptyClsCd	= ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "fullEmptyClsCd");   
            var sameYn = "N";
            var wrkRsltsYn	= "N";

            for (var i = cntrInfoRows - 1; i >= 0; i--) {
                if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { // 실적일어나지 않은 경우만 해당
                    if (ds_cntrInfo.getCellData(i, "cntrSizCd") == cntrSizCd
                        && ds_cntrInfo.getCellData(i, "cntrTypCd") == cntrTypCd
                        && ds_cntrInfo.getCellData(i, "fullEmptyClsCd") == fullEmptyClsCd 
                    ) {   
                        // ds_cntrInfo.DeleteRow(i); (확인할것)
                        ds_cntrInfo.deleteRow(i);
                        sameYn = "Y";
                    }
                } else {
                    if (ds_cntrInfo.getCellData(i, "cntrSizCd") == cntrSizCd
                        && ds_cntrInfo.getCellData(i, "cntrTypCd") == cntrTypCd
                        && ds_cntrInfo.getCellData(i, "fullEmptyClsCd") == fullEmptyClsCd 
                    ) {   
                        wrkRsltsYn = "Y";
                    }
                }
            }

            if (sameYn == "Y")
                scwin.f_calInputQty();

            // 실적체크
            if (wrkRsltsYn == "Y") { 
                await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_002, ["품명"]); // "실적이 발생한 @은 삭제할 수 없습니다."						
            } else {
                scwin.fn_deleteGridRowByStatus(ds_commInfo, gr_commInfo, ds_commInfo.getRowPosition());
            }
		}	
	}
};

// 품명목록 행취소
scwin.f_undoRow1 = function () {
	var commInfoRows = ds_commInfo.getRowCount();	
	var cntrInfoRows = ds_cntrInfo.getRowCount();
	scwin.btnPos = "U1";

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반인 경우 : FullEmpty구분할필요없음
        if (commInfoRows > 0) {
            var sameYn = "N";
            ds_commInfo.undoRow(ds_commInfo.getRowPosition());			
            for (var i = 0; i < cntrInfoRows; i++) {
                if (ds_cntrInfo.getCellData(i, "cntrSizCd") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrSizCd")
                    && ds_cntrInfo.getCellData(i, "cntrTypCd") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrTypCd")
                    && ds_cntrInfo.getCellData(i, "wt") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "grossWt")
                    && ds_cntrInfo.getCellData(i, "temper") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "temper")
                    && ds_cntrInfo.getCellData(i, "dryYn") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "dryYn")
                ) {	       				
                    //ds_cntrInfo.undoRow(i);
                    scwin.f_undoRow(ds_cntrInfo, gr_cntrInfo, i);
                    sameYn = "Y";       				
                }
            }
            if (sameYn == "Y")
                scwin.f_calInputQty();
        }	    
	} else {
        if (commInfoRows > 0) {
            var sameYn = "N";
            ds_commInfo.undoRow(ds_commInfo.getRowPosition());			
            for (var i = 0; i < cntrInfoRows; i++) {
                if (ds_cntrInfo.getCellData(i, "cntrSizCd") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrSizCd")
                    && ds_cntrInfo.getCellData(i, "cntrTypCd") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "cntrTypCd")
                    && ds_cntrInfo.getCellData(i, "fullEmptyClsCd") == ds_commInfo.getCellData(ds_commInfo.getRowPosition(), "fullEmptyClsCd")) {

                    //ds_cntrInfo.undoRow(i);
                    scwin.f_undoRow(ds_cntrInfo, gr_cntrInfo, i);
                    sameYn = "Y";       				
                }
            }
            if (sameYn == "Y")
                scwin.f_calInputQty();
        }
	}
};

// 컨테이너목록 행추가
scwin.f_addRow2 = async function () {
    var commRows = ds_commInfo.getRowCount();
    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR		                    // 수입본선컨테이너오더    
        || (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "1")	// 부두간TS
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR			                // 하선지경유TS(부두-->CY)
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR 		                // 수입일반
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 	                // CFS셔틀
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR	                // 세관검사
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR			                    // 검색기
    ) {
        var rowIndex = ds_cntrInfo.insertRow();
        gr_cntrInfo.setFocusedCell(rowIndex, 0);
        ds_cntrInfo.setRowPosition(rowIndex);
        ds_cntrInfo.setCellData(rowIndex, "Currow", rowIndex+1);
        ds_cntrInfo.setCellData(rowIndex, "wrkStDt", ed_wrkStDt.getValue().trim());
        ds_cntrInfo.setCellData(rowIndex, "wrkStHh", ed_wrkStHh.getValue().trim());
        ds_cntrInfo.setCellData(rowIndex, "wrkEndDt", ed_wrkEndDt.getValue().trim());
        ds_cntrInfo.setCellData(rowIndex, "wrkEndHh", ed_wrkEndHh.getValue().trim());
    } else {
        // 컨테이너목록 rowCount와 품명목록 rowCount가 같은 경우에는 더이상 행추가하지 않게 함
        var commRowsExceptDel = 0;
        var cntrRowsExceptDel = dscommon.cf_CountRowExceptDeleteRow(ds_cntrInfo);

        // 품명목록에서 총수량
        for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
            // 행추가 또는 행수정만 Count
            if (ds_commInfo.getRowStatus(i) != "D") {
                commRowsExceptDel = commRowsExceptDel + Number(ds_commInfo.getCellData(i, "qty"));
            }
        }				

        if (commRowsExceptDel == cntrRowsExceptDel) {
            await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_005); // 컨테이너는 품명목록의 총수량 이상 입력할 수 없습니다"
            return;
        }

        // 행추가
        if (commRows > 0) {
            var chkFlag = false; //delete 체크 flag

            for (var i = 0; i < commRows; i++) {
                if (ds_commInfo.getRowStatus(i) != "D")
                    chkFlag = true;
            }

            // 행추가
            if (chkFlag == true) {
                var rowIndex = ds_cntrInfo.insertRow();
                ds_cntrInfo.setRowPosition(rowIndex);
                ds_cntrInfo.setCellData(rowIndex, "odrNo", ds_odrInfo.getCellData(0, "odrNo"));
                ds_cntrInfo.setCellData(rowIndex, "Currow", rowIndex+1);
                if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR		// 수출일반인 경우
                    || (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "2")	
                    || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR		    // On-hire
                    || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR		// Off-hire 
                    || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR	// Empty Position	
                ) { 		
                    if (commRows > 0) {

                        ds_cntrInfo.setCellData(rowIndex, "wrkStDt", ds_commInfo.getCellData(commRows, "wrkStDt"));
                        ds_cntrInfo.setCellData(rowIndex, "wrkStHh", ds_commInfo.getCellData(commRows, "wrkStHh"));
                        ds_cntrInfo.setCellData(rowIndex, "wrkEndDt", ds_commInfo.getCellData(commRows, "wrkEndDt"));
                        ds_cntrInfo.setCellData(rowIndex, "wrkEndHh", ds_commInfo.getCellData(commRows, "wrkEndHh"));
                        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "2") {
                            ds_cntrInfo.setCellData(rowIndex, "dptWrkPlCd", ds_cntrInfo.getCellData(0, "dptWrkPlCd"));
                            ds_cntrInfo.setCellData(rowIndex, "destPortCd", ds_cntrInfo.getCellData(0, "destPortCd"));
                            ds_cntrInfo.setCellData(rowIndex, "portCd", ds_cntrInfo.getCellData(0, "portCd"));
                        }
                    } else {
                        ds_cntrInfo.setCellData(rowIndex, "wrkStDt", ed_wrkStDt.getValue().trim());
                        ds_cntrInfo.setCellData(rowIndex, "wrkStHh", ed_wrkStHh.getValue().trim());
                        ds_cntrInfo.setCellData(rowIndex, "wrkEndDt", ed_wrkEndDt.getValue().trim());
                        ds_cntrInfo.setCellData(rowIndex, "wrkEndHh", ed_wrkEndHh.getValue().trim());
                    }

                    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR) { // OFF-HIRE인 경우				
                        ds_cntrInfo.setCellData(rowIndex, "fullEmptyClsCd", "E");

                    } else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { //수출일반인 경우	
                        ds_cntrInfo.setCellData(rowIndex, "fullEmptyClsCd", "F");
                        ds_cntrInfo.setCellData(rowIndex, "cntrWtCondCd", lc_cntrWtCondCd.getValue());
                    }
                } else {
                    ds_cntrInfo.setCellData(rowIndex, "wrkStDt", ed_wrkStDt.getValue().trim());
                    ds_cntrInfo.setCellData(rowIndex, "wrkStHh", ed_wrkStHh.getValue().trim());
                    ds_cntrInfo.setCellData(rowIndex, "wrkEndDt", ed_wrkEndDt.getValue().trim());
                    ds_cntrInfo.setCellData(rowIndex, "wrkEndHh", ed_wrkEndHh.getValue().trim());	

                    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) { //수입일반인 경우				
                        ds_cntrInfo.setCellData(rowIndex, "cntrWtCondCd", lc_cntrWtCondCd.getValue());
                    }					
                }
            }
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["품명정보가 없으므로 본 컨테이너정보","추가"]); // "@은(는) @할 수 없습니다.";
        }
    }
};

// 컨테이너목록 행삭제
scwin.f_deleteRow2 = async function () {
    var commInfoRows = ds_commInfo.getRowCount();
	var cntrInfoRows = ds_cntrInfo.getRowCount();
	scwin.btnPos = "D2";

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	// 수입본선컨테이너오더    
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR			// 부두간TS
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR	// 하선지경유TS(부두-->CY)
	) {
        if (cntrInfoRows > 0) {
            var cntrNo = ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "cntrNo");

            // 실적체크
            if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "wrkRsltsNo"))) {
                await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_002, ["컨테이너"]); //"실적이 발생한 컨테이너는 삭제할 수 없습니다."	
                return;
            }

            if (cntrNo != "") {
                // 수입본선,부두간TS,하선지경유TS(부두-->CY)인 경우, 행삭제 클릭시 실행
                // 컨테이너번호를 삭제하는 경우 해당 컨테이너의 BL번호에 속해 있는 모든 컨테이너를 동시에 삭제하도록한다. BL기준 삭제됨
                scwin.f_retrieveBlAndCntrForCvssl(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "cntrNo"));
            } else {
                scwin.fn_deleteGridRowByStatus(ds_cntrInfo, gr_cntrInfo, ds_cntrInfo.getRowPosition());
                scwin.f_calInputQty();
            }
        }
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반인 경우 : FullEmpty구분할필요없음
        var arrCntrNo = new Array();
        var idx		  = 0;
        var alertStr  = "";

        if (cntrInfoRows > 0) {
            for (var i = cntrInfoRows - 1; i >= 0; i--) {
                var status = ds_cntrInfo.getRowStatusValue(i);
                if (status == "2" || status == "1") {
                //if (ds_cntrInfo.getRowStatusValue(i) == 1) {
                    if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { // 실적일어나지 않은 경우만 해당
                        // ds_cntrInfo.DeleteRow(i); (확인할것)
                        ds_cntrInfo.removeRow(i);
                    } else {
                        arrCntrNo[idx] = ds_cntrInfo.getCellData(i, "cntrNo");
                        idx = idx + 1;
                    }
                }
            }

            if (arrCntrNo.length > 0) {
                for (var i in arrCntrNo) {
                    if (!$c.gus.cfIsNull(arrCntrNo[i])) {
                        if (i == 0) {
                            alertStr = alertStr + "<br>[컨테이너번호]<br>";
                            alertStr = alertStr + arrCntrNo[i];
                        } else {
                            alertStr = alertStr + "," + arrCntrNo[i];
                        }
                    }
                }

                alertStr = "현재 선택한 컨테이너 중에서 <br>"
                            + alertStr 
                            + "<br><br>총 " 
                            + arrCntrNo.length + " 건의 컨테이너는 실적이 일어난 건이므로 삭제할 수 없습니다.";

                await $c.gus.cfAlertMsg(alertStr);
            }			
            scwin.f_calInputQty();
        }
	} else {
        var arrCntrNo = new Array();
        var idx		  = 0;
        var alertStr  = "";

        if (cntrInfoRows > 0) {
            for (var i = cntrInfoRows - 1; i >= 0; i--) {
                var status = ds_cntrInfo.getRowStatusValue(i);
                if (status == "2" || status == "1") {
                    if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { // 실적일어나지 않은 경우만 해당
                        // ds_cntrInfo.DeleteRow(i); (확인할것)
                        ds_cntrInfo.removeRow(i);
                    } else {
                        arrCntrNo[idx] = ds_cntrInfo.getCellData(i, "cntrNo");
                        idx = idx + 1;
                    }
                }
            }

            if (arrCntrNo.length > 0) {
                for (var i in arrCntrNo) {
                    if (!$c.gus.cfIsNull(arrCntrNo[i])) {
                        if (i == 0) {
                            alertStr = alertStr + "<br>[컨테이너번호]<br>";
                            alertStr = alertStr + arrCntrNo[i];
                        } else {
                            alertStr = alertStr + "," + arrCntrNo[i];
                        }
                    }
                }

                alertStr = "현재 선택한 컨테이너 중에서 <br>"
                            + alertStr 
                            + "<br><br>총 " 
                            + arrCntrNo.length + " 건의 컨테이너는 실적이 일어난 건이므로 삭제할 수 없습니다.";

                await $c.gus.cfAlertMsg(alertStr);
            }

            scwin.f_calInputQty();
        }
	}
};

// 컨테이너목록 행취소
scwin.f_undoRow2 = function () {debugger;
    var commInfoRows = ds_commInfo.getRowCount();	
	var cntrInfoRows = ds_cntrInfo.getRowCount();
	scwin.btnPos = "U2";

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR // 수입본선컨테이너오더    
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR			// 부두간TS
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR	// 하선지경유TS(부두-->CY)
	) {
        if (cntrInfoRows > 0) {
            if (ds_cntrInfo.getRowStatus(ds_cntrInfo.getRowPosition()) == "D") {
                // 수입본선,부두간TS,하선지경유TS(부두-->CY)인 경우, 행삭제 클릭시 실행
                // 컨테이너번호를 삭제하는 경우 해당 컨테이너의 BL번호에 속해 있는 모든 컨테이너를 동시에 삭제하도록한다. BL기준 삭제됨
                scwin.f_retrieveBlAndCntrForCvssl(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "cntrNo"));
            } else {
                scwin.f_undoRow(ds_cntrInfo, gr_cntrInfo, ds_cntrInfo.getRowPosition());
            }
        }
		scwin.f_calInputQty();
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반인 경우 : FullEmpty구분할필요없음
        for (var i = 0; i < cntrInfoRows; i++) {	
            if (ds_cntrInfo.getRowStatusValue(i) == 1) { // select된 row만 해당
                for (var j = 0; j < commInfoRows; j++) {
                    if (ds_cntrInfo.getCellData(i, "cntrSizCd") == ds_commInfo.getCellData(j, "cntrSizCd")
                        && ds_cntrInfo.getCellData(i, "cntrTypCd") == ds_commInfo.getCellData(j, "cntrTypCd")
                        && ds_cntrInfo.getCellData(i, "wt") == ds_commInfo.getCellData(j, "grossWt")
                        && ds_cntrInfo.getCellData(i, "temper") == ds_commInfo.getCellData(j, "temper")		
                        && ds_cntrInfo.getCellData(i, "dryYn") == ds_commInfo.getCellData(j, "dryYn")	
                        && ds_commInfo.getRowStatus(j) == "D" 
                    ) {
                        scwin.f_undoRow(ds_commInfo, gr_commInfo, i);
                    }
                }
            }			
        }
        //ds_cntrInfo.UndoMarked();
        scwin.f_undoRow(ds_cntrInfo, gr_cntrInfo, ds_cntrInfo.getRowPosition());
        scwin.f_calInputQty();
	} else {
        for (var i = 0; i < cntrInfoRows; i++) {	
            if (ds_cntrInfo.getRowStatusValue(i) == 1) { // select된 row만 해당
                for (var j = 0; j < commInfoRows; j++) {
                    if (ds_cntrInfo.getCellData(i, "cntrSizCd") == ds_commInfo.getCellData(j, "cntrSizCd")
                        && ds_cntrInfo.getCellData(i, "cntrTypCd") == ds_commInfo.getCellData(j, "cntrTypCd")
                        && ds_cntrInfo.getCellData(i, "fullEmptyClsCd") == ds_commInfo.getCellData(j, "fullEmptyClsCd")
                        && ds_commInfo.getRowStatus(j) == "D") {
                        scwin.f_undoRow(ds_commInfo, gr_commInfo, j);
                    }
                }
            }			
        }
        //ds_cntrInfo.UndoMarked();
        scwin.f_undoRow(ds_cntrInfo, gr_cntrInfo, ds_cntrInfo.getRowPosition());
        scwin.f_calInputQty();
	}
};

// 유효성 확인
scwin.f_validate = async function () {
	var commInfoRows	= ds_commInfo.getRowCount();    // 품명목록 row수
	var cntrInfoRows	= ds_cntrInfo.getRowCount();    // 컨테이너목록 row수
	var commWrkDtHhShow	= "N"; 					        // 품명 출발/도착일시 show 여부
	var cntrWrkDtHhShow	= "N"; 					        // 컨테이너 출발/도착일시 show 여부	
	var odrLineCd		= ed_lineCd.getValue().trim();  // 오더정보의 Line코드

	// 품명목록 또는 컨테이너목록이 한건도 입력되지 않은 경우
	if (commInfoRows == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["품명목록"]); //@은(는) 필수 입력 항목입니다
		return false;
	}

	// 오더기본정보 - 계약거래처가 '공통거래처'인 경우, 청구거래처가 '공통거래처'가 오면 안됨
	if (lc_bilgClntNm.getText().substring(0, 5) == "공통거래처") {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["청구거래처", "공통거래처를 입력"]); //@은(는) @할 수 없습니다.
	}

	// 오더기본정보-출발일자, 도착일자 체크
	if (!scwin.f_chkDate(ed_wrkStDt.getValue(), ed_wrkEndDt.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_061, ["출발일자(입항일자)", "도착일자(출항일자) 이전"]); //"@은(는) @이어야 합니다."		
		ed_wrkStDt.focus();
		return false;
	}

	if (!scwin.f_chkTime(ed_wrkStDt.getValue(), ed_wrkStHh.getValue(), ed_wrkEndDt.getValue(), ed_wrkEndHh.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_061, ["출발시간(입항시간)", "도착시간(출항시간) 이전"]); //"@은(는) @이어야 합니다."		
		ed_wrkStDt.focus();	
		return false;
	}

	// 상차,하차,오더 담당 전화번호 유효성 확인
	if (tr_picNmTelNo.getStyle("display") != "none") {
		if (ed_odrPicTelNo.getValue() != "") {
			if (!dscommon.cf_PhoneCheck(ed_odrPicTelNo))
                return false;
		}
	}

	// 품명정보-출발일자, 도착일자 체크
    if (gr_commInfo.getColumnVisible("wrkStDt") && gr_commInfo.getColumnVisible("wrkStHh") && 
        gr_commInfo.getColumnVisible("wrkEndDt") && gr_commInfo.getColumnVisible("wrkEndHh")) {

        commWrkDtHhShow = "Y";
    }

	// 컨테이너정보-출발일자, 도착일자 체크
    if (gr_cntrInfo.getColumnVisible("wrkStDt") && gr_cntrInfo.getColumnVisible("wrkStHh") && 
        gr_cntrInfo.getColumnVisible("wrkEndDt") && gr_cntrInfo.getColumnVisible("wrkEndHh")) {

        cntrWrkDtHhShow = "Y";
    }

	// 품명정보 validation체크
	for (var i = 0; i < commInfoRows; i++) {
		if (ds_commInfo.getRowStatus(i) != "D") { //삭제건이 아닌 경우 		

			// 수량체크
			if (Number(ds_commInfo.getCellData(i, "inputQty")) > Number(ds_commInfo.getCellData(i, "qty"))) {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_048.replace("%1", "%3").replace("%2", "%4"), ["품명목록", i+1, "입력수량 ", "수량"]); //@의 @번째 데이터에서 + @은(는) @보다 작아야 합니다.	
				return false;
			}

			// 중량체크 - C4인 경우 중량을 입력하도록 한다.
			if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) {
				if (ds_commInfo.getCellData(i, "grossWt") == 0) {
					await $c.gus.cfAlertMsg("품명목록의 중량을 입력하여 주세요.");
					return false;
				}
			}

			// 일시체크
			if (commWrkDtHhShow == "Y") {
				// 출발일시 입력하지 않은 경우, 오더정보의 출발일시로 대체
				if (ds_commInfo.getCellData(i, "wrkStDt") == "" || ds_commInfo.getCellData(i, "wrkStHh") == "") {
                    let msg  = $c.data.getMessage(MSG_CM_ERR_031 + "출발일자 또는 시간을 입력하지 않았습니다. 오더정보의 출발(입항)일시로 대체하시겠습니까?", ["품명목록", i]);
                    if (await $c.win.confirm(msg)) {
						ds_commInfo.setCellData(i, "wrkStDt", ed_wrkStDt.getValue().trim());
						ds_commInfo.setCellData(i, "wrkStHh", ed_wrkStHh.getValue().trim());
					} else {
						return false;
					}
				}

				// 도착일시 입력하지 않은 경우, 오더정보의 도착일시로 대체
				if (ds_commInfo.getCellData(i, "wrkEndDt") == "" || ds_commInfo.getCellData(i, "wrkEndHh") == "") {
                    let msg  = $c.data.getMessage(MSG_CM_ERR_031 + "도착일자 또는 시간을 입력하지 않았습니다. 오더정보의 도착(출항)일시로 대체하시겠습니까?", ["품명목록", i]);
                    if (await $c.win.confirm(msg)) {
						ds_commInfo.setCellData(i, "wrkEndDt", ed_wrkStDt.getValue().trim());
						ds_commInfo.setCellData(i, "wrkEndHh", ed_wrkStHh.getValue().trim());
					} else {
						return false;
					}
				}

				// 품명목록의 출발일자와 도착일자 비교
				if (!scwin.f_chkDate(ds_commInfo.getCellData(i,"wrkStDt"), ds_commInfo.getCellData(i,"wrkEndDt"))) {
					if (await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_061.replace("%1", "%3").replace("%2", "%4"), ["품명목록", i+1, "출발일자", "도착일자 이전"])) { //"@의 @번째 데이터에서"+"@은(는) @이어야 합니다."	
                        ds_commInfo.setRowPosition(i);
                        return false;
                    } 
				}

				// 품명목록의 출발시간와 도착시간 비교
				if (!scwin.f_chkTime(ds_commInfo.getCellData(i,"wrkStDt"), ds_commInfo.getCellData(i,"wrkStHh"), 
							   ds_commInfo.getCellData(i,"wrkEndDt"), ds_commInfo.getCellData(i,"wrkEndHh"))) {
					if (await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_061.replace("%1", "%3").replace("%2", "%4"), ["품명목록", i+1, "출발시간", "도착시간 이전"])) { //"@의 @번째 데이터에서"+"@은(는) @이어야 합니다."	
                        ds_commInfo.setRowPosition(i);
                        return false;
                    } 
				}
			}
		}

        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR 
           && (ed_lineCd.getValue() == "EVER" || ed_lineCd.getValue() == "LTXX" ||ed_lineCd.getValue() == "HTML" || ed_lineCd.getValue() == "ITS")      
        ) {	
			for (var j = 0; j < ds_bkCommInfo.getRowCount(); j++) {
			   if (ds_commInfo.getCellData(i, "cntrSizCd") == ds_bkCommInfo.getCellData(i, "cntrSizCd") && ds_commInfo.getCellData(i, "cntrTypCd") == ds_bkCommInfo.getCellData(i, "cntrTypCd")) {
                    if (ds_commInfo.getCellData(i, "qty") > ds_bkCommInfo.getCellData(i, "qty")) {
                        if (await $c.win.confirm("Booking 수량보다도 입력수량이 큽니다. 그래도 저장하겠습니까")) { // 저장하시겠습니까?

                        } else {
                            return false;
                        }
                    }
                }
			}
		}
	}

	// 컨테이너정보 - 수입본선,수입/수출하역, 부두간TS, 하선지경유TS가 아닌 경우
	if (gr_commInfo.getColumnVisible("cntrTypCd") && gr_commInfo.getColumnVisible("inputQty")) { // 수입/수출하역이 아닌 경우
		// 컨테이너정보 validation체크
		for (var i = 0; i < cntrInfoRows; i++) {	
			if (ds_cntrInfo.getRowStatus(i) != "D" && $c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { // 삭제건이 아니고, 실적이 일어난 경우가 아닌 경우만 해당
				//라인코드 체크 - 검색기 오더는 제외
				if (scwin.odrKndCd != DsConstants.ODR_KND_CD_EXAMINE_ODR //검색기
				    && scwin.odrKndCd != DsConstants.ODR_KND_CD_TS_ODR
					&& !$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "cntrNo")) 
					&& odrLineCd != ds_cntrInfo.getCellData(i, "lineCd")
				) {
					await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_061.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", i+1, "Line코드", "오더정보와 같은 Line코드"]); //"@의 @번째 데이터에서"+"@은(는) @이어야 합니다."	
					return false;
				}

				// 컨테이너 type이 RF/RH인 경우, 온도 또는 dry 체크
				var cntrType = ds_cntrInfo.getCellData(i, "cntrTypCd").trim();
				var temper   = ds_cntrInfo.getCellData(i, "temper").trim();
				var dryYn    = ds_cntrInfo.getCellData(i, "dryYn");

				if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "cntrNo")) && (cntrType == DsConstants.CNTR_TYP_CD_RF || cntrType == DsConstants.CNTR_TYP_CD_RH)) {
					//온도 또는 dry 중 하나라도 입력했는지 체크					
					if ($c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_NO) {
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", i+1, "TYPE이 RF/RH인 경우, 온도 또는 DRY"]); //@의 @번째 데이터에서 @은(는) 필수 입력 항목입니다.
						return false;						
					}

					//온도 또는 dry 모두 입력했는지 체크					
					if (!$c.gus.cfIsNull(temper) && dryYn == DsConstants.YN_YES) {
						await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_041.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", i+1, "TYPE이 RF/RH인 경우, 온도와 DRY 모두 입력"]); //@의 @번째 데이터에서 @은(는) @할 수 없습니다.
						return false;						
					}
				}

				// 컨테이너정보-출발일자, 도착일자 체크
				if (cntrWrkDtHhShow == "Y") {
					// 출발일시 입력하지 않은 경우, 오더정보의 출발일시로 대체
					if (ds_cntrInfo.getCellData(i, "wrkStDt") == "" || ds_cntrInfo.getCellData(i, "wrkStHh") == "") {
                        let msg  = $c.data.getMessage(MSG_CM_ERR_031 + "출발일자 또는 시간을 입력하지 않았습니다. 오더정보의 출발(입항)일시로 대체하시겠습니까?", ["컨테이너목록",i]);
                        if (await $c.win.confirm(msg)) {
							ds_cntrInfo.setCellData(i, "wrkStDt", ed_wrkStDt.getValue().trim());
							ds_cntrInfo.setCellData(i, "wrkStHh", ed_wrkStHh.getValue().trim());
						} else {
							return false;
						}
					}

					// 도착일시 입력하지 않은 경우, 오더정보의 도착일시로 대체
					if (ds_cntrInfo.getCellData(i,"wrkEndDt") == "" || ds_cntrInfo.getCellData(i,"wrkEndHh") == "") {
                        let msg  = $c.data.getMessage(MSG_CM_ERR_031 + "도착일자 또는 시간을 입력하지 않았습니다. 오더정보의 도착(출항)일시로 대체하시겠습니까?", ["컨테이너목록",i]);
                        if (await $c.win.confirm(msg)) {
							ds_cntrInfo.setCellData(i, "wrkEndDt", ed_wrkStDt.getValue().trim());
							ds_cntrInfo.setCellData(i, "wrkEndHh", ed_wrkStHh.getValue().trim());
						} else {
							return false;
						}
					}

					// 컨테이너목록의 출발일자와 도착일자 비교
					if (!scwin.f_chkDate(ds_cntrInfo.getCellData(i,"wrkStDt"), ds_cntrInfo.getCellData(i,"wrkEndDt"))) {
						if (await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_061.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", i+1, "출발일자", "도착일자 이전"])) { //"@의 @번째 데이터에서"+"@은(는) @이어야 합니다."		
                            ds_cntrInfo.setRowPosition(i);
                            return false;
                        } 
					}

					// 컨테이너목록의 출발일자와 도착일자 비교
					if (!scwin.f_chkTime(ds_cntrInfo.getCellData(i,"wrkStDt"), ds_cntrInfo.getCellData(i,"wrkStHh"), ds_cntrInfo.getCellData(i,"wrkEndDt"), ds_cntrInfo.getCellData(i,"wrkEndHh"))) {
						if (await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_061.replace("%1", "%3").replace("%2", "%4"), ["컨테이너목록", i+1, "출발시간", "도착시간 이전"])) { //"@의 @번째 데이터에서"+"@은(는) @이어야 합니다."		
                            ds_cntrInfo.setRowPosition(i);
                            return false;
                        } 
					}

					// 오더별 체크사항
					if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) { //수출본선

					} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { //수출일반
						if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) { //자가영업인 경우
							if (ds_cntrInfo.getCellData(i, "currPosCd") == "" && ds_cntrInfo.getCellData(i, "cntrNo") != "") {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_002.replace("%1", "%3"), ["컨테이너목록", i+1, "현위치"]); //@의 @번째 데이터에서  @은(는) 필수 입력 항목입니다.
								return false;		
							}					
						} else { //자가영업이 아닌 경우							
							if (ds_cntrInfo.getCellData(i, "arrvlportDtm") == "" && ds_cntrInfo.getCellData(i, "cntrNo") != "") {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_053.replace("%1", "%3"), ["컨테이너목록", i+1, "입항일시"]); //"@의 @번째 데이터에서"+"@이(가) 누락되었습니다."	
								return false;
							}
						}		

					} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) {//EMPTY POSITION
						if (scwin.selfClsCd != DsConstants.SELF_CLS_CD_SELF_SALES) { //자가영업이 아닌 경우
							if (ds_cntrInfo.getCellData(i, "arrvlportDtm") == "" && ds_cntrInfo.getCellData(i, "cntrNo") != "") {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_053.replace("%1", "%3"), ["컨테이너목록", i+1, "입항일시"]); //"@의 @번째 데이터에서"+"@이(가) 누락되었습니다."	
								return false;
							}
						}
					}
				}
			}
		}
	}

	return true;
};

// 시작일자, 종료일자 유효성 체크
scwin.f_chkDate = async function(strDate, endDate) {
    var differDays = $c.date.diffDate(strDate, endDate); 
    if (differDays >= 0) {
        return true;
    } else {
        return false;
    }
};

// 시작시간, 종료시간 유효성 체크
scwin.f_chkTime = async function(strDate, strTime, endDate, endTime) {
    var differTime = Number(endDate + endTime.replaceAll(":", "")) - Number(strDate + strTime.replaceAll(":", ""));
    if (differTime >= 0) {
        return true;    
    } else {
        return false;
    }
};

scwin.f_setInterfaceFromLinkPage = async function() {
	var linkOdrKndCd = $p.parent().scwin.hid_odrKndCd; // 링크오더종류
	var linkPage	 = $p.parent().scwin.hid_linkPage; // 링크 페이지명

	if (!$c.gus.cfIsNull(linkOdrKndCd)) {
		if (linkPage == "bookingNo") { //booking페이지에서 넘어온 경우
		    if (linkOdrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR 	 // 수출일반
		    	|| linkOdrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR	     // on-hire
			    || linkOdrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR	     // off-hire
			    || linkOdrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR // empty position
		    ) {
	        	// bookingNo정보 관련 전역변수 세팅
				scwin.orgLineCd	 = $p.parent().scwin.hid_lineCd.trim();	        	
				scwin.orgBookingNo = $p.parent().scwin.hid_bookingNo.trim();

				ed_lineCd.setValue(scwin.orgLineCd);
				ed_bookingNo.setValue(scwin.orgBookingNo);

				// 출발일시, 도착일시 세팅
				ed_wrkStDt.setValue($p.parent().scwin.hid_pickupdt.trim());
				ed_wrkStHh.setValue($p.parent().scwin.hid_pickuphh.trim());
				ed_wrkEndDt.setValue($p.parent().scwin.hid_pickupdt.trim());

				// Line명과 선사거래처 가져오기
				scwin.f_openCommonPopUp(3, '', 'T', 'F', 'T');

				// booking정보 조회
				scwin.f_retrieveBookingInfo("NEW");
		    } 
		} else if (linkPage == "manifest") { // 적하목록페이지에서 넘어온 경우	
		    if (linkOdrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR 	// 수입본선
			    || linkOdrKndCd == DsConstants.ODR_KND_CD_TS_ODR	    	// 부두간TS
			    || linkOdrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR 	// 수입TS
		    ) { 
				ed_lineCd.setValue($p.parent().scwin.hid_lineCd.trim());

				// Line명과 선사거래처 가져오기				
			    scwin.f_openCommonPopUp( 3, '', 'T', 'F', 'T');	 

                ed_cvsslMgntNo.setValue($p.parent().scwin.hid_cvsslMgntNo.trim());
                acb_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS); // 자가구분코드 : 당사운송(LI)
				scwin.f_openCommonPopUp(4, '','T','F','F');
		    } else if (linkOdrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) { // 수입일반
                ed_lineCd.setValue($p.parent().scwin.hid_lineCd.trim());
                ed_cvsslMgntNo.setValue($p.parent().scwin.hid_cvsslMgntNo.trim());
                ed_blNo.setValue($p.parent().scwin.hid_blNo.trim());

                lc_mcomAssgnClsCd.setValue($p.parent().scwin.hid_mcomAssgnClsCd.trim());
                acb_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS); // 자가구분코드 : 당사운송(LI)
			    scwin.f_openCommonPopUp(7, '', 'T', 'F','F');
		    }
		}
	}
};

// 수출일반, On-Hire, Off-Hire, Empty Position오더에만 해당 
//  * BookingNo입력후, killFocus이벤트 발생시 실행 : booking정보 및 booking품명목록 가져오기
//  * gubun : OLD - 원래 BOOKINGNO를 삭제하기 위한 트랜잭션 세팅, 
//  *         NEW - 새로 입력한 BOOKINGNO를 삭제하기 위한 트랜잭션 세팅
scwin.f_retrieveBookingInfo = async function (gubun) {
    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR		 	// 수출일반
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR	     	    // on-hire
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR	     	// off-hire
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR		// empty position
	) {
		// 라인코드 체크
		if ($c.gus.cfIsNull(ed_lineCd.getValue())) {
	   		await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["라인코드"]); //@을(를) 입력하십시오
	   		return;
	    }		

		// 검색조건값 세팅          
		if (ds_cndBkInfo.getRowCount() > 0)	
            ds_cndBkInfo.removeAll();

        ds_cndBkInfo.insertRow();

		if (gubun == "OLD") {
			// 라인코드를 변경한 경우
			if (scwin.orgLineCd != ed_lineCd.getValue().trim()) {
				ds_cndBkInfo.setCellData(0, "lineCd", scwin.orgLineCd);
				ds_cndBkInfo.setCellData(0, "bookingNo", ed_bookingNo.getValue().trim());
			}

			// BookingNo를 변경한 경우
			if (scwin.orgBookingNo != ed_bookingNo.getValue().trim()) {
				ds_cndBkInfo.setCellData(0, "lineCd", ed_lineCd.getValue().trim());
				ds_cndBkInfo.setCellData(0, "bookingNo", scwin.orgBookingNo);
			}			

            let e = await $c.sbm.execute(sbm_retrieveBookingInfoOrg);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_retrieveBookingInfoOrg_submitdone(e);
            }
		} else if (gubun == "NEW") {
			ds_cndBkInfo.setCellData(0, "lineCd", ed_lineCd.getValue().trim());
			ds_cndBkInfo.setCellData(0, "bookingNo", ed_bookingNo.getValue().trim());

            let e = await $c.sbm.execute(sbm_retrieveBookingInfo);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_retrieveBookingInfo_submitdone(e);
            }
		}
	}
};

// 컨테이너목록 그리드에서 컨테이너번호 입력시 컨테이너 기본정보 조회
// 수입본선,수입하역,부두간TS,하선지경유TS오더인 경우 : 입력한 컨테이너에 해당하는 BL정보와 BL정보에 해당되는 컨테이너 모두 가져옴
scwin.f_retrieveCntrBasisInfo = async function (cntrNo) {
    let submissionObj = {};
    submissionObj.id = "sbm_retrieveCntrBasisInfo";
    submissionObj.method = "post";
    submissionObj.mediatype = "application/json";
    submissionObj.encoding = "UTF-8";
    submissionObj.submitDoneHandler = async function (e) {
        scwin.sbm_retrieveCntrBasisInfo_submitdone(e);
    }
    submissionObj.submitErrorHandler = async function (e) {
        scwin.sbm_retrieveCntrBasisInfo_submiterror(e);
    }

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR					        // 수입본선
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR					    // 수입하역
		|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "1")	// 부두간TS
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR						    // 하선지경유TS(부두-->CY)
	) {
        var mrn = "";       	

        if ($c.gus.cfIsNull(ed_cvsslMgntNo.getValue().trim())) {
            if (await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["본선관리번호"])) { // @을(를) 입력하십시오
                ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(), "cntrNo", "");
                return;
            } 
        }

        // 부두간TS인 경우, 도착지 체크
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) { // 부두간TS
            //본선관리번호 입력 여부 체크
            if ($c.gus.cfIsNull(ed_cvsslMgntNo.getValue().trim())) {
                if (await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["본선관리번호"])) { // @을(를) 입력하십시오
                    scwin.f_clearDataByCvsslMgntNo(); //본선관리번호와 관련한 데이터셋 Clear
                    return;
                }
            }
            // TS본선관리번호 입력 여부 체크 
            if ($c.gus.cfIsNull(ed_tsCvsslMgntNo.getValue().trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["TS본선관리번호"]); // @을(를) 입력하십시오
                return;
            }
            // 도착지 입력 여부 체크 
            if ($c.gus.cfIsNull(ed_arvWrkPlCd.getValue().trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["도착지"]); // @을(를) 입력하십시오
                return;
            }
        } 

        // 검색조건 데이터셋 세팅
        if (ds_cndCvsslMgntNo.getRowCount() > 0) 
            ds_cndCvsslMgntNo.removeAll();

        var rowIndex = ds_cndCvsslMgntNo.insertRow();
        ds_cndCvsslMgntNo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
        ds_cndCvsslMgntNo.setCellData(rowIndex, "cvsslMgntNo", ed_cvsslMgntNo.getValue().trim());
        ds_cndCvsslMgntNo.setCellData(rowIndex, "impExpClsCd", "I");
        ds_cndCvsslMgntNo.setCellData(rowIndex, "mcomLineCd", ed_lineCd.getValue().trim());
        ds_cndCvsslMgntNo.setCellData(rowIndex, "arvWrkPlCd", "");

        // ts여부 세팅
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR				// 부두간TS
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR   // 하선지경유TS(부두-->CY)
        ) { 
            ds_cndCvsslMgntNo.setCellData(0, "tsYn", "1");

            // 검색조건 데이터셋에 도착지 세팅
            if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) { // 부두간TS  
                ds_cndCvsslMgntNo.setCellData(0, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim()); 
            }
        } else {
            ds_cndCvsslMgntNo.setCellData(0, "tsYn", "0");
        } 

        // bl정보에서 mrn값 가져오기
        if (ds_blInfo.getRowCount() > 0) {
            mrn = ds_blInfo.getCellData(0, "mrn");
        }

        submissionObj.ref = 'data:json,[{"id":"ds_cndCvsslMgntNo","key":"IN_DS1"},{"id":"ds_cntrBasisInfo","key":"OUT_DS1"},{"id":"ds_cntrBasisBlInfo","key":"OUT_DS2"}]';
        submissionObj.target = 'data:json,[{"id":"ds_cntrBasisInfo","key":"OUT_DS1"},{"id":"ds_cntrBasisBlInfo","key":"OUT_DS2"}]';
        submissionObj.action = "/ds.sd.odrmgnt.odrreg.RetrieveManifestBillOfLadingContainerCMD.do?containerNumber=" + cntrNo + "&mrn=" + mrn;
        $c.sbm.executeDynamic(submissionObj);
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR) { // 수출본선컨테이너오더, 수출TS컨테이너오더
        // 현위치 세팅 로직 추가
        submissionObj.ref = 'data:json,[{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
        submissionObj.target = 'data:json,[{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
        submissionObj.action = "/ds.sd.odrmgnt.odrreg.RetrieveExportCarryingVesselContainerCMD.do?containerNumber=" + cntrNo;
        $c.sbm.executeDynamic(submissionObj);
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR 	 			// 수입일반컨테이너인 경우
				|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 		// CFS셔틀
				|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR 	 	// 세관검사
				|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR 	 			// 검색기
	) {
        if ($c.gus.cfIsNull(ed_lineCd.getValue().trim())) {
            if (await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["라인코드"])) { // @을(를) 입력하십시오
                scwin.f_setCntrInfo(2);
                return;
            }; 
        }

        if (ds_condCntrBasisInfo.getRowCount() > 0)
            ds_condCntrBasisInfo.removeAll();

        var rowIndex = ds_condCntrBasisInfo.insertRow();
        ds_condCntrBasisInfo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
        ds_condCntrBasisInfo.setCellData(rowIndex, "selfClsCd", scwin.selfClsCd);
        ds_condCntrBasisInfo.setCellData(rowIndex, "cntrNo", cntrNo);
        ds_condCntrBasisInfo.setCellData(rowIndex, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
        ds_condCntrBasisInfo.setCellData(rowIndex, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

        submissionObj.ref = 'data:json,[{"id":"ds_condCntrBasisInfo","key":"IN_DS1"},{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
        submissionObj.target = 'data:json,[{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
        submissionObj.action = "/ds.sd.odrmgnt.odrreg.RetrieveContainerCMD.do";
        $c.sbm.executeDynamic(submissionObj);
	} else { // 일반컨테이너오더 및 셔틀컨테이너         
        if (scwin.cntrLoadGubun != "Y") {
            if (ds_condCntrBasisInfo.getRowCount() > 0) 
                ds_condCntrBasisInfo.removeAll();

            var rowIndex = ds_condCntrBasisInfo.insertRow(rowIndex)();
            ds_condCntrBasisInfo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
            ds_condCntrBasisInfo.setCellData(rowIndex1, "selfClsCd", scwin.selfClsCd);
            ds_condCntrBasisInfo.setCellData(rowIndex, "cntrNo", cntrNo);
            ds_condCntrBasisInfo.setCellData(rowIndex, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
            ds_condCntrBasisInfo.setCellData(rowIndex, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

            submissionObj.ref = 'data:json,[{"id":"ds_condCntrBasisInfo","key":"IN_DS1"},{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
            submissionObj.target = 'data:json,[{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
            submissionObj.action = "/ds.sd.odrmgnt.odrreg.RetrieveContainerCMD.do";
            $c.sbm.executeDynamic(submissionObj);
        } else {
            if (ds_condCntrBasisInfo.getRowCount > 0) 
                ds_condCntrBasisInfo.removeAll();

            var rowIndex = ds_condCntrBasisInfo.insertRow();
            ds_condCntrBasisInfo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
            ds_condCntrBasisInfo.setCellData(rowIndex, "selfClsCd", scwin.selfClsCd);
            ds_condCntrBasisInfo.setCellData(rowIndex, "cntrNo", cntrNo);
            ds_condCntrBasisInfo.setCellData(rowIndex, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
            ds_condCntrBasisInfo.setCellData(rowIndex, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

            submissionObj.ref = 'data:json,[{"id":"ds_condCntrBasisInfo","key":"IN_DS1"},{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
            submissionObj.target = 'data:json,[{"id":"ds_cntrBasisInfo","key":"OUT_DS1"}]';
            submissionObj.action = "/ds.sd.odrmgnt.odrreg.RetrieveContainerCMD.do";
            $c.sbm.executeDynamic(submissionObj);
        }
	}		
};

// BL번호에 따른 품명,컨테이너조회
// 수입일반, CFS셔틀, 세관검사, 검색기인 경우
scwin.f_retrieveBillOfLadingContainerList = async function () { 	
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR 			// 수입일반
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 	// CFS셔틀
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR 	// 세관검사
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR 	 		// 검색기
	) {	
		// 라인코드 체크
		if ($c.gus.cfIsNull(ed_lineCd.getValue().trim())) {
       		if (await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["라인코드"])) { //@을(를) 입력하십시오
                scwin.f_clearDataByBlNo(); // BL번호와 관련한 데이터셋 Clear
                return;
            } 
       	}

		scwin.retrieveYn = "Y";

		// 검색데이터셋 값세팅
	 	if (ds_cndBlNo.getRowCount() > 0)
            ds_cndBlNo.removeAll();

		var rowIndex = ds_cndBlNo.insertRow();
	    ds_cndBlNo.setCellData(rowIndex, "cvsslMgntNo", ed_cvsslMgntNo.getValue().trim());
	    ds_cndBlNo.setCellData(rowIndex, "impExpClsCd", "I");
	    ds_cndBlNo.setCellData(rowIndex, "mrn", ds_blInfo.getCellData(0, "mrn"));  
	    ds_cndBlNo.setCellData(rowIndex, "msn", ds_blInfo.getCellData(0, "msn"));  
	    ds_cndBlNo.setCellData(rowIndex, "hsn", ds_blInfo.getCellData(0, "hsn"));  
	    ds_cndBlNo.setCellData(rowIndex, "hblNo", ed_blNo.getValue().trim());
	    ds_cndBlNo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd); 
	    ds_cndBlNo.setCellData(rowIndex, "selfClsCd", scwin.selfClsCd); 

        let submissionObj = {};
        submissionObj.id = "sbm_retrieveBLContainer";
        submissionObj.method = "post";
        submissionObj.mediatype = "application/json";
        submissionObj.encoding = "UTF-8";
        submissionObj.submitDoneHandler = async function (e) {
            await scwin.sbm_retrieveBLContainer_submitdone(e);
        }
        submissionObj.submitErrorHandler = async function (e) {
            await scwin.sbm_retrieveBLContainer_submiterror(e);
        }

	    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) { // 수입일반(자가영업)인 경우
            submissionObj.ref = 'data:json,[{"id":"ds_cndBlNo","key":"IN_DS1"},{"id":"ds_outCommInfoByBlNo","key":"OUT_DS1"},{"id":"ds_outCntrInfoByCvsslMgntNo","key":"OUT_DS2"}]';
            submissionObj.target = 'data:json,[{"id":"ds_outCommInfoByBlNo","key":"OUT_DS1"},{"id":"ds_outCntrInfoByCvsslMgntNo","key":"OUT_DS2"}]';
	    } else {
            submissionObj.ref = 'data:json,[{"id":"ds_cndBlNo","key":"IN_DS1"},{"id":"ds_outCommInfoByBlNo","key":"OUT_DS1"},{"id":"ds_cntrInfo","key":"OUT_DS2"}]';
            submissionObj.target = 'data:json,[{"id":"ds_outCommInfoByBlNo","key":"OUT_DS1"},{"id":"ds_cntrInfo","key":"OUT_DS2"}]';
	    }

        submissionObj.action = "/ds.sd.odrmgnt.odrreg.RetrieveBillOfLadingContainerListCMD.do";
        $c.sbm.executeDynamic(submissionObj);
	}
};

// 본선관리번호에 해당하는 BL목록, 품명목록, 컨테이너목록 조회
// 수입본선,수입하역,부두간TS,하선지경유TS오더인 경우
scwin.f_retrieveManifestBLContainerList = async function() {
	// 수입본선컨테이너 또는 수입하역컨테이너인 경우
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	    // 수입본선
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR	// 수입하역
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR			    // 부두간TS
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR		// 하선지경유TS(부두-->CY)
	) { 
		// 라인코드 체크
		if ($c.gus.cfIsNull(ed_lineCd.getValue().trim())) {
       		if (await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["라인코드"])) { //@을(를) 입력하십시오
                scwin.f_clearDataByCvsslMgntNo(); //본선관리번호와 관련한 데이터셋 Clear
                return;
            } 
       	}

       	// 부두간TS인 경우, 도착지 체크
		if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) { //부두간TS
			//본선관리번호 입력 여부 체크
			if ($c.gus.cfIsNull(ed_cvsslMgntNo.getValue().trim())) {
	       		await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["본선관리번호"]); // @을(를) 입력하십시오
	       		return;
       		}
       		// TS본선관리번호 입력 여부 체크 
			if ($c.gus.cfIsNull(ed_tsCvsslMgntNo.getValue().trim())) {
	       		await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["TS본선관리번호"]); // @을(를) 입력하십시오
	       		return;
       		}
       		// 도착지 입력 여부 체크 
			if ($c.gus.cfIsNull(ed_arvWrkPlCd.getValue().trim())) {
	       		await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["도착지"]); // @을(를) 입력하십시오
	       		return;
       		}
       	}       	

		scwin.retrieveYn = "Y";

	    // 검색조건 데이터셋 세팅
	 	if (ds_cndCvsslMgntNo.getRowCount() > 0)
            ds_cndCvsslMgntNo.removeAll();

		var rowIndex = ds_cndCvsslMgntNo.insertRow();	   
	    ds_cndCvsslMgntNo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd); //오더종류 : 수입본선, 수입하역  구분하기 위함
	    ds_cndCvsslMgntNo.setCellData(rowIndex, "cvsslMgntNo", ed_cvsslMgntNo.getValue().trim());
	    ds_cndCvsslMgntNo.setCellData(rowIndex, "impExpClsCd", scwin.impExpClsCd);
		ds_cndCvsslMgntNo.setCellData(rowIndex, "mcomLineCd", ed_lineCd.getValue().trim()); 
		ds_cndCvsslMgntNo.setCellData(rowIndex, "arvWrkPlCd", "");

	    // ts여부 세팅
	    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR				// 부두간TS
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR	// 하선지경유TS(부두-->CY)
	    ) { 
	    	ds_cndCvsslMgntNo.setCellData(0, "tsYn", "1");

	    	// 검색조건 데이터셋에 도착지 세팅
	    	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) { // 부두간TS  
				ds_cndCvsslMgntNo.setCellData(0, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim()); 
	    	}
	    } else {
	    	ds_cndCvsslMgntNo.setCellData(0, "tsYn", "0");
	    } 

        let e = await $c.sbm.execute(sbm_retrieveManifestBLContainerList);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieveManifestBLContainerList_submitdone(e);
        } else if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
            scwin.sbm_retrieveManifestBLContainerList_submiterror(e);
        }
	}
};

// 본선관리번호팝업의 리턴값에서 오더종류별로 필요한 값 세팅
// param : rtnList - array(14)
// rtnList[0];  본선관리번호
// rtnList[1];  선박코드
// rtnList[2];  선박명
// rtnList[3];  마감일자
// rtnList[4];  마감시간
// rtnList[5];  도착(입항)일자
// rtnList[6];  도착(입항)시간
// rtnList[7];  출발(출항)일자
// rtnList[8];  출발(출항)시간
// rtnList[9];  선사항차
// rtnList[10]; 항로
// rtnList[11]; 항구코드
// rtnList[12]; 부두코드
// rtnList[13]; 부두코드명			
scwin.f_setCvsslMgntNoByOdrKndCd = async function(rtnList, gubun) {
	if (rtnList != null) {
		if (rtnList[0] != "N/A") {
			if (gubun == "") {
				if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	    // 수입본선
					|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR			    // 부두간TS
					|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR		// 하선지경유TS
				) {	
					if (rtnList[5] == "" || rtnList[6] == "") {	
						await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["본선스케줄에서 입항일시"]); //@을(를) 입력하십시오.
						return;
					}
				}

				ed_cvsslMgntNo.setValue(rtnList[0]);
				ed_vsslCd.setValue(rtnList[1]);                     // 선박코드
				ed_vsslNm.setValue(rtnList[2]);                     // 선박명
				ed_portcnt.setValue(rtnList[9]);                    // 선사항차
				ed_lane.setValue(rtnList[10]);                      // 항로
				ds_odrInfo.setCellData(0, "portCd", rtnList[11]);   // 항구코드	

				// 수입본선, 수입하역 : 부두코드를 출발지로 세팅, 도착(입항)일시,출발(출항)일시 세팅
				if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR			// 수입본선
					|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR		// 수입하역
				) { 
					ed_dptWrkPlCd.setValue(rtnList[12]);    // 부두코드
					ed_dptWrkPlNm.setValue(rtnList[13]);    // 부두코드명
					ed_wrkStDt.setValue(rtnList[5]);        // 도착(입항)일자
					ed_wrkStHh.setValue(rtnList[6]);        // 도착(입항)시간
					ed_wrkEndDt.setValue(rtnList[7]);       // 출발(출항)일자
					ed_wrkEndHh.setValue(rtnList[8]);       // 출발(출항)시간
				// 수출본선, 수출하역 : 부두코드를 도착지로 세팅, 마감일시, 도착(입항)일시,출발(출항)일시 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR	// 수출본선
					|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR		// 수출하역
				) { 
					if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) {	  // 수출본선
						ed_arvWrkPlCd.setValue(rtnList[12]); // 부두코드
						ed_arvWrkPlNm.setValue(rtnList[13]); // 부두코드명	
					} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR) { // 수출하역
						ed_dptWrkPlCd.setValue(rtnList[12]); // 부두코드
						ed_dptWrkPlNm.setValue(rtnList[13]); // 부두코드명	
					}
					ica_closeDt.setValue(rtnList[3]);    // 마감일자
					ed_closeHh.setValue(rtnList[4]);    // 마감시간
					ed_wrkStDt.setValue(rtnList[5]);    // 도착(입항)일자
					ed_wrkStHh.setValue(rtnList[6]);    // 도착(입항)시간
					ed_wrkEndDt.setValue(rtnList[7]);   // 출발(출항)일자
					ed_wrkEndHh.setValue(rtnList[8]);   // 출발(출항)시간				

				// 수출일반 : 마감일시 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) { // 수출일반
					ica_closeDt.setValue(rtnList[3]); // 마감일자
					ed_closeHh.setValue(rtnList[4]); // 마감시간			
				// 부두간TS : 부두코드를 출발지로 세팅, 도착(입항)일시,출발(마감일시)일시 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) {				// 부두간TS				 
					ed_dptWrkPlCd.setValue(rtnList[12]);    // 부두코드
					ed_dptWrkPlNm.setValue(rtnList[13]);    // 부두코드명
					ed_wrkStDt.setValue(rtnList[5]);        // 도착(입항)일자
					ed_wrkStHh.setValue(rtnList[6]);        // 도착(입항)시간
				// 하선지 TS인 경우 confirmMsg로 확인한 후, 값 세팅
				// case1: 부두코드 --> 하선지(CY) ==> 부두코드를 출발지로 세팅
				// case2: 하선지(CY) --> 부두코드 ==> 부두코드를 도착지로 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR) {    // 하선지 TS(부두-->CY)
					ed_dptWrkPlCd.setValue(rtnList[12]); // 부두코드
					ed_dptWrkPlNm.setValue(rtnList[13]); // 부두코드명
				// 하선지 TS인 경우 confirmMsg로 확인한 후, 값 세팅
				// case1: 부두코드 --> 하선지(CY) ==> 부두코드를 출발지로 세팅
				// case2: 하선지(CY) --> 부두코드 ==> 부두코드를 도착지로 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR) {    // 하선지 TS(CY-->부두)
					ed_arvWrkPlCd.setValue(rtnList[12]); // 부두코드
					ed_arvWrkPlNm.setValue(rtnList[13]); // 부두코드명	
				// port change : 부두코드를 도착지로 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_PORT_CHANGE_ODR) {  // port change
					ed_arvWrkPlCd.setValue(rtnList[12]);    // 부두코드
					ed_arvWrkPlNm.setValue(rtnList[13]);    // 부두코드명	
					ica_closeDt.setValue(rtnList[3]);        // 마감일자
					ed_closeHh.setValue(rtnList[4]);        // 마감시간
				// return order : 부두코드를 출발지로 세팅
				} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_RETURN_ODR) {				//return order				 
					ed_dptWrkPlCd.setValue(rtnList[12]);    // 부두코드
					ed_dptWrkPlNm.setValue(rtnList[13]);    // 부두코드명	
					ica_closeDt.setValue(rtnList[3]);        // 마감일자
					ed_closeHh.setValue(rtnList[4]);        // 마감시간
				}
				// 본선관리번호에 해당하는 BL정보, 품명정보, 컨테이너정보 가져오기
				// 수입본선, 부두간TS, 하선지TS(부두코드 --> 하선지(CY))인 경우, 하선장소를 도착지로 세팅
				scwin.f_retrieveManifestBLContainerList(); 
			} else if (gubun == "TS") {
				ed_tsCvsslMgntNo.setValue(rtnList[0]);
				ed_tsVsslCd.setValue(rtnList[1]);                   // 선박코드
				ed_tsVsslNm.setValue(rtnList[2]);                   // 선박명
				ed_tsPortcnt.setValue(rtnList[9]);                  // 선사항차
				ed_tslane.setValue(rtnList[10]);                    // 항로
				ds_odrInfo.setCellData(0, "tsPortCd", rtnList[11]); // 항구코드	

				//부두코드를 도착지로 세팅
				if (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) { // 부두간TS
					ed_arvWrkPlCd.setValue(rtnList[12]);    // 부두코드
					ed_arvWrkPlNm.setValue(rtnList[13]);    // 부두코드명
					ed_wrkEndDt.setValue(rtnList[3]);       // 도착(마감일자)일자
					ed_wrkEndHh.setValue(rtnList[4]);       // 도착(마감시간)시간	

					// 본선관리번호에 해당하는 BL정보, 품명정보, 컨테이너정보 가져오기
					// 수입본선, 부두간TS, 하선지TS(부두코드 --> 하선지(CY))인 경우, 하선장소를 도착지로 세팅
					if (scwin.odrCtrlClsCd == "1") {
					   scwin.f_retrieveManifestBLContainerList(); 
					}
				}
			}
		}
	} else { // rtnList값이 null인 경우
		if (gubun == "") {
			scwin.f_clearDataByCvsslMgntNo(); // 본선관리번호와 관련한 데이터셋 Clear
		} else if (gubun == "TS") {
			scwin.f_clearDataByTsCvsslMgntNo(); // TS본선관리번호와 관련한 데이터셋 Clear	
		}
	}
};

//수입본선,부두간TS,하선지경유TS(부두-->CY)인 경우, 행삭제 클릭시 실행
//컨테이너번호를 삭제하는 경우 해당 컨테이너의 BL번호에 속해 있는 모든 컨테이너를 동시에 삭제하도록한다.(BL기준 삭제됨)
scwin.f_retrieveBlAndCntrForCvssl = async function(cntrNo) {
	var mrn = "";

	// 본선관리번호 체크
	if (ed_cvsslMgntNo.getValue().trim() == "") {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["본선관리번호"]); // @을(를) 입력하십시오
		return false;
	}

	// bl정보에서 mrn값 가져오기
	if (ds_blInfo.getRowCount() > 0) {
		mrn = ds_blInfo.getCellData(0, "mrn");
	}

    $c.sbm.setAction(sbm_retrieveBLAndCntrForCvssl, "/ds.sd.odrmgnt.odrreg.RetrieveContainerStandardBillOfLadingAndContainerListCMD.do" + "?mrn=" + mrn + "&cntrNo=" + cntrNo);
    let e = await $c.sbm.execute(sbm_retrieveBLAndCntrForCvssl);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_retrieveBLAndCntrForCvssl_submitdone(e);
    }
};

// 수입본선,부두간TS, 수입TS인 경우, 행삭제시 실행 : tr_retrieveBLAndCntrForCvssl를 실행한 후, success시 실행
// 삭제하고자 하는 컨테이너번호와 관련된 bl정보, 또 그 bl정보와 관련된 컨테이너번호를 모두 삭제시켜준다.
scwin.f_successRetrieveBLAndCntrForCvssl = async function() {
	if (scwin.btnPos == "D2" || (scwin.btnPos == "U2" && ds_cntrInfo.getRowStatus(ds_cntrInfo.getRowPosition()) == "D")) {
		var cntrRows = ds_cntrInfo.getRowCount();
		var blRows   = ds_blInfo.getRowCount();
		var dsRows   = ds_retrieveBLAndCntrForCvssl.getRowCount();

		if (dsRows > 0) {
			var arrCntrNo  = new Array();
			var arrCntrPos = new Array();
			var idxCntr    = 0;
			var arrBlNo    = new Array();
			var arrBlPos   = new Array();
			var idxBl      = 0;

			for (var i = 0; i < dsRows; i++) {
				var cntrNo = (ds_retrieveBLAndCntrForCvssl.getCellData(i, "cntrNo")).trim();
				var blNo   = (ds_retrieveBLAndCntrForCvssl.getCellData(i, "blNo")).trim();

				// 컨테이너정보와 체크
				if (cntrNo != "" && blNo == "") {
					for (var j = 0; j < cntrRows; j++) {
						if (ds_cntrInfo.getCellData(j, "cntrNo") == cntrNo) {
							arrCntrNo[idxCntr]  = cntrNo;
							arrCntrPos[idxCntr] = j;
							idxCntr = idxCntr + 1;
						}				
					}
				}

				// BL정보와 체크
				if (cntrNo == "" && blNo != "") {
					for (var j = 0; j < blRows; j++) {
						if (ds_blInfo.getCellData(j, "blNo") == blNo) {
							arrBlNo[idxBl]  = blNo;
							arrBlPos[idxBl] = j;
							idxBl = idxBl + 1;
						}				
					}
				}
			}

			// 확인메세지로 보여주기 위한 부분
			var alertStr = "";
			if (arrCntrNo.length > 0 || arrBlNo.length > 0) {
				for (var i in arrCntrNo) {
					if (arrCntrNo[i] != null) {
						if (i == 0) {
							alertStr = alertStr + "<br>[컨테이너번호]<br>";
							alertStr = alertStr + arrCntrNo[i];
						} else {
							alertStr = alertStr + "," + arrCntrNo[i];
						}
					}
				}			

				for (var i in arrBlNo) {
					if (arrBlNo[i] != null) {
						if (i == 0) {
							alertStr = alertStr + "<br>[BL번호]<br>";	
							alertStr = alertStr + arrBlNo[i];
						} else {
							alertStr = alertStr + "," + arrBlNo[i];
						}
					}
				}

				if (scwin.btnPos == "D2") {
					alertStr = "현재 선택한 컨테이너를 삭제하면 <br>"
							 + alertStr 
							 + "<br><br>총 " 
							 + arrCntrNo.length + " 건의 컨테이너정보와 총 "
							 + arrBlNo.length + " 건의 BL정보를 모두 삭제하시겠습니까?";
				} else if (scwin.btnPos == "U2") {
					alertStr = "현재 선택한 컨테이너를 삭제취소하면 <br>"
							 + alertStr 
							 + "<br><br>총 " 
							 + arrCntrNo.length + " 건의 컨테이너정보와 총 "
							 + arrBlNo.length + " 건의 BL정보가 모두 삭제취소됩니다.<br>취소하시겠습니까?";
				}

                if (await $c.win.confirm(alertStr)) {
					var arrCntrLength = arrCntrNo.length + 0;
					var arrBlLength = arrBlNo.length + 0;

					// 컨테이너 삭제 또는 취소
					for (var i=arrCntrLength-1; i>=0; i--) {
						if (arrCntrNo[i] != null) {
							if (scwin.btnPos == "D2") {
								ds_cntrInfo.deleteRow(arrCntrPos[i]);
							} else if (scwin.btnPos == "U2") {
								ds_cntrInfo.undoRow(arrCntrPos[i]);
							}
						}
					}			

					// Bl정보 삭제 또는 취소
					for (var i=arrBlLength-1; i>=0; i--) {
						if (arrBlNo[i] != null) {
							if (scwin.btnPos == "D2") {
								ds_blInfo.deleteRow(arrBlPos[i]);
							} else if (scwin.btnPos == "U2") {
								ds_blInfo.undoRow(arrBlPos[i]);
							}						
						}
					}
					// 품명목록의 입력수량 계산
					scwin.f_calInputQty();	
                }
			} else {
				alertStr = MSG_CM_CRM_008 + ["현재 선택한 컨테이너"]; //@을(를) 삭제하시겠습니까?
                if (await $c.win.confirm(alertStr)) {
					ds_cntrInfo.removeRow(ds_cntrInfo.getRowPosition());
					//품명목록의 입력수량 계산
					scwin.f_calInputQty();	
				}
			}
		}
	}
};

// 컨테이너목록에서 행추가 후, 컨테이너번호 입력시 값 가져오기 
// 수입본선,부두간TS,하선지경유TS(부두-->CY)인 경우, 컨테이너번호와 bl정보 가져오기
// 수입본선,부두간TS, 수입TS인 경우, 행추가하여 컨테이너번호를 입력시 실행 : tr_retrieveCntrBasisInfo를 실행한 후, success시 실행
// 추가하고자 하는 컨테이너번호와 관련된 bl정보, 또 그 bl정보와 관련된 컨테이너번호를 모두 메세지로 보여주고 추가시켜준다.
// 입력수량을 다시 계산한다.
scwin.f_setCntrBasisInfoAndBlInfo = async function () {
	var blRows		    = ds_blInfo.getRowCount();
	var cntrRows	    = ds_cntrInfo.getRowCount() - 1; //방금 입력한 컨테이너 row 삭제
	var cntrBasisRows   = ds_cntrBasisInfo.getRowCount();
	var cntrBasisBlRows = ds_cntrBasisBlInfo.getRowCount();
	var iBlRows		    = 0;
	var iCntrRows	    = 0;
	var arrBlNo		    = new Array();
	var arrBlPos	    = new Array();
	var arrCntrNo	    = new Array();
	var arrCntrPos	    = new Array();	

	// BL중복 체크 및 세팅
	for (var i = 0; i < cntrBasisBlRows; i++) {
		if (blRows > 0) {
			var sameYn = "N";
			for (var j = 0; j < blRows; j++) {
				if (ds_blInfo.getRowStatus(j) != "D") { // 해당 row가 삭제건이 아닌 경우 
					if (ds_cntrBasisBlInfo.getCellData(i, "mrn") == ds_blInfo.getCellData(j, "mrn")
						&& ds_cntrBasisBlInfo.getCellData(i, "msn") == ds_blInfo.getCellData(j, "msn")
						&& ds_cntrBasisBlInfo.getCellData(i, "hsn") == ds_blInfo.getCellData(j, "hsn")
						&& ds_cntrBasisBlInfo.getCellData(i, "blNo") == ds_blInfo.getCellData(j, "blNo")
					) {
						sameYn = "Y";
						break;
					}
				}
			}

			if (sameYn == "N") {
				// bl번호 배열값 세팅
				arrBlPos[iBlRows] = i;
				arrBlNo [iBlRows] = ds_cntrBasisBlInfo.getCellData(i, "blNo");
				iBlRows = iBlRows + 1;
			}
		} else {
			//bl번호 배열값 세팅
			arrBlPos[iBlRows] = i;
			arrBlNo [iBlRows] = ds_cntrBasisBlInfo.getCellData(i, "blNo");
			iBlRows = iBlRows + 1;
		}
	}

	// 컨테이너 중복 체크 및 세팅
	for (var i = 0; i < cntrBasisRows; i++) {
		if (cntrRows > 0) {
			var sameYn = "N";
			for (var j = 0; j < cntrRows; j++) {
				if (ds_cntrInfo.getRowStatus(j) != "D") { //해당row가 삭제건이 아닌 경우
					if (ds_cntrBasisInfo.getCellData(i, "cntrNo") == ds_cntrInfo.getCellData(j, "cntrNo")
						&& ds_cntrBasisInfo.getCellData(i, "cntrSizCd") == ds_cntrInfo.getCellData(j, "cntrSizCd")
						&& ds_cntrBasisInfo.getCellData(i, "cntrTypCd") == ds_cntrInfo.getCellData(j, "cntrTypCd")
						&& ds_cntrBasisInfo.getCellData(i, "fullEmptyClsCd") == ds_cntrInfo.getCellData(j, "fullEmptyClsCd")
					) {
						sameYn = "Y";
						break;
					}
				}
			}

			if (sameYn == "N") {
				//컨테이너번호 배열값 세팅
				arrCntrPos[iCntrRows] = i;
				arrCntrNo [iCntrRows] = ds_cntrBasisInfo.getCellData(i, "cntrNo");
				iCntrRows = iCntrRows + 1;
			}
		} else {
			//컨테이너번호 배열값 세팅
			arrCntrPos[ iCntrRows ] = i;
			arrCntrNo [ iCntrRows ] = ds_cntrBasisInfo.getCellData(i, "cntrNo");
			iCntrRows = iCntrRows + 1;
		}			
	}

	// 추가해야할 bl번호와 컨테이너번호를 확인메세지로 보여주기 위한 부분
	var alertStr = "";
	if (arrCntrNo.length > 0 || arrBlNo.length > 0) {
		for (var i in arrCntrNo) {
			if (arrCntrNo[i] != null) {
				if (i == 0) {
					alertStr = alertStr + "<br>[컨테이너번호]<br>";
					alertStr = alertStr + arrCntrNo[i];
				} else {
					alertStr = alertStr + "," + arrCntrNo[i];
				}
			}
		}			

		for (var i in arrBlNo) {
			if (arrBlNo[i] != null) {
				if (i == 0) {
					alertStr = alertStr + "<br>[BL번호]<br>";	
					alertStr = alertStr + arrBlNo[i];
				} else {
					alertStr = alertStr + "," + arrBlNo[i];
				}
			}
		}

		alertStr = "현재 선택한 컨테이너를 추가하면 <br>"
				 + alertStr 
				 + "<br><br>총 " 
				 + arrCntrNo.length + " 건의 컨테이너정보와 총 "
				 + arrBlNo.length + " 건의 BL정보가 추가됩니다. 모두 추가하시겠습니까?";

		if (await $c.win.confirm(alertStr)) {
			var arrBlLength   = arrBlPos.length + 0;
			var arrCntrLength = arrCntrPos.length + 0;

			if (arrBlLength > 0) {
				for (var i = 0; i < arrBlLength; i++) {
                    var newIdx = ds_blInfo.insertRow(); 
                    ds_blInfo.setCellData(newIdx, "mrn",  ds_cntrBasisBlInfo.getCellData(arrBlPos[i], "mrn"));
                    ds_blInfo.setCellData(newIdx, "msn",  ds_cntrBasisBlInfo.getCellData(arrBlPos[i], "msn"));
                    ds_blInfo.setCellData(newIdx, "hsn",  ds_cntrBasisBlInfo.getCellData(arrBlPos[i], "hsn"));
                    ds_blInfo.setCellData(newIdx, "blNo", ds_cntrBasisBlInfo.getCellData(arrBlPos[i], "blNo"));
				}
			}	

			if (arrCntrLength > 0) {
				ds_cntrInfo.removeRow(ds_cntrInfo.getRowPosition()); //컨테이너 입력한 row 삭제
				for (var i = 0; i < arrCntrLength; i++) {
                    var newIdx = ds_cntrInfo.insertRow(); 

                    ds_cntrInfo.setCellData(newIdx, "arrvlportDtm",   ds_cntrBasisInfo.getCellData(arrCntrPos[i], "arrvlportDtm"));
                    ds_cntrInfo.setCellData(newIdx, "cntrNo",        ds_cntrBasisInfo.getCellData(arrCntrPos[i], "cntrNo"));
                    ds_cntrInfo.setCellData(newIdx, "cntrSizCd",     ds_cntrBasisInfo.getCellData(arrCntrPos[i], "cntrSizCd"));
                    ds_cntrInfo.setCellData(newIdx, "cntrTypCd",     ds_cntrBasisInfo.getCellData(arrCntrPos[i], "cntrTypCd"));
                    ds_cntrInfo.setCellData(newIdx, "fullEmptyClsCd",ds_cntrBasisInfo.getCellData(arrCntrPos[i], "fullEmptyClsCd"));
                    ds_cntrInfo.setCellData(newIdx, "lineCd",        ds_cntrBasisInfo.getCellData(arrCntrPos[i], "mcomLineCd")); //Line코드
                    ds_cntrInfo.setCellData(newIdx, "impSealNo",     ds_cntrBasisInfo.getCellData(arrCntrPos[i], "impSealNo"));
                    ds_cntrInfo.setCellData(newIdx, "blNo",          ds_cntrBasisInfo.getCellData(arrCntrPos[i], "blNo"));

                    ds_cntrInfo.setCellData(newIdx, "dptWrkPlCd",    ed_dptWrkPlCd.getValue().trim());
                    ds_cntrInfo.setCellData(newIdx, "arvWrkPlCd",    ds_cntrBasisInfo.getCellData(arrCntrPos[i], "arvWrkPlCd")); //하선지 코드
                    ds_cntrInfo.setCellData(newIdx, "arvWrkPlNm",    ds_cntrBasisInfo.getCellData(arrCntrPos[i], "arvWrkPlNm")); //하선지 코드명
                    ds_cntrInfo.setCellData(newIdx, "wt",            ds_cntrBasisInfo.getCellData(arrCntrPos[i], "impWt"));      //수입중량
                    ds_cntrInfo.setCellData(newIdx, "impWt",         ds_cntrBasisInfo.getCellData(arrCntrPos[i], "impWt"));      //수입중량
                    ds_cntrInfo.setCellData(newIdx, "xrayLupTrgtYn", ds_cntrBasisInfo.getCellData(arrCntrPos[i], "xrayLupTrgtYn")); //X-RAY대상여부

                    ds_cntrInfo.setCellData(newIdx, "wrkStDt",       ed_wrkStDt.getValue().trim());
                    ds_cntrInfo.setCellData(newIdx, "wrkStHh",       ed_wrkStHh.getValue().trim());
                    ds_cntrInfo.setCellData(newIdx, "wrkEndDt",      ed_wrkEndDt.getValue().trim());
                    ds_cntrInfo.setCellData(newIdx, "wrkEndHh",      ed_wrkEndHh.getValue().trim());
				}
			}

			// 품명목록의 입력수량 계산
			scwin.f_calInputQty();	
		} else {
			ds_cntrInfo.undoRow(ds_cntrInfo.getRowPosition());

			// 품명목록의 입력수량 계산
			scwin.f_calInputQty();	
		}
	}
};

