scwin.f_delete = async function () {
    let msg  = "오더번호 : " + $c.data.getMessage(MSG_CM_CRM_008, new Array(ds_odrInfo.getCellData(0,"odrNo").trim()));
    let conf = await $c.win.confirm(msg);
    if (conf) {
 		if (ds_deleteOrderCond.getRowCount() > 0) { 
 			ds_deleteOrderCond.removeAll();
 		}
        var rowIndex = ds_deleteOrderCond.insertRow();
 		ds_deleteOrderCond.setCellData(rowIndex, "odrNo", ds_odrInfo.getCellData(1,"odrNo").trim());
 		ds_deleteOrderCond.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
 		ds_deleteOrderCond.setCellData(rowIndex, "impExpDomesticClsCd", scwin.impExpClsCd);
 		ds_deleteOrderCond.setCellData(rowIndex, "selfClsCd", scwin.selfClsCd);

        let e = await $c.sbm.execute(sbm_deleteOrderCond);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_deleteOrderCond_submitdone(e);
        }
	} 
}; 

