// DeleteMarked 기능 구현
scwin.fn_deleteGridRowByStatus = function(dataListObj, gridObj, rowIdx) {
    if (rowIdx === undefined || rowIdx < 0) {
        rowIdx = gridObj.getFocusedRowIndex();
    }
    var rowStatus = dataListObj.getRowStatus(rowIdx);
    if (rowStatus === "C") {
        dataListObj.removeRow(rowIdx);
    } else {
        dataListObj.deleteRow(rowIdx);
    }
};

// undoRow 기능 구현
scwin.f_undoRow = function(dataListObj, gridObj, rowIdx) {
    if (rowIdx === undefined || rowIdx < 0) {
        rowIdx = gridObj.getFocusedRowIndex();
    }

    var rowStatus = dataListObj.getRowStatus(rowIdx);
    if (rowStatus === "C") {
        dataListObj.removeRow(rowIdx);
    } else {
        dataListObj.undoRow(rowIdx);
    }
};

// gr_commInfo에서 OnCloseUp이벤트 발생시, 컨테이너목록을 체크한 후, 품명목록에 컨테이너 종류가 존재하지 않으면 에러
// 사용자가 입력한 컨테이너 종류와 품명목록의 종류가 다른 것이 있는지 체
scwin.f_checkCommTypeByCntrTypeOnCloseUpEvent = async function (row, colid) {;
	var commVal  = "";	
	if (Number(ds_commInfo.getCellData(row, "inputQty")) > 0 && ds_commInfo.getCellData(row, colid) != scwin.orgCommVal && !scwin.f_checkCommTypeByCntrType()) {
		if (colid == "cntrSizCd") {
			commVal = scwin.orgCommVal + ds_commInfo.getCellData(row, "cntrTypCd") + ds_commInfo.getCellData(row, "fullEmptyClsCd");
		} else if (colid == "cntrTypCd") {
			commVal = ds_commInfo.getCellData(row, "cntrSizCd") + scwin.orgCommVal + ds_commInfo.getCellData(row, "fullEmptyClsCd");					
		} else if (colid == "fullEmptyClsCd") {
			commVal = ds_commInfo.getCellData(row, "cntrSizCd") + ds_commInfo.getCellData(row, "cntrTypCd") + scwin.orgCommVal;
		}

		if (await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_003, [commVal])) { //컨테이너 목록에  [@]컨테이너가 존재하고 있으므로 해당 품명을 수정할 수 없습니다
            ds_commInfo.setCellData(row, colid, scwin.orgCommVal);
            return;
        } 
	}
};

// gr_commInfo에서 OnCloseUp이벤트 발생시, 컨테이너목록을 체크한 후, 품명목록에 컨테이너 종류가 존재하지 않으면 에러
// 사용자가 입력한 컨테이너 종류와 품명목록의 종류가 다른 것이 있는지 체크
// f_checkCommTypeByCntrTypeOnCloseUpEvent()내에서 사용
scwin.f_checkCommTypeByCntrType = function () {
	var cntrRows = ds_cntrInfo.getRowCount();
	var commRows = ds_commInfo.getRowCount();

	for (var i = 0; i < cntrRows; i++) {
		if (ds_cntrInfo.getRowStatus(i) != "D") { // 삭제한 경우는 제외
			var cntrSize = ds_cntrInfo.getCellData(i, "cntrSizCd");
			var cntrType = ds_cntrInfo.getCellData(i, "cntrTypCd");
			var cntrFE	 = ds_cntrInfo.getCellData(i, "fullEmptyClsCd");
			var sameYn	 = "Y";

			for (var j = 0; j < commRows; j++) {
				if (ds_commInfo.getRowStatus(j) != "D") { //삭제한 경우는 제외
					if (ds_commInfo.getCellData(j, "inputQty") > 0) {
						var commSize = ds_commInfo.getCellData(j, "cntrSizCd");
						var commType = ds_commInfo.getCellData(j, "cntrTypCd");
						var commFE	 = ds_commInfo.getCellData(j, "fullEmptyClsCd");

						if (cntrSize != commSize || cntrType != commType || cntrFE != commFE) {
							sameYn = "N";
							break;
						}
					}					
				}
			}

			if (sameYn == "N") {
				return false;
			}			
		}
	}

	return true;
};

// 공통팝업 열기 전에 체크
// param설명 : nmObj-코드명(text), cdObj-코드(emedit), gubun1, gubun2
