    if (nmObj.value == "") {
        cdObj.setValue("");
        if (gubun1 == "3") { //Line조회
            ds_odrInfo.setCellData(0, "shpCoClntNo", "");
            ed_shpCoClntNm.setValue("");
        } else if (gubun1 == 1) { // 거래처조회
            if (ds_ctrtNo.getRowCount() > 0)			ds_ctrtNo.removeAll();        
            if (ds_reqClntNo.getRowCount() > 0)		    ds_reqClntNo.removeAll();
            if (ds_bilgClntNo.getRowCount() > 0)		ds_bilgClntNo.removeAll();
            if (ds_realMchtClntNo.getRowCount() > 0)	ds_realMchtClntNo.removeAll();

            $c.gus.cfInitObjects([ed_ctrtClntNo, ed_ctrtClntNm, ed_reqClntNo, ed_bilgClntNo, ed_realMchtClntNo]);
            $c.gus.cfInitHidVal([ed_ctrtClntNo, ed_ctrtClntNm, ed_reqClntNo, ed_bilgClntNo, ed_realMchtClntNo]);
        }
        return;
    } else {
        cdObj.setValue("");
        if (gubun1 == 3) { // Line조회
            ds_odrInfo.setCellData(0, "shpCoClntNo", "");
            ed_shpCoClntNm.setValue("");
        } else if (gubun1 == 1) { // 거래처조회
            if (ds_reqClntNo.getRowCount() > 0)		    ds_reqClntNo.removeAll();
            if (ds_bilgClntNo.getRowCount() > 0)		ds_bilgClntNo.removeAll();
            if (ds_realMchtClntNo.getRowCount() > 0)	ds_realMchtClntNo.removeAll();

            $c.gus.cfInitObjects([ed_reqClntNo, ed_bilgClntNo, ed_realMchtClntNo]);
            $c.gus.cfInitHidVal([ed_reqClntNo, ed_bilgClntNo, ed_realMchtClntNo]);
        }
    }
	scwin.f_openCommonPopUp(gubun1, gubun2, pWinCloseTF, pAllSearchTF, 'F');
};

// 본선관리번호와 관련한 DataSet초기화(수입본선인 경우)  
scwin.f_clearDataByCvsslMgntNo = function () {										
	$c.gus.cfInitObjects([
                            ed_cvsslMgntNo,	ed_vsslCd,		ica_closeDt,	ed_closeHh,		ed_wrkStDt,
					        ed_wrkStHh,		ed_wrkEndDt,	ed_wrkEndHh,	ed_portcnt,		ed_vsslNm,
					        ed_lane,		ed_dptWrkPlCd,	ed_dptWrkPlNm,	ed_dptDtl,		ed_arvWrkPlCd,
					        ed_arvWrkPlNm,	ed_arvDtl
                        ]);
	$c.gus.cfInitHidVal([ed_cvsslMgntNo]);
	ds_odrInfo.setCellData(0, "portCd", ""); // 항구코드	

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR			// 수입본선
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR		// 수입하역
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR					// 부두간TS
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR			// 하선지경유TS(부두-->CY)
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR 		// 수입일반
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 	// CFS셔틀
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR 	// 세관검사
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR 	 		// 검색기
	) { 	
		if (ds_outCommInfoByCvsslMgntNo.getRowCount() > 0)	ds_outCommInfoByCvsslMgntNo.removeAll();    // 품명목록
		if (ds_outCntrInfoByCvsslMgntNo.getRowCount() > 0)	ds_outCntrInfoByCvsslMgntNo.removeAll();    // 컨테이너목록
		if (ds_blInfo.getRowCount() > 0)	                ds_blInfo.removeAll();                      // BL목록
		if (ds_commInfo.getRowCount() > 0)	                ds_commInfo.removeAll();                    // 오더품명목록
		if (ds_cntrInfo.getRowCount() > 0)	                ds_cntrInfo.removeAll();                    // 오더컨테이너목록

		// 총건수 세팅
        commTotalRows.setValue(0);
        sellTotalRows.setValue(0);
        cntrTotalRows.setValue(0);
	}
};

// 수입본선, 수입하역, 부두간TS, 하선지경유TS(부두-->CY) 컨테이너 오더인 경우
// 오더정보에서 도착지 입력시 - 컨테이너에 해당되는 도착지(To)의 범위를 벗어나는 경우 세팅 불가	
scwin.f_checkOdrArvWrkPlCdForCntr = async function (odrArvWrkPlCd) {
	for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
		if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "arvWrkPlCd"))) {
			if (odrArvWrkPlCd != ds_cntrInfo.getCellData(i, "arvWrkPlCd")) {
				if (await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_004)) { // 컨테이너목록의 도착지 정보와 상이합니다
				    return false;
                }; 
			}
		}
	}

	return true;
};

// 수입일반오더인 경우 : 당사배정구분코드의 첫째자리가  'B'인 경우 배정창고를 도착작업장상세로 세팅
