// 그리드에서 팝업오픈하기전 작업(코드와 코드명이 있는 경우)
scwin.f_openPopUpGridBefore = function(ds, row, cdColid, nmColid, olddata, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
	if (ds.getCellData(row, cdColid) != "" && ds.getCellData(row, cdColid) != olddata) {
		ds.setCellData(row, nmColid, "");
		scwin.f_openPopUpGrid(ds, row, cdColid, nmColid, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF);
	} else if (ds.getCellData(row,cdColid) == "") {
		ds.setCellData(row, cdColid, "");
		ds.setCellData(row, nmColid, "");
	}
};

// 그리드 팝업
// 1.컨테이너목록(From(출발지)) : 작업장구분코드가 지역인 경우, 에러메시지 띄우고 ''처리하기
scwin.f_openPopUpGrid = async function(ds, row, cdColid, nmColid, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
	var pCode = "";
	var pName = "";
	var pWtitleSearch = null;
	var pWhere = null;
	var pNoDataCloseTF = null;
	var rtnList = new Array();

    scwin.ds = "";
    scwin.row = "";
    scwin.cdColid = ""; 
    scwin.nmColid = "";

	pCode = ds.getCellData(row, cdColid);

	if (gubun == 1) { // 컨테이너목록 - TO(도착지)
		pSelectID = "retrieveWrkPlInfo";
		pWtitleSearch = "작업장,코드,코드명";
	} else if (gubun == 2) { // 컨테이너목록 - 현위치
		pSelectID = "retrieveWrkPlInfo";
		pWtitleSearch = "현위치, 코드, 코드명";
	} else if (gubun == 3) { // 컨테이너목록 - 항구코드
		pSelectID = "retrievePortInfo";
		pWtitleSearch = "항구, 코드, 코드명";
	} else if (gubun == 4) { // 컨테이너목록 - 항구코드
		pSelectID = "retrievePortInfo";
		pWtitleSearch = "목적항구, 코드, 코드명";
	} else if (gubun == 5) { // 컨테이너목록 - From(출발지)
		pSelectID = "retrieveWrkPlInfo";
		pWtitleSearch = "작업장,코드,코드명";
		pWhere = "";
	}
    udc_openPopUpGrid.setSelectId(pSelectID);
    scwin.ds = ds;
    scwin.row = row;
    scwin.cdColid = cdColid; 
    scwin.nmColid = nmColid;
    await udc_openPopUpGrid.cfCommonPopUpAsync(
                                                scwin.udc_openPopUpGrid_callBackFunc,
                                                pCode,							//pCode
                                                pName,							//pName
                                                pWinCloseTF,					//pWinCloseTF
                                                null,							//pDispCnt
                                                null,							//pTitle
                                                null,							//pWidth
                                                null,							//pHidden
                                                pWhere,							//pWhere
                                                null,							//pW
                                                null,							//pH
                                                null,							//pTop
                                                null,							//pLeft
                                                null,							//pExistTF - 중복체크여부	("F")
                                                pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
                                                pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                pNoDataCloseTF,                 //Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                            );
};

// validate 체크하기 전에 세팅되어야 할 값
scwin.f_setValueBeforeValidation = async function () {
	// 수입일반(자가영업), 수출일반(자가영업), Empty Position(자가영업), On-Hire오더인 경우 Line코드 세팅
	// RCL/ANL인경우 청구처 CHECK함./
	if (ed_lineCd.getValue() == "ANL" || ed_lineCd.getValue() == "RCL") {
	    if (ed_bilgClntNo.getValue() == "999901") {
	       await $c.gus.cfAlertMsg("RCL/AML 라인은  청구처를   공통거래처을 넣을 수  입니다.");
	       return;
	    }
	}

	if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)       // 수출일반(자가영업)
	 	|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)   // 수입일반(자가영업)
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR                                                                     // on-hire
	) {
		for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
			if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { // 실적이 일어나지 않은 경우에만 update할 것!
				ds_cntrInfo.setCellData(i, "lineCd", ed_lineCd.getValue().trim()); // Line코드	
			}
		}
	}	
    if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && ed_lineCd.getValue() == "RCL")) {
        if (ed_bookingNo.getValue() == null || ed_bookingNo.getValue() == "") {
            await $c.gus.cfAlertMsg("RCL라인 수출일반 진행시  BOOKING 번호는 필수 입니다.");
        }
    }
    if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && ed_lineCd.getValue() == "ANL")) {
        if (ed_bookingNo.getValue() == null || ed_bookingNo.getValue() == "") {
            await $c.gus.cfAlertMsg("RCL라인 수출일반 진행시  BOOKING 번호는 필수 입니다.");
        }
    } 
};

//컨테이너번호 유효성 체크
scwin.f_checkCntrNo = async function (parCntrNo) {
	var cntrNo = parCntrNo.trim();

	if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)	    // 수출일반이고, 자가영업인경우
		|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)   // 수입일반이고, 자가영업인경우
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR	                                                                    // On-hire
	) {
		if (cntrNo != "") {		
			if (!dscommon.cf_CheckCntrNo(cntrNo)) {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["컨테이너"]); //유효한 @가 아닙니다
			}
		}	
	}	
};

// 출발일시, 도착일시 값이 없는 경우, 다시 세팅
scwin.f_setDataSetDtHh = function (ds, row) {
	if ($c.gus.cfIsNull(ds.getCellData(row, "wrkStDt")))		ds.setCellData(row, "wrkStDt", ed_wrkStDt.getValue().trim());   // 출발일자
	if ($c.gus.cfIsNull(ds.getCellData(row, "wrkStHh")))		ds.setCellData(row, "wrkStHh", ed_wrkStHh.getValue().trim());   // 출발시간
	if ($c.gus.cfIsNull(ds.getCellData(row, "wrkEndDt")))		ds.setCellData(row, "wrkEndDt", ed_wrkEndDt.getValue().trim()); // 도착일자
	if ($c.gus.cfIsNull(ds.getCellData(row, "wrkEndHh")))		ds.setCellData(row, "wrkEndHh", ed_wrkEndHh.getValue().trim()); // 도착시간
};

// 컨테이너번호를 입력한 경우, 403테이블의 컨테이너입력여부를 1로 update
scwin.f_setCntrInsYn = function (ds, row) {
	if (scwin.statusFlag == "C") { // 신규 저장인 경우 
		if (!$c.gus.cfIsNull(ds.getCellData(row, "cntrNo")))		ds.setCellData(row, "cntrInsYn", 1); // 컨테이너입력여부
	} else if (scwin.statusFlag == "U") { // 수정인 경우 
		if (ds.getRowStatus(row) == "C" && !$c.gus.cfIsNull(ds.getCellData(row, "cntrNo"))) { // 행추가상태이며, 컨테이너번호를 지정한 경우
			ds.setCellData(row, "cntrInsYn", 1); // 컨테이너입력여부
		} else if (ds.getRowStatus(row) == "U" && $c.gus.cfIsNull(ds.getOriginalCellData(row, "cntrNo")) && !$c.gus.cfIsNull(ds.getCellData(row, "cntrNo"))) { // 행수정상태이며, 미지정컨테이너를 지정한 경우
			ds.setCellData(row, "cntrInsYn", 1); // 컨테이너입력여부
		}
	}
};

// 저장하기전에 데이터셋value들 재세팅 - 수출입구분에 따른 컨테이너별 중량,온도,dry여부 세팅
scwin.f_setDryYnByImpExpClsCd = function (ds, row) {
	if (scwin.impExpClsCd == DsConstants.IMP_CD) {
		ds.setCellData(row, "impWt", ds.getCellData(row, "wt"));		    // 수입중량		
		ds.setCellData(row, "impTemper", ds.getCellData(row, "temper"));	// 수입온도	
		ds.setCellData(row, "impDryYn", ds.getCellData(row, "dryYn"));	    // dry여부
	} else if (scwin.impExpClsCd == DsConstants.EXP_CD) {	
		ds.setCellData(row, "expWt", ds.getCellData(row, "wt"));		    // 수출중량		
		ds.setCellData(row, "expTemper", ds.getCellData(row, "temper"));	// 수출온도	
		ds.setCellData(row, "expDryYn", ds.getCellData(row, "dryYn"));	    // dry여부
	} else { // null인 경우, 수출로 보이게 함
		ds.setCellData(row, "expWt", ds.getCellData(row, "wt"));		    // 수출중량		
		ds.setCellData(row, "expTemper", ds.getCellData(row, "temper"));    // 수출온도	
		ds.setCellData(row, "expDryYn", ds.getCellData(row, "dryYn"));	    // dry여부	
	}
};

// 오더별로 저장하기전에 데이터셋value들 재세팅
scwin.f_setValueBeforeSave = function () {	
	var lineCd		= ds_odrInfo.getCellData(0, "lineCd");		// Line코드
	var shpCoClntNo	= ds_odrInfo.getCellData(0, "shpCoClntNo");	// 선사거래처코드
	var sellYn		= ds_odrInfo.getCellData(0, "sellYn");		// 매출여부

	// 오더기본정보 세팅
	ds_odrInfo.setCellData(0, "crcCd", ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "crcCd"));	            // 계약번호에 해당하는 통화코드
    ds_odrInfo.setCellData(0, "taxnClsCd", ds_ctrtNo.getCellData(lc_ctrtNo.getSelectedIndex(), "taxnClsCd"));   // 과세구분코드

	// 오더종류에 따른 값 세팅
    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR) { // 수입본선컨테이너오더
		ds_odrInfo.setCellData(0, "realMchtClntNo", ""); // 실화주

		// 품명정보 값 세팅
		for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
			ds_commInfo.setCellData(i, "qtyUnitCd", "VAN"); // 수량단위코드	

			// 출발일시, 도착일시 값이 없는 경우, 다시 세팅
			scwin.f_setDataSetDtHh(ds_commInfo, i);
		}

		// 컨테이너정보 값 세팅
		var currPosCd = ds_odrInfo.getCellData(0, "dptWrkPlCd");	// 컨테이너 현위치
		for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
			if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) { //실적이 일어나지 않은 경우에만 update할것!
				ds_cntrInfo.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim()); // 출발지코드

