// 데이터셋을 row별로 copy하기
// oDS1 : copy하고자 하는 데이터셋
// oDS2 : copy되고자 하는 데이터셋
scwin.f_copyDataSetRow = function (oDS1, oDS2) {
  	for (var i = 0; i < oDS1.getRowCount(); i++) {
  		if (oDS1.getRowStatus(i) != "D") { // 삭제건이 아닌 경우만 해당
			var rowIndex = oDS2.insertRow();
            // 원본 데이터셋의 모든 컬럼 ID를 가져옴
            var columnIds = oDS1.getColumnID(); 

            for (var j = 0; j < columnIds.length; j++) {
                var colId = columnIds[j];
                // oDS1의 값을 oDS2의 새 행에 복사
                oDS2.setCellData(rowIndex, colId, oDS1.getCellData(i, colId));
            }
		}
  	}
};

// gr_cntrInfo에서 OnCloseUp이벤트 발생시, 품명목록을 체크한 후, 수량 업데이트하기
// param : row - 데이터셋의 현재 RowPosition
scwin.f_setCntrGridCloseUp = async function (row) {
	if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)       // 수출일반,자가영업인 경우
		||(scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)    // Empty Position,자가영업인 경우
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR	                                                                    // on-hire		
	) {
		if (ds_cntrInfo.getCellData(row, "cntrSizCd") != "" && ds_cntrInfo.getCellData(row, "cntrTypCd") != "" && ds_cntrInfo.getCellData(row, "fullEmptyClsCd") != "") {
			scwin.f_calInputQty();  //품명목록 입력수량 계산

			// 컨테이너기본정보값 세팅
			for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
				if (ds_commInfo.getCellData(i, "cntrSizCd") == ds_cntrInfo.getCellData(row, "cntrSizCd") 
					&& ds_commInfo.getCellData(i, "cntrTypCd") == ds_cntrInfo.getCellData(row, "cntrTypCd")
					&& ds_commInfo.getCellData(i, "fullEmptyClsCd") == ds_cntrInfo.getCellData(row, "fullEmptyClsCd")
				) {			
					if (ds_commInfo.getRowStatus(i) != "D") { // 품명정보가 삭제상태가 아닌 경우
						if (Number(ds_commInfo.getCellData(i, "qty")) < Number(ds_commInfo.getCellData(i, "inputQty"))) {	
							if (await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["컨테이너 수량 ","품명 수량"])) { //@은(는) @보다 작아야 합니다.	
                                scwin.f_setCntrInfo(2);
                                scwin.f_calInputQty();
                                return;
                            } 
						}
					} else { // 해당품명정보가 삭제상태인 경우
						if (await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["품명정보가 삭제상태이므로 본 컨테이너정보","추가"])) {  //"@은(는) @할 수 없습니다.";
						    scwin.f_setCntrInfo(2);
						    scwin.f_calInputQty();	
						    return;
                        }
					}
				}
			}
		}
	}
};

// Booking품명정보를 컨테이너오더 품명목록으로 가져오기 및 삭제하기
// gubun : ADD-컨테이너오더 품명목으로 가져가기, DELETE-컨테이너오더 품명목록으로 가져간 것을 삭제
scwin.f_setCommInfoByBkCommInfo = async function (gubun) {

    const options = {};
    options.sortIndex = "seq";
    options.sortOrder = "1";

    ds_bkCommInfo.multisort( options );

	if (gubun == "ADD") { //추가하기
		for (var i = 0; i < ds_bkCommInfo.getRowCount(); i++) {
			var cntrSizCd = ds_bkCommInfo.getCellData(i, "cntrSizCd");   
			var cntrTypCd = ds_bkCommInfo.getCellData(i, "cntrTypCd"); 
			var grossWt	  = ds_bkCommInfo.getCellData(i, "wt");   
			var temper	  = ds_bkCommInfo.getCellData(i, "temper");     
			var sameYn	  = "N";
			var idx		  = 0;	

			for (var j = 0; j < ds_commInfo.getRowCount(); j++) {
				if (ds_commInfo.getRowStatus(j) != "D") { //삭제건이 아닌 경우
					if (cntrSizCd == ds_commInfo.getCellData(j, "cntrSizCd")
						&& cntrTypCd == ds_commInfo.getCellData(j, "cntrTypCd")
						&& grossWt == ds_commInfo.getCellData(j, "grossWt")
						&& temper == ds_commInfo.getCellData(j, "temper")
					) {
						sameYn = "Y";
						idx = j;
						break;
					}
				}
			}

			if (sameYn == "Y") {
				var qty = Number(ds_commInfo.getCellData(idx, "qty"));
				ds_commInfo.setCellData(idx, "qty", qty + Number(ds_bkCommInfo.getCellData(i, "qty")));
			} else if (sameYn == "N") {
				var rowIndex;
                if(rowIndex != null ) {
                    if(await $c.gus.cfValidateGrid(gr_commInfo, null, null, scwin.gr_commInfo_validConfig, "품명목록")) {
                        if( await scwin.f_validateCommAndCntr() ){

                        } else {
                            break;
                        }
                    } else {
                        break;
                    }
                }
                rowIndex = ds_commInfo.insertRow();
                ds_commInfo.setRowPosition(rowIndex);
				var rowPos = ds_commInfo.getRowPosition();
				ds_commInfo.setCellData(rowPos, "cntrSizCd", cntrSizCd);
				ds_commInfo.setCellData(rowPos, "cntrTypCd", cntrTypCd);
				ds_commInfo.setCellData(rowPos, "fullEmptyClsCd", "F");
				ds_commInfo.setCellData(rowPos, "grossWt", grossWt);
				ds_commInfo.setCellData(rowPos, "temper", temper);
				ds_commInfo.setCellData(rowPos, "qty", ds_bkCommInfo.getCellData(i, "qty"));

				if ($c.gus.cfIsNull(ds_bkCommInfo.getCellData(i, "pickupdt"))) {
				    ds_commInfo.setCellData(rowPos, "wrkStDt", ed_wrkStDt.getValue());
				} else {
				    ds_commInfo.setCellData(rowPos, "wrkStDt", ds_bkCommInfo.getCellData(i, "pickupdt"));
				}

				if ($c.gus.cfIsNull(ds_bkCommInfo.getCellData(i, "pickuphh"))) {
				    ds_commInfo.setCellData(rowPos, "wrkStHh", ed_wrkStHh.getValue());
				} else {
   				    ds_commInfo.setCellData(rowPos, "wrkStHh", ds_bkCommInfo.getCellData(i, "pickuphh"));
				}

				if ($c.gus.cfIsNull(ds_bkCommInfo.getCellData(i, "pickupdt"))) {
				    ds_commInfo.setCellData(rowPos, "wrkEndDt", ed_wrkEndDt.getValue());
				} else {
				    ds_commInfo.setCellData(rowPos, "wrkEndDt", ds_bkCommInfo.getCellData(i, "pickupdt"));
				}
				ds_commInfo.setCellData(rowPos, "wrkEndHh", ed_wrkEndHh.getValue());
              //  const r = await scwin.gr_commInfo_oncellclick(rowPos);
               // if(!r) break;
			}
		}
	} else if (gubun == "DELETE") { //삭제하기
		for (var i = 0; i < ds_bkCommInfo.getRowCount(); i++) {
			var cntrSizCd = ds_bkCommInfo.getCellData(i, "cntrSizCd");   
			var cntrTypCd = ds_bkCommInfo.getCellData(i, "cntrTypCd"); 
			var grossWt	  = ds_bkCommInfo.getCellData(i, "wt");   
			var temper	  = ds_bkCommInfo.getCellData(i, "temper");     
			var sameYn	  = "N";
			var idx		  = 0;	

			for (var j = 0; j < ds_commInfo.getRowCount(); j++) {
				if (ds_commInfo.getRowStatus(j) != "D") { // 삭제건이 아닌 경우
					if (cntrSizCd == ds_commInfo.getCellData(j, "cntrSizCd")
						&& cntrTypCd == ds_commInfo.getCellData(j, "cntrTypCd")
						&& grossWt == ds_commInfo.getCellData(j, "grossWt")
						&& temper == ds_commInfo.getCellData(j, "temper")
					) {
						sameYn = "Y";
						idx = j;
						break;
					}
				}
			}

			if (sameYn == "Y") {
				var qty = Number(ds_commInfo.getCellData(idx, "qty"));
				ds_commInfo.setCellData(idx, "qty", qty - Number(ds_bkCommInfo.getCellData(i, "qty")));
			}

			if (Number(ds_commInfo.getCellData(idx, "qty")) <= 0 && Number(ds_commInfo.getCellData(idx, "inputQty")) == 0) {
				ds_commInfo.deleteRow(idx);
			}
		}
	}
};

