        , popupName : "임금수령증인쇄순서"
        , modal : true
        , type : "browserPopup"
        , width : 540
        , height : 550 
        , title : "임금수령증인쇄순서"
    };

    $c.win.openPopup("/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_21p.xml", opts, param);

