// 수출일반, on-hire, off-hire, empty position 오더인 경우만 해당
//   f_setValueBeforeSave()에서 사용됨
//   * 설명 : BOOKING번호의 품명수량과 오더품명수량을 체크하여 컨테이너오더의 품명수량이 많으면 ERROR를 띄우기 위해서, 
//   *       오더품명수량을 size와 type별로 다시 계산한다.
scwin.f_setDs_commQtyCalByCommSizTyp = function () {
	if (ds_commQtyCalByCommSizTyp.getRowCount() > 0) 
        ds_commQtyCalByCommSizTyp.removeAll();

	for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
		if (ds_commInfo.getRowStatus(i) != "D") {	
			if (ds_commQtyCalByCommSizTyp.getRowCount() > 0) {
				var sameYn = "N";
				var idx    = 0;

				for (var j = 0; j < ds_commQtyCalByCommSizTyp.getRowCount(); j++) {
					if (ds_commQtyCalByCommSizTyp.getCellData(j, "cntrSizCd") == ds_commInfo.getCellData(i, "cntrSizCd")
						&& ds_commQtyCalByCommSizTyp.getCellData(j, "cntrTypCd") == ds_commInfo.getCellData(i, "cntrTypCd")
					) {
						sameYn = "Y";
						idx = j;
						break;
					}				
				}

				if (sameYn == "N") {
                    var rowIndex = ds_commQtyCalByCommSizTyp.insertRow();
                    ds_commQtyCalByCommSizTyp.setRowPosition(rowIndex);
					var rowPos = ds_commQtyCalByCommSizTyp.getRowPosition();
					ds_commQtyCalByCommSizTyp.setCellData(rowPos, "cntrSizCd", ds_commInfo.getCellData(i, "cntrSizCd"));
					ds_commQtyCalByCommSizTyp.setCellData(rowPos, "cntrTypCd", ds_commInfo.getCellData(i, "cntrTypCd"));
					ds_commQtyCalByCommSizTyp.setCellData(rowPos, "qty", ds_commInfo.getCellData(i, "qty"));
				} else {
					ds_commQtyCalByCommSizTyp.setCellData(j, "qty", Number(ds_commQtyCalByCommSizTyp.getCellData(j, "qty")) + Number(ds_commInfo.getCellData(i, "qty")));
				}
			} else {
                var rowIndex = ds_commQtyCalByCommSizTyp.insertRow();
                ds_commQtyCalByCommSizTyp.setRowPosition(rowIndex);
				ds_commQtyCalByCommSizTyp.setCellData(rowIndex, "cntrSizCd", ds_commInfo.getCellData(0, "cntrSizCd"));
				ds_commQtyCalByCommSizTyp.setCellData(rowIndex, "cntrTypCd", ds_commInfo.getCellData(0, "cntrTypCd"));
				ds_commQtyCalByCommSizTyp.setCellData(rowIndex, "qty", ds_commInfo.getCellData(0, "qty"));
			}
		}
	}
};

// 유효성 항목 생성용 헬퍼 함수
scwin.getValItem = function(id, name, options = {}) {
    return {
        id: id,
        name: name,
        mandatory: (options.mandatory !== undefined) ? options.mandatory : true,
        ...options       // 나머지 옵션(minNumber, date 등)을 병합
    };
};

scwin.setValidations = function(configs) {
    configs.forEach(function(item) {
        var comp = $p.getComponentById(item.id);
        if (!comp) return;

        // 1. exp가 빈 문자열("")인 경우 속성 초기화
        if (item.exp === "") {
            comp.options.mandatory = false;
            comp.options.title = "";
            return;
        }

        // 2. 파싱 (타이틀:필수여부:옵션)
        var parts = item.exp.split(":");
        var title = parts[0];
        var isMandatory = (parts[1] === "yes");
        var extra = parts[2] || "";

        // 3. 웹스퀘어 표준 속성 주입
        comp.options.title = title;
        comp.options.mandatory = isMandatory;
    });
};

// 값이 화면에 표시되기 직전에 실행되는 함수
scwin.fn_noDash = function(value) {
    if (!value) return "";

    // 원본 데이터(value)에서 하이픈(-)을 모두 제거하여 화면에 리턴
    return value.toString().replace(/-/g, "");
};

scwin.fn_timeFormatter = function(value) {
    if (!value) return "";

    // 숫자만 추출 (혹시 모를 콜론 제거)
    var val = value.replace(/[^0-9]/g, ""); 

    // 4자리 이상일 때만 앞의 4자리를 "HH:mm"으로 변환
    if (val.length >= 4) {
        return val.substring(0, 2) + ":" + val.substring(2, 4);
    }

    return val;
};

