//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function (e) {

    if (ds_ctrtNo.getRowCount() > 0) {
        for (var i = 0; i < ds_ctrtNo.getRowCount(); i++) {
            ds_ctrtNo.setCellData(i, "label", ds_ctrtNo.getCellData(i, "ctrtNo") + " (" + ds_ctrtNo.getCellData(i, "clntPicNm") + ":~" + ds_ctrtNo.getCellData(i, "ctrtEndDt") + ":" + ds_ctrtNo.getCellData(i, "crcCd") + ")");
        }

        ds_ctrtNo.sort("ctrtNo", 1);
        lc_ctrtNo.setSelectedIndex(-1);
        lc_ctrtNo.setValue(ds_ctrtNo.getCellData(0, "ctrtNo"));
    }

    await scwin.lc_ctrtNo_onviewchange();

    ds_odrInfo.setJSON(e.responseJSON.OUT_DS1);
    ds_odrInfo.setRowPosition(0);

    ds_blInfo.setJSON(e.responseJSON.OUT_DS2);
    ds_blInfo.setRowPosition(0);
    ds_commInfo.setJSON(e.responseJSON.OUT_DS3);

    const OUT_DS4 = e.responseJSON.OUT_DS4.map((item, index) => ({
        ...item,      
        Currow : index + 1 
    }));

    ds_cntrInfo.setJSON(OUT_DS4);
    ds_reqClntNo.setJSON(e.responseJSON.OUT_DS6);
    ds_bilgClntNo.setJSON(e.responseJSON.OUT_DS7);
    ds_realMchtClntNo.setJSON(e.responseJSON.OUT_DS8);
    ds_sellInfo.setJSON(e.responseJSON.OUT_DS9);
    ds_bookingInfo.setJSON(e.responseJSON.OUT_DS10);
    ds_bookingInfo.setRowPosition(0); 
    ds_orderallocarpicnm.setJSON(e.responseJSON.OUT_DS11);

 /*   var dsList = [
        "ds_odrInfo", "ds_blInfo", "ds_commInfo", "ds_cntrInfo", 
        "ds_ctrtNo", "ds_reqClntNo", "ds_bilgClntNo", "ds_realMchtClntNo", 
        "ds_sellInfo", "ds_bookingInfo", "ds_orderallocarpicnm"
    ];

    dsList.forEach(function(dsId) {
        var dsObj = $p.getComponentById(dsId); // ID로 객체 찾기

        if (dsObj) {
            // 데이터 건수가 0보다 크면 0번째 row로 위치 설정
            if (dsObj.getTotalRow() > 0) {
                dsObj.setRowPosition(0);
            }
        }
    });
*/


    var odrCnclYn = 0; //취소여부
    scwin.ed_alloccarPicNm2 = "";
    scwin.ed_alloccarPicNm3 = "";
    scwin.ed_alloccarPicNm4 = "";
    scwin.ed_alloccarPicNm5 = "";

    scwin.f_setTabOrderInfo();

    if (ds_odrInfo.getRowCount() > 0) {
        odrCnclYn = ds_odrInfo.getCellData(0, "odrCnclYn");
        if (ds_odrInfo.getCellData(0, "odrCtrlClsCd") == "1") {
            acb_odrCtrlClsCd.setValue("1");
            scwin.odrCtrlClsCd = acb_odrCtrlClsCd.getValue();
        } else {
            acb_odrCtrlClsCd.setValue("2");
            scwin.odrCtrlClsCd = acb_odrCtrlClsCd.getValue();
        }

        scwin.f_set("RETRIEVE");

        // hidValue 세팅하기
        scwin.f_setHidValues(1);

        // 수입본선, 부두간TS, 하선지경유TS(부두-->CY), 수입일반인 경우, original품명정보, original컨테이너정보 데이터셋 세팅(오더수정시 필요함)
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR		    // 수입본선
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR				    // 부두간TS
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR			// 하선지경유TS(부두-->CY)
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR		// 수입일반
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_CUSTOM_INSPECTION_ODR	// 세관검사
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_CFS_SHUTTLE_ODR 	 	// CFS셔틀
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR			    // 검색기
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR		// 수입하역
        ) {
            $c.gus.cfCopyDataSet(ds_blInfo, ds_orgBlInfo, "copyHeader=yes");     // BL정보
            $c.gus.cfCopyDataSet(ds_commInfo, ds_orgCommInfo, "copyHeader=yes"); // 품명정보
            $c.gus.cfCopyDataSet(ds_cntrInfo, ds_orgCntrInfo, "copyHeader=yes"); // 컨테이너정보
        }

        if (ds_commInfo.getRowCount() > 0) {
            commTotalRows.setValue(ds_commInfo.getRowCount());
        }
        if (ds_cntrInfo.getRowCount() > 0) {
            cntrTotalRows.setValue(ds_cntrInfo.getRowCount());
        }

        if (ds_sellInfo.getRowCount() > 0) {
            sellTotalRows.setValue(ds_sellInfo.getRowCount());
        }

        if (!(scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR)) {
            scwin.f_calInputQty("N"); // 컨테이너정보에 따라서 품명정보의 입력수량 계산하기 - validation체크하지 않고, 오류메세지 나타내지 않음
        }

        // 수출일반오더에만 해당 : booking정보 및 booking품명목록 가져오기		
        if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR		// 수출일반
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR	     	// on-hire
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR        // off - hire
            || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR	// empty position
        ) {
            if (ed_lineCd.getValue() == "EVER" || ed_lineCd.getValue() == "HTML" || ed_lineCd.getValue() == "LTXX" || ed_lineCd.getValue() == "LTXX"
                || ed_lineCd.getValue() == "AAL" || ed_lineCd.getValue() == "ANL" || ed_lineCd.getValue() == "HSD" || ed_lineCd.getValue() == "RCL"
                || ed_lineCd.getValue() == "TSL" || ed_lineCd.getValue() == "WW") {
                scwin.f_retrieveBookingInfo("NEW");
            }
        } else {
            // Booking정보 및 Booking품명정보 그리드 숨기기
            tbl_bkInfoTitleArea.hide();
            tbl_bkCommInfoTitleArea.hide();
            scwin.f_hideOdrSelItem(1);
            scwin.f_hideOdrSelItem(2);
        }

        ds_commInfo.reform();
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_046, ["오더번호"]); // 존재하지 않는 @입니다.

        scwin.f_set("INIT", "INIT"); // Clear DataSet
    }

    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR ||
        scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR ||
        scwin.odrKndCd == DsConstants.ODR_KND_CD_PORT_CHANGE_ODR ||
        scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR ||
        scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR ||
        scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) { // 수출본선(C3), 수출TS(CW), PORT CHANGE(CP), ON-HIRE(C5), OFF-HIRE(C6), POSITION(C7)

        // EXCEL UPLOAD 버튼 비활성화
        //$c.gus.cfDisableObjects([btn_excel_up]);
        udc_gr_cntrInfo.setDisabledBtn("btn_excelUp", true);

        // 일괄복사
        $c.gus.cfDisableObjects([lc_cntrItemRow, btn_copy]);
    }

    // 자가구분코드 LuxeCombo
    scwin.f_onSelChangeSelfClsCd(); // 자가구분코드 LuxeCombo OnselChange이벤트 발생시, 화면 필수/비필수 세팅
    acb_selfClsCd.setValue(scwin.selfClsCd);

    // 관리대상인 경우 수정모드 불가
    if (scwin.mgntTrgtClntYn == 1 || odrCnclYn == 1) {
        if (scwin.mgntTrgtClntYn == 1) {
            if (odrCnclYn == 1) {
                await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_006, ["해당 오더", "관리대상 계약거래처이고, 취소된 오더"]);   //"@은(는) @입니다.
            }
        } else {
            if (odrCnclYn == 1) {
                await $c.gus.cfAlertMsg(dscommon.MSG_SD_WRN_006, ["해당 오더", "취소된 오더"]);   //"@은(는) @입니다.
            }
        }
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();
        $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2, btn_updateCntrInfo, btn_chgCntrNoInfo, btn_updateRepWrkInfo, btn_dcSc, btn_unitySelling, btn_copyOdr, btn_tmlEdiIfno]);
        $c.gus.cfEnableBtnOnly([btn_create, btn_create1]);
    }

    // 배차담당자
    for (var i = 0; i < ds_orderallocarpicnm.getRowCount(); i++) {
        if (ds_orderallocarpicnm.getCellData(i, "cntrSeq") == 9001) {
            ed_alloccarPicNm1.setValue(ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicNm"));
            scwin.hid_alloccarPicId1 = ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicId");
        } else if (ds_orderallocarpicnm.getCellData(i, "cntrSeq") == 9002) {
            txt_alloccarPicNm2.setValue(ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicNm"));
            scwin.hid_alloccarPicId2 = ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicId");
        } else if (ds_orderallocarpicnm.getCellData(i, "cntrSeq") == 9003) {
            txt_alloccarPicNm3.setValue(ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicNm"));
            scwin.hid_alloccarPicId3 = ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicId");
        } else if (ds_orderallocarpicnm.getCellData(i, "cntrSeq") == 9004) {
            txt_alloccarPicNm4.setValue(ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicNm"));
            scwin.hid_alloccarPicId4 = ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicId");
        } else if (ds_orderallocarpicnm.getCellData(i, "cntrSeq") == 9005) {
            txt_alloccarPicNm5.setValue(ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicNm"));
            scwin.hid_alloccarPicId5 = ds_orderallocarpicnm.getCellData(i, "shtlAlloccarPicId");
        }
    }

    // 조회 성공여부 		
    scwin.hid_chkReterieve = "retrieveIn";

    scwin.retrieveYn = "N";

    scwin.hid_chkMode = "";
};

scwin.sbm_retrieveCtrtNo_submitdone = async function (e) {

