    // 실화주거래처 데이터가 없는 경우, 계약거래처를 default로 세팅
    if (ds_realMchtClntNo.getRowCount() == 0) {
        ds_realMchtClntNo.removeAll();
        $c.gus.cfInitObjects([ed_realMchtClntNo]);
        $c.gus.cfInitHidVal([ed_realMchtClntNo]);

        ed_realMchtClntNo.setValue(ds_odrInfo.getCellData(0, "ctrtClntNo"));
        scwin.f_openCommonPopUp(1, 'REAL', 'T', 'F', 'T');
    } else {
        ed_realMchtClntNo.setValue(ds_realMchtClntNo.getCellData(0, "clntNo"));
        scwin.f_openCommonPopUp(1, 'REAL', 'T', 'F', 'T');
    }
};

