scwin.sbm_retrieveBookingInfo_submitdone = async function (e) {
	var bkRows     = ds_bkInfo.getRowCount();
	var bkCommRows = ds_bkCommInfo.getRowCount();

	// 비활성화
	$c.gus.cfDisableObjects([tbl_bkInfoArea]); 

	if (bkRows > 0) {
        ds_bkInfo.setRowPosition(0);
		if (bkCommRows > 0) {
            ds_commInfo.setRowPosition(0);
			// 수정mode에서 자가영업(수출일반, Empty Position)인 경우, booking품명정보가 없는 경우에만, LineCd 및 bookingNo 수정 가능하게 해놓았음, 
			// 만약 이때 bookingNo를 수정한 후, booking품명정보가 존재하면 error메시지 띄우기
			if (scwin.bkCommInfoRows == 0 && scwin.retrieveYn == "N" && scwin.statusFlag == "U") {
				// booking품명정보 숨기기
				dscommon.cf_HideObject([tbl_bkCommInfoTitleArea]);
				scwin.f_hideOdrSelItem(2);	
                if (await $c.gus.cfAlertMsg("Booking번호[" + ed_bookingNo.getValue() + "]는 품명정보가 존재하므로 입력할 수 없습니다.")) {
                    ed_bookingNo.setValue("")
                }
			} else {
		 		// 오더조회시 해당 안됨 - booking품명목록 정보를 컨테이너 품명목록의 옮기기
				if (scwin.retrieveYn == "N") {
					scwin.f_setCommInfoByBkCommInfo("ADD");
				}

				// booking품명정보 숨기기
				dscommon.cf_ShowObject([tbl_bkCommInfoTitleArea]);
				scwin.f_showOdrSelItem(2);

				// booking정보 보이기
				dscommon.cf_ShowObject([tbl_bkInfoTitleArea]);
				scwin.f_showOdrSelItem(1);	

				// 특이사항 세팅
				if (scwin.retrieveYn == "N") {
					ta_rmk.setValue(ta_bk_rmk.getValue());
				}				
			}
		} else {
			// booking품명정보 숨기기
			dscommon.cf_HideObject([tbl_bkCommInfoTitleArea]);
			scwin.f_hideOdrSelItem(2);

			// booking정보 보이기
			dscommon.cf_ShowObject([ tbl_bkInfoTitleArea ]);
			scwin.f_showOdrSelItem(1);				
		}	
	} else {
		// booking정보 숨기기
		dscommon.cf_HideObject([tbl_bkInfoTitleArea]);
		scwin.f_hideOdrSelItem(1);

		// booking품명정보 숨기기
		dscommon.cf_HideObject([tbl_bkCommInfoTitleArea]);
		scwin.f_hideOdrSelItem(2);
	}	

	// 오더번호로 조회한 후, 해당 오더번호의 booking품명정보 총 row수를 전역변수 bkCommInfoRows에 담기
	// 자가영업(수출일반, Empty Position)인 경우, booking품명정보가 없는 경우에만, LineCd 및 bookingNo 수정 가능하게 하기 위하여 전역변수에 담는 작업 필요함
	if (scwin.retrieveYn == "Y")	
        bkCommInfoRows = bkCommRows;

    bkCommTotalRows.setValue(bkCommRows);
 	//parent.f_TabFrameResize("iFrame0", document.body.scrollHeight);(확인할것)
};

scwin.sbm_retrieveCntrBasisInfo_submitdone = async function (e) {
	//모든 오더에 해당 - LINE코드가 다르면 에러메시지 띄우기
	if (!(scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR		// 수입본선
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR				//부두간 TS
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR		// 수입TS
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR 		// On-hire
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR	// 수입일반
			|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)  // 수출일반이고 자가영업인 경우 해당
			|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) // EMPTY POSITION이고 자가영업인 경우 해당
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR		    // 검색기
		)
	) {
		if (ds_cntrBasisInfo.getCellData(0, "mcomLineCd") == ed_lineCd.getValue().trim()) {
			if (await $c.gus.cfAlertMsg("해당컨테이너의 Line과 오더정보의 Line이 상이합니다.<br>컨테이너를 다시 입력하여 주십시오.")) {
                ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(), "cntrNo", "");
			    return;
            } 
		}	
	}

	// 오더별 컨테이너정보 세팅
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	                        // 수입본선
		|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "1")   // 부두간TS 적하
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR		                    // 하선지경유TS(부두-->CY)
	) { 
		if (ds_cntrBasisInfo.getRowCount() > 0) {
			scwin.f_setCntrBasisInfoAndBlInfo();
		} else {
			scwin.f_setCntrInfo(2);	
		}
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR // On-hire
			|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES)  // 수출일반이고 자가영업인 경우 해당
			|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) // EMPTY POSITION이고 자가영업인 경우 해당
			|| (scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR && scwin.odrCtrlClsCd == "2") // 부두간TS 비적하
	) {
	    // 화요일작업
		if (ds_cntrBasisInfo.getRowCount() > 0) {
		    if (ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "currPosCd").substring(1, 2) != "C") {
				if (await $c.gus.cfAlertMsg(MSG_CM_WRN_011, ["컨테이너번호"])) { // 이미 존재하는 @입니다
				    ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(), "cntrNo", "");
                } 
			} else {
			    ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(), "arrvlportDtm", ds_cntrBasisInfo.getCellData(ds_cntrBasisInfo.getRowPosition(), "arrvlportDtm"));
			}
		}
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR) { // OFF-HIRE
		if (ds_cntrBasisInfo.getRowCount() > 0) {
				scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
				scwin.f_calInputQty();  // 품명목록 입력수량 계산

				// 컨테이너기본정보값 세팅
				for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
					if (ds_commInfo.getCellData(i, "cntrSizCd") == ds_cntrBasisInfo.getCellData(0, "cntrSizCd") 
						&& ds_commInfo.getCellData(i, "cntrTypCd") == ds_cntrBasisInfo.getCellData(0, "cntrTypCd")
						&& ds_commInfo.getCellData(i, "fullEmptyClsCd") == ds_cntrBasisInfo.getCellData(0, "fullEmptyClsCd")
					) {			
						if (ds_commInfo.getRowStatus(i) != "D") { // 품명정보가 삭제상태가 아닌 경우
							if (ds_commInfo.getCellData(i, "qty") < ds_commInfo.getCellData(i, "inputQty")) {
								if (await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["컨테이너 수량 ","품명 수량"])) { // @은(는) @보다 작아야 합니다.	
                                    scwin.f_setCntrInfo(2);
                                    scwin.f_calInputQty();	
                                    ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(),"fullEmptyClsCd", "E");
                                    return;
                                } 
							}
						} else { // 해당품명정보가 삭제상태인 경우
							if (await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["품명정보가 삭제상태이므로 본 컨테이너정보","추가"])) { // "@은(는) @할 수 없습니다.";
                                scwin.f_setCntrInfo(2);
                                scwin.f_calInputQty();
                                ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(),"fullEmptyClsCd", "E");
                                return;
                            } 
						}
					}
				}
		} else {
			if (await $c.gus.cfAlertMsg(MSG_CM_ERR_046, ["컨테이너번호"])) { // 존재하지 않는 @입니다.
			    scwin.f_setCntrInfo(2);	
            } 
		}
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) { // 수출일반
		if (ds_cntrBasisInfo.getRowCount() > 0) {
			// 수출일반 - F/E가 F면 에러메시지 띄우기
			if (ds_cntrBasisInfo.getCellData(0, "fullEmptyClsCd") == "F") {
				if (await $c.gus.cfAlertMsg(MSG_SD_ERR_001, ["Full"])) { // @컨테이너를 지정할 수 없습니다
				    ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(), "cntrNo", "");
				    return;
                } 
			}

			scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
			scwin.f_calInputQty();  // 품명목록 입력수량 계산

			// 컨테이너기본정보값 세팅
			for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
				if (ds_commInfo.getCellData(i, "cntrSizCd") == ds_cntrBasisInfo.getCellData(0, "cntrSizCd") 
					&& ds_commInfo.getCellData(i, "cntrTypCd") == ds_cntrBasisInfo.getCellData(0, "cntrTypCd")
					&& ds_commInfo.getCellData(i, "grossWt") == ds_cntrBasisInfo.getCellData(0, "wt")    
					&& ds_commInfo.getCellData(i, "temper") == ds_cntrBasisInfo.getCellData(0, "temper") 
					&& ds_commInfo.getCellData(i, "dryYn") == ds_cntrBasisInfo.getCellData(0, "dryYn")	
				) {
					if (ds_commInfo.getRowStatus(i) != "D") { // 품명정보가 삭제상태가 아닌 경우
						if (ds_commInfo.getCellData(i, "qty") < ds_commInfo.getCellData(i, "inputQty")) {	
							if (await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["컨테이너 수량 ","품명 수량"])) { // @은(는) @보다 작아야 합니다.	
                                scwin.f_setCntrInfo(2);
                                scwin.f_calInputQty();	
                                return;
                            } 
						}
					} else { // 해당품명정보가 삭제상태인 경우
						if (await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["품명정보가 삭제상태이므로 본 컨테이너정보","추가"])) { // "@은(는) @할 수 없습니다.";
                            scwin.f_setCntrInfo(2);
                            scwin.f_calInputQty();
                            return;
                        } 
					}
				}
			}
		} else {
			if (await $c.gus.cfAlertMsg(MSG_CM_ERR_046, ["컨테이너번호"])) { // 존재하지 않는 @입니다.
                scwin.f_setCntrInfo(2);
            } 
		}
	} else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR ||
		     scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_EXP_TS_ODR      ||
		     scwin.odrKndCd == DsConstants.ODR_KND_CD_PORT_CHANGE_ODR    ) { // 수출본선, 수출TS, CP
		if (ds_cntrBasisInfo.getRowCount() > 0) {
			/* 현위치 세팅
			 * 1.컨테이너목록의 Size, Type, F/E가 존재하고 컨테이너번호를 입력하는 경우
			 * 2.컨테이너목록의 Size, Type, F/E가 없고, 컨테이너번호를 입력하는 경우
			 */
			var rowPos			= ds_cntrInfo.getRowPosition();
			var cntrSizCd 		= ds_cntrInfo.getCellData(rowPos, "cntrSizCd");
			var cntrTypCd 		= ds_cntrInfo.getCellData(rowPos, "cntrTypCd");
			var fullEmptyClsCd	= ds_cntrInfo.getCellData(rowPos, "fullEmptyClsCd");			

			// 현위치 세팅
			if (ds_cntrBasisInfo.getCellData(0, "odrKndCd") == "CP") { // CP오더인 경우
				// 컨테이너목록에 컨테이너정보를 세팅 - 작업장코드를 컨테이너목록의 From에 세팅한다.
				scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
				ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", ds_cntrBasisInfo.getCellData(0, "wrkPlCd"));
			} else if (ds_cntrBasisInfo.getCellData(0, "odrKndCd") == "CS") { // CS오더인 경우
				// 컨테이너목록에 컨테이너정보를 세팅 - 작업장코드를 컨테이너목록의 From에 세팅한다.
				scwin.f_setCntrInfo(1); //컨테이너정보값 세팅
				ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", ds_cntrBasisInfo.getCellData(0, "wrkPlCd"));
			} else if (!$c.gus.cfIsNull(cntrSizCd) && !$c.gus.cfIsNull(cntrTypCd) && !$c.gus.cfIsNull(fullEmptyClsCd)) {
				if (fullEmptyClsCd == "E") {
					if (ds_cntrBasisInfo.getCellData(0, "wrkPlClsCd") == "C" || ds_cntrBasisInfo.getCellData(0, "wrkPlClsCd") == "P") {
						// 컨테이너목록에 컨테이너정보를 세팅 - 현위치를 컨테이너목록의 From에 세팅한다.
						scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
						ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", ds_cntrBasisInfo.getCellData(0, "currPosCd"));
					} else {
						// 컨테이너목록에 컨테이너정보를 세팅 - From은 사용자가 입력한다.
						scwin.f_setCntrInfo(1); //컨테이너정보값 세팅
						ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", "");
					}
				} else if (fullEmptyClsCd == "F") {
					if (ds_cntrBasisInfo.getCellData(0, "wrkPlClsCd") == "C" && (ds_cntrBasisInfo.getCellData(0, "odrKndCd") == "C4" || ds_cntrBasisInfo.getCellData(0, "odrKndCd") == "CM")) {
						// 컨테이너목록에 컨테이너정보를 세팅 - 현위치를 컨테이너목록의 From에 세팅한다.
						scwin.f_setCntrInfo(1); //컨테이너정보값 세팅
						ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", ds_cntrBasisInfo.getCellData(0, "currPosCd"));
					} else if (ds_cntrBasisInfo.getCellData(1, "odrKndCd") == "C4") {
						// 컨테이너목록에 컨테이너정보를 세팅 - 작업장코드를 컨테이너목록의 From에 세팅한다.
						scwin.f_setCntrInfo(1); //컨테이너정보값 세팅
						ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", ds_cntrBasisInfo.getCellData(0, "wrkPlCd"));
					} else {
						// 컨테이너목록에 컨테이너정보를 세팅 - From은 사용자가 입력한다.
						scwin.f_setCntrInfo(1); //컨테이너정보값 세팅
						ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", "");
					}				
				}
			} else {
				if (ds_cntrBasisInfo.getCellData(0, "odrKndCd") == "C4") { // C4오더인 경우
					// 컨테이너목록에 컨테이너정보를 세팅 - 작업장코드를 컨테이너목록의 From에 세팅한다.
					scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
					ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", ds_cntrBasisInfo.getCellData(0, "wrkPlCd"));
				} else {
					// 컨테이너목록에 컨테이너정보를 세팅 - From은 사용자가 입력한다.
					scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
					ds_cntrInfo.setCellData(rowPos, "dptWrkPlCd", "");
				}
			}

			// 품명목록 입력수량 계산
			if (scwin.excelUploadYn == 0)
                scwin.f_calInputQty();

			// 컨테이너기본정보값 세팅
			for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
				if (ds_commInfo.getCellData(i, "cntrSizCd") == ds_cntrBasisInfo.getCellData(0, "cntrSizCd") 
					&& ds_commInfo.getCellData(i, "cntrTypCd") == ds_cntrBasisInfo.getCellData(0, "cntrTypCd")
					&& ds_commInfo.getCellData(i, "fullEmptyClsCd") == ds_cntrBasisInfo.getCellData(0, "fullEmptyClsCd")
				) {
					if (ds_commInfo.getRowStatus(i) != "D") { // 품명정보가 삭제상태가 아닌 경우
						if (ds_commInfo.getCellData(i, "qty") < ds_commInfo.getCellData(i, "inputQty")) {	
							if (await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["컨테이너 수량 ","품명 수량"])) { // @은(는) @보다 작아야 합니다.	
                                scwin.f_setCntrInfo(2);
                                scwin.f_calInputQty();	
                                return;
                            } 
						}
					} else { // 해당품명정보가 삭제상태인 경우
						if (await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["품명정보가 삭제상태이므로 본 컨테이너정보","추가"])) { //"@은(는) @할 수 없습니다.";
                            scwin.f_setCntrInfo(2);
                            scwin.f_calInputQty();	
                            return;
                        } 
					}
				}
			}
		} else {
			if (await $c.gus.cfAlertMsg(MSG_CM_ERR_046, ["컨테이너번호"])) { // 존재하지 않는 @입니다.
			    scwin.f_setCntrInfo(2);	
            } 
		}
	} else { // 그외 컨테이너오더
		if (ds_cntrBasisInfo.getRowCount() > 0) {
			scwin.f_setCntrInfo(1); // 컨테이너정보값 세팅
			scwin.f_calInputQty();  // 품명목록 입력수량 계산

			// 컨테이너기본정보값 세팅
			for (var i = 0; i < ds_commInfo.getRowCount(); i++) {
				if (ds_commInfo.getCellData(i, "cntrSizCd") == ds_cntrBasisInfo.getCellData(0, "cntrSizCd") 
					&& ds_commInfo.getCellData(i, "cntrTypCd") == ds_cntrBasisInfo.getCellData(0, "cntrTypCd")
					&& ds_commInfo.getCellData(i, "fullEmptyClsCd") == ds_cntrBasisInfo.getCellData(0, "fullEmptyClsCd")
				) {			
					if (ds_commInfo.getRowStatus(i) != "D") { // 품명정보가 삭제상태가 아닌 경우
						if (ds_commInfo.getCellData(i, "qty") < ds_commInfo.getCellData(i, "inputQty")) {	
							if (await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["컨테이너 수량 ","품명 수량"])) { //@은(는) @보다 작아야 합니다.	
                                scwin.f_setCntrInfo(2);
                                scwin.f_calInputQty();	
                                return;
                            } 
						}
					} else { // 해당품명정보가 삭제상태인 경우
						if (await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["품명정보가 삭제상태이므로 본 컨테이너정보","추가"])) { //"@은(는) @할 수 없습니다.";
                            scwin.f_setCntrInfo(2);
                            scwin.f_calInputQty();	
                            return;
                        } 
					}
				}
			}
		} else {
			if (await $c.gus.cfAlertMsg(MSG_CM_ERR_046, ["컨테이너번호"])) { //존재하지 않는 @입니다.
			    scwin.f_setCntrInfo(2);	
            } 
		}
	}

	// RF인 경우 온도 또는  dry여부를 enable/disable하기
	if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), 'cntrNo')) && !$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), 'fullEmptyClsCd'))) {
		scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, ds_cntrInfo.getRowPosition());
	}
};

scwin.sbm_retrieveBLContainer_submitdone = async function(e) {
	ds_commInfo.removeAll();

	// 품명정보세팅		
	if (ds_outCommInfoByBlNo.getRowCount() > 0) {
		ds_commInfo.removeAll();
		for (var i = 0; i < ds_outCommInfoByBlNo.getRowCount(); i++) {
			var newIndex = ds_commInfo.insertRow();
			ds_commInfo.setCellData(newIndex, "cntrSizCd", ds_outCommInfoByBlNo.getCellData(i, "cntrSizCd"));
			ds_commInfo.setCellData(newIndex, "cntrTypCd", ds_outCommInfoByBlNo.getCellData(i, "cntrTypCd"));
			ds_commInfo.setCellData(newIndex, "fullEmptyClsCd", ds_outCommInfoByBlNo.getCellData(i, "fullEmptyClsCd"));
			ds_commInfo.setCellData(newIndex, "qty", ds_outCommInfoByBlNo.getCellData(i, "qty"));
		}	
	}

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR && scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) { // 수입일반(자가영업)인 경우
		ds_cntrInfo.removeAll();
		// 컨테이너정보 세팅
		var outCntrInfoCntRows	= ds_outCntrInfoByCvsslMgntNo.getRowCount(); 
		if (outCntrInfoCntRows > 0) {
			for (var i = 0; i < outCntrInfoCntRows; i++) {
				ds_cntrInfo.insertRow();
				ds_cntrInfo.setCellData(i, "arrvlportDtm", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "arrvlportDtm"));
				ds_cntrInfo.setCellData(i, "cntrNo", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "cntrNo"));
				ds_cntrInfo.setCellData(i, "cntrSizCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "cntrSizCd"));
				ds_cntrInfo.setCellData(i, "cntrTypCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "cntrTypCd"));
				ds_cntrInfo.setCellData(i, "fullEmptyClsCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "fullEmptyClsCd"));
				ds_cntrInfo.setCellData(i, "lineCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "mcomLineCd")); //Line코드
				ds_cntrInfo.setCellData(i, "impSealNo", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "impSealNo"));
				ds_cntrInfo.setCellData(i, "blNo", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "blNo"));
				ds_cntrInfo.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
				ds_cntrInfo.setCellData(i, "arvWrkPlCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "arvWrkPlCd")); //BL테이블의 하선지 코드			
				ds_cntrInfo.setCellData(i, "arvWrkPlNm", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "arvWrkPlNm")); //BL테이블의 하선지 코드명
				ds_cntrInfo.setCellData(i, "wt", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "impWt")); //수입중량
				ds_cntrInfo.setCellData(i, "impWt", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "impWt")); //수입중량
				ds_cntrInfo.setCellData(i, "xrayLupTrgtYn", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "xrayLupTrgtYn")); //X-RAY대상여부
				ds_cntrInfo.setCellData(i, "wrkStDt", ed_wrkStDt.getValue().trim());
				ds_cntrInfo.setCellData(i, "wrkStHh", ed_wrkStHh.getValue().trim());
				ds_cntrInfo.setCellData(i, "wrkEndDt", ed_wrkEndDt.getValue().trim());
				ds_cntrInfo.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue().trim());
			}		
		}

		// 하선장소코드를 도착지로 세팅
		if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR 	// 수입본선인 경우
			|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR 		// 하선지TS이고, 부두코드-->하선지(CY)인 경우
		) { 
			var idx = 0;
			var cntrRows = ds_cntrInfo.getRowCount();
			for (var i = 0; i < cntrRows; i++) {
				if ((ds_cntrInfo.getCellData(i, "arvWrkPlCd")).trim() != "") {
					idx = i;
					break;
				}			
			}		
			ed_arvWrkPlCd.setValue(ds_cntrInfo.getCellData(idx, "arvWrkPlCd"));

			if (cntrRows > 0) {
				ed_arvWrkPlNm.setValue(ds_outCntrInfoByCvsslMgntNo.getCellData(idx, "arvWrkPlNm"));
			} else {
				ed_arvWrkPlNm.setValue("");
			}
		}
		scwin.chkInputQtyYn = "N";
	} else {
		if (ds_cntrInfo.getRowCount() > 0) {
			for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
				ds_cntrInfo.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
				ds_cntrInfo.setCellData(i, "wt", ds_cntrInfo.getCellData(i, "impWt"));
				ds_cntrInfo.setCellData(i, "temper", ds_cntrInfo.getCellData(i, "impTemper"));
				ds_cntrInfo.setCellData(i, "dryYn", ds_cntrInfo.getCellData(i, "impDryYn"));
				ds_cntrInfo.setCellData(i, "wrkStDt", ed_wrkStDt.getValue().trim());
				ds_cntrInfo.setCellData(i, "wrkStHh", ed_wrkStHh.getValue().trim());
				ds_cntrInfo.setCellData(i, "wrkEndDt", ed_wrkEndDt.getValue().trim());
				ds_cntrInfo.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue().trim());

				// RF인 경우 DRY,온도 enable/disable
				scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, i);

                ds_cntrInfo.modifyRowStatus(i, "R");
			}
		}
	}

	// 컨테이너정보에 따라서 품명정보의 입력수량 계산하기
	scwin.f_calInputQty(); 

    commTotalRows.setValue(ds_commInfo.getRowCount());
    sellTotalRows.setValue(ds_sellInfo.getRowCount());
    cntrTotalRows.setValue(ds_cntrInfo.getRowCount());

	// 데이터셋의 상태를 normal하게 만들기
	ds_blInfo.reform();
	ds_commInfo.reform();
	ds_cntrInfo.reform();

	// 조회여부 세팅
	scwin.retrieveYn = "N"; 
};

scwin.sbm_retrieveManifestBLContainerList_submitdone = async function(e) {
	scwin.chkInputQtyYn = "Y";
	ds_commInfo.removeAll();
	ds_cntrInfo.removeAll();

	// 품명정보세팅
	if (ds_outCommInfoByCvsslMgntNo.getRowCount() > 0) {
		for (var i = 0; i < ds_outCommInfoByCvsslMgntNo.getRowCount(); i++) {
			ds_commInfo.insertRow();
			ds_commInfo.setCellData(i, "cntrSizCd", ds_outCommInfoByCvsslMgntNo.getCellData(i, "cntrSizCd"));
			ds_commInfo.setCellData(i, "cntrTypCd", ds_outCommInfoByCvsslMgntNo.getCellData(i, "cntrTypCd"));
			ds_commInfo.setCellData(i, "fullEmptyClsCd", ds_outCommInfoByCvsslMgntNo.getCellData(i, "fullEmptyClsCd"));
			ds_commInfo.setCellData(i, "qty", ds_outCommInfoByCvsslMgntNo.getCellData(i, "qty"));
		}
	}

	// 컨테이너정보 세팅
	var outCntrInfoCntRows = ds_outCntrInfoByCvsslMgntNo.getRowCount(); 

	if (outCntrInfoCntRows > 0) {
		for (var i = 0; i < outCntrInfoCntRows; i++) {
			ds_cntrInfo.insertRow();			
			ds_cntrInfo.setCellData(i, "arrvlportDtm", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "arrvlportDtm"));
			ds_cntrInfo.setCellData(i, "cntrNo", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "cntrNo"));
			ds_cntrInfo.setCellData(i, "cntrSizCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "cntrSizCd"));
			ds_cntrInfo.setCellData(i, "cntrTypCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "cntrTypCd"));
			ds_cntrInfo.setCellData(i, "fullEmptyClsCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "fullEmptyClsCd"));
			ds_cntrInfo.setCellData(i, "lineCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "mcomLineCd")); //Line코드
			ds_cntrInfo.setCellData(i, "impSealNo", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "impSealNo"));
			ds_cntrInfo.setCellData(i, "blNo", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "blNo"));
			ds_cntrInfo.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
			ds_cntrInfo.setCellData(i, "arvWrkPlCd", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "arvWrkPlCd")); //BL테이블의 하선지 코드			
			ds_cntrInfo.setCellData(i, "arvWrkPlNm", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "arvWrkPlNm")); //BL테이블의 하선지 코드명
			ds_cntrInfo.setCellData(i, "wt", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "impWt")); //수입중량
			ds_cntrInfo.setCellData(i, "impWt", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "impWt")); //수입중량
			ds_cntrInfo.setCellData(i, "xrayLupTrgtYn", ds_outCntrInfoByCvsslMgntNo.getCellData(i, "xrayLupTrgtYn")); //X-RAY대상여부
			ds_cntrInfo.setCellData(i, "wrkStDt", ed_wrkStDt.getValue().trim());
			ds_cntrInfo.setCellData(i, "wrkStHh", ed_wrkStHh.getValue().trim());
			ds_cntrInfo.setCellData(i, "wrkEndDt", ed_wrkEndDt.getValue().trim());
			ds_cntrInfo.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue().trim());

            ds_cntrInfo.setCellData(i, "Currow",  i+1);
            ds_cntrInfo.setCellData(i, "chk", "0");
            ds_cntrInfo.setCellData(i, "dcsnYn", "0");
            ds_cntrInfo.setCellData(i, "xrayLupTrgtYn", "0");
            ds_cntrInfo.setCellData(i, "leaseYn", "0");
            ds_cntrInfo.setCellData(i, "socYn", "0");
            ds_cntrInfo.setCellData(i, "impMgsetYn", "0");
            ds_cntrInfo.setCellData(i, "dryYn", "0");


		}		
	}

	// 하선장소코드를 도착지로 세팅
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR 	// 수입본선인 경우
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR 		// 하선지TS이고, 부두코드-->하선지(CY)인 경우
	) { 
		var idx = 0;
		var cntrRows = ds_cntrInfo.getRowCount();
		for (var i = 0; i < cntrRows; i++) {
			if ((ds_cntrInfo.getCellData(i, "arvWrkPlCd")).trim() != "") {
				idx = i;
				break;
			}			
		}		
		ed_arvWrkPlCd.setValue(ds_cntrInfo.getCellData(idx, "arvWrkPlCd")); 	

		if (cntrRows > 0) {
			ed_arvWrkPlNm.setValue(ds_outCntrInfoByCvsslMgntNo.getCellData(idx, "arvWrkPlNm"));
		} else {
			ed_arvWrkPlNm.setValue("");
		}
	}	

	// 컨테이너정보에 따라서 품명정보의 입력수량 계산하기
	await scwin.f_calInputQty(); 
    sellTotalRows.setValue(ds_sellInfo.getRowCount());
    cntrTotalRows.setValue(ds_cntrInfo.getRowCount());

	scwin.chkInputQtyYn = "N";

	// 데이터셋의 상태를 normal하게 만들기
    ds_blInfo.reform();
    ds_blInfo.modifyAllStatus("R");

    ds_commInfo.reform();
    ds_commInfo.modifyAllStatus("R");

    ds_cntrInfo.reform();
    ds_cntrInfo.modifyAllStatus("R");

	// 조회여부 세팅
	scwin.retrieveYn = "N"; 
};

