scwin.sbm_regist_submitdone = async function(e) {
	// 수입일반인 경우, 추가매출 확인
	scwin.f_retrieveContainerAdditionSelling();

	ed_odrNo.setValue(ds_cndOdrNo.getCellData(0, "odrNo"));

    var k =0;

	// 배차담당자
    ds_orderallocarpicnm.removeAll();

    if (ed_alloccarPicNm1.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm1.getValue())) {
        k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId1);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm1.getValue());
	}

	if (ed_alloccarPicNm2.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm2.getValue())) {
	    k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId2);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm2.getValue());	
	}

	if (ed_alloccarPicNm3.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm3.getValue())) {
	    k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId3);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm3.getValue());		
	}

	if (ed_alloccarPicNm4.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm4.getValue())) {
	    k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId4);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm4.getValue());		
	}

	if (ed_alloccarPicNm5.getValue() != "" && !$c.gus.cfIsNull(ed_alloccarPicNm5.getValue())) {
	    k = k + 1;
        var rowIndex = ds_orderallocarpicnm.insertRow();
        ds_orderallocarpicnm.setCellData(rowIndex, "odrNo", ds_cndOdrNo.getCellData(0, "odrNo"));
        ds_orderallocarpicnm.setCellData(rowIndex, "cntrSeq", (9000 + k));
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicId", scwin.hid_alloccarPicId5);
        ds_orderallocarpicnm.setCellData(rowIndex, "shtlAlloccarPicNm", ed_alloccarPicNm5.getValue());		
	}

    let rnt = await $c.sbm.execute(sbm_regist2);
    if (rnt.responseJSON.resultDataSet[0].Msg == "SUCC") { 
        if (await $c.gus.cfAlertMsg(MSG_CM_INF_001)) { // 성공적으로 저장하였습니다.	
            //parent.putMapValue(  "ODR_KND_CD" , lc_odrKndCd.ValueOfIndex("cd", lc_odrKndCd.Index)) (확인할것);

            // 탭선택시 재조회
            $p.parent().scwin.hid_chkReterieve = "";

            scwin.f_setTabOrderInfo();
            scwin.f_Retrieve();
        }
    }
};

