scwin.acb_selfClsCd_onclick = async function (e) {
	if (scwin.retrieveYn == "N") {
		// 컨테이너를 지정하지 않은 경우 , 자가구분코드를 활성화하므로, 자가구분코드 수정가능하므로 필요한 로직		
		var cntrAssgnYn = "N";
		for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
			if (ds_cntrInfo.getCellData(i, "cntrNo").trim() != "") {
				cntrAssgnYn = "Y";
				break;
			}
		}

		if (cntrAssgnYn == "Y") {
			ds_odrInfo.setCellData(0, "selfClsCd", ds_odrInfo.getOriginalCellData(0, "selfClsCd"));
			if (await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["컨테이너목록에서 컨테이너번호가 지정되어 있으므로, 자가구분코드","변경"])) { //@은(는) @할 수 없습니다
                return;
            }
		}		
	}
};

//-------------------------------------------------------------------------
// Event onchange
//-------------------------------------------------------------------------
scwin.acb_odrKndCd_onchange = function (info) {
    scwin.odrKndCd = acb_odrKndCd.getValue(); // 오더종류코드

    var selValue = acb_odrKndCd.getValue();
    var realIdx = ds_odrKndCd.getMatchedIndex("cd", selValue); // "컬럼ID"는 실제 값 컬럼명
    scwin.impExpClsCd = ds_odrKndCd.getCellData(realIdx[0], "fltrCd2");

    if (scwin.impExpClsCd == "null")
        scwin.impExpClsCd = ""; // TS셔틀컨테이너가 아닌 경우

    scwin.f_setInterfaceByOdr(scwin.odrKndCd, scwin.impExpClsCd);

    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) {
        if (ed_sellLodeptCd.getValue().substring(0, 2) == "6A" || ed_sellLodeptCd.getValue() == null || ed_sellLodeptCd.getValue() == "") {
            $c.gus.cfEnableObj(ed_alloccarPicNm1, false);	//txt_alloccarPicNm1
            $c.gus.cfEnableObj(ed_alloccarPicNm2, false);	//txt_alloccarPicNm2
            $c.gus.cfEnableObj(ed_alloccarPicNm3, false);	//txt_alloccarPicNm3
            $c.gus.cfEnableObj(ed_alloccarPicNm4, false);	//txt_alloccarPicNm4
