// LINE 명 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_lineCd_onblurCodeEvent = function (e) {
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	    // 수입본선
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR	// 수입하역
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_TS_ODR				// 부두간TS
		|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR		// 하선지경유TS(부두-->CY)
	) {
        if (ed_lineCd.getValue().trim() == "") {	
            ed_lineNm.setValue("");
            ed_shpCoClntNm.setValue("");
            scwin.f_clearDataByCvsslMgntNo(); // 본선관리번호와 관련한 데이터셋 Clear
        } else {
            scwin.f_beforeOpenCommonPopUpEd(ed_lineNm, ed_lineCd, 3, '', 'T', 'F');
        }
	} else {
        scwin.f_beforeOpenCommonPopUpEd(ed_lineNm, ed_lineCd, 3, '', 'T', 'F');

        // 수출일반오더,on-hire,off-hire,empty position에만 해당 : 수정하기 전의 BookingNo값으로 가져온 해당 Booking품명 목록 삭제
        if (!$c.gus.cfIsNull(scwin.orgBookingNo)) {
            scwin.f_retrieveBookingInfo("OLD");
        }

        // 수출일반오더,on-hire,off-hire,empty position에만 해당 : booking정보 및 booking품명목록 가져오기
        if (!$c.gus.cfIsNull(ed_lineCd.getValue().trim())) {
            scwin.f_retrieveBookingInfo("NEW");
        }
	}

	if (ed_lineCd.getValue() == "DVTG" && scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR) {
	   dscommon.cf_ShowObject([ lay_dispPchsClsCd ]);
       lay_txt_transCondCdHl.setValue("매입매각");
	} else {
  	   dscommon.cf_HideObject([ lay_dispPchsClsCd ]);
       lay_txt_transCondCdHl.setValue("");
	}
};

