// 그리드 대문자 입력
scwin.gr_cntrInfo_oneditkeyup = function (info) {
    const inputEl = event.target;
    switch (info.colID) {
        case "cntrNo":
        case "impSealNo":
        case "expSealNo":
        case "dptWrkPlCd":
        case "arvWrkPlCd":
        case "portCd":
        case "destPortCd":
            inputEl.value = info.newValue.toUpperCase();
        break;
        default:
        break;
    }
};

scwin.gr_cntrInfo_CustomFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    if (columnId == "wrkRsltsNo") {
        if (ds_cntrInfo.getCellData(rowIndex, "wrkRsltsNo") == "") {
            val = "미생성";
        } else {
            val = "생성";
        }
    } 

    return val;
};

scwin.gr_commInfo_onviewchange = async function (info) {
    var colId = info.colId;
    var colIndex = info.colIndex;
    var newValue = info.newValue;
    var oldValue = info.oldValue;
    var rowIndex = info.rowIndex;

	switch (colId) {
		case "grossWt":
			if (ds_commInfo.getCellData(rowIndex, "grossWt") < 0) {
				ds_commInfo.setCellData(rowIndex, "grossWt", Math.abs(ds_commInfo.getCellData(rowIndex, "grossWt"))); //원래값으로 되돌리기
			}
        break;

		case "qty": 
			if (Number(ds_commInfo.getCellData(rowIndex, colId)) < Number(ds_commInfo.getCellData(rowIndex, "inputQty"))) {
				if (await $c.gus.cfAlertMsg(MSG_CM_ERR_057, ["수량","컨테이너 입력수량"])) { //@은(는) @ 보다 큰 값으로 입력하십시오.
                    ds_commInfo.setCellData(rowIndex, colId, ds_commInfo.getOriginalCellData(rowIndex, colId));
                    return;
                }
			}
        break;	

		case "temper":
			scwin.f_setTemperDryByRFCntr(ds_commInfo, gr_commInfo, rowIndex);
        break;
	}
};

scwin.gr_commInfo_oncellclick = async function (rowIndex, columnIndex, columnId) {
    var prevRow = scwin.gr_commInfo_lastRowIndex;
    var currRow = rowIndex;

    // 1. 행 인덱스가 유효하지 않거나(신규 행 추가 직후 등) 동일 행이면 통과
    if (prevRow === undefined || prevRow === null || prevRow === currRow) {
        scwin.gr_commInfo_lastRowIndex = currRow; // 현재 행을 마지막 행으로 기록하고 종료
        return false;
    }

    if (scwin.retrieveYn == "N") {
        // 유효성 체크 실행
        let ret = await $c.gus.cfValidateGrid(gr_commInfo, null, null, scwin.gr_commInfo_validConfig, "품명목록");

        if (!ret) {
            // 검증 실패 시 이전 행으로 강제 되돌리기 (이때 이 이벤트가 다시 발생하지 않도록 주의)
            ds_commInfo.setRowPosition(prevRow);
            return false; 
        } else {
            // 추가 검증 로직
            if (scwin.f_validateCommAndCntr()) {
                ds_commInfo.setRowPosition(prevRow);
                return false;
            }
        }
    }


    // 모든 검증을 통과했다면 마지막 행 인덱스를 현재 행으로 업데이트
    scwin.gr_commInfo_lastRowIndex = currRow;

    // 컬럼별 스위치 문
    switch (columnId) {
        case "dryYn":
            scwin.f_setTemperDryByRFCntr(ds_commInfo, gr_commInfo, rowIndex);
        break;
    }
};

scwin.gr_cntrInfo_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (columnId == 'dryYn') {
        scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
    }
};

scwin.gr_commInfo_onafteredit = function (rowIndex, columnIndex, value) {
    var colId = gr_commInfo.getColumnID(columnIndex);
	// 사용자가 입력한 컨테이너 종류와 품명목록의 종류가 다른 것이 있는지 체크
	switch (colId) {
		case "cntrSizCd": //컨테이너 size	
			scwin.f_checkCommTypeByCntrTypeOnCloseUpEvent(rowIndex, colId);	
        break;

		case "cntrTypCd": //컨테이너 type	
			scwin.f_checkCommTypeByCntrTypeOnCloseUpEvent(rowIndex, colId);

			// 품명 또는 컨테이너의 type이 RF인 경우, 온도 또는 DRY 필드의 EDIT여부 체크
			scwin.f_setTemperDryByRFCntr(ds_commInfo, gr_commInfo, rowIndex);	

        break;

		case "fullEmptyClsCd": // 컨테이너 F/E	
			scwin.f_checkCommTypeByCntrTypeOnCloseUpEvent(rowIndex, colId);
        break;
	}
};

scwin.gr_cntrInfo_onafteredit = function (rowIndex, columnIndex, value) {
    var colId = gr_commInfo.getColumnID(columnIndex);
	//gr_cntrInfo에서 OnCloseUp이벤트 발생시, 품명목록을 체크한 후, 수량 업데이트하기

	switch (colId) {
		case "cntrSizCd": //컨테이너 size
			scwin.f_setCntrGridCloseUp(rowIndex);
        break;

		case "cntrTypCd": //컨테이너 type
			scwin.f_setCntrGridCloseUp(rowIndex);

			// 품명 또는 컨테이너의 type이 RF인 경우, 온도 또는 DRY 필드의 EDIT여부 체크
			scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);					
        break;

		case "fullEmptyClsCd": //컨테이너 F/E
			scwin.f_setCntrGridCloseUp(rowIndex);
        break;
	}
};

scwin.gr_cntrInfo_ontextimageclick = function (rowIndex, columnIndex) {
    var colId = gr_cntrInfo.getColumnID(columnIndex);
	switch (colId) {
		case "dptWrkPlCd": // 출발지
			scwin.f_openPopUpGrid(ds_cntrInfo, rowIndex, "dptWrkPlCd", "dptWrkPlNm", 5, "F", "F");
        break;

		case "arvWrkPlCd": // 도착지
			scwin.f_openPopUpGrid(ds_cntrInfo, rowIndex, "arvWrkPlCd", "arvWrkPlNm", 1, "F", "F");
        break;

		case "currPosCd": // 현위치
			scwin.f_openPopUpGrid(ds_cntrInfo, rowIndex, "currPosCd", "currPosNm", 2, "F", "F");
        break;

		case "portCd": // PORT
			scwin.f_openPopUpGrid(ds_cntrInfo, rowIndex, "portCd", "portNm", 3, "F", "F");
        break;

		case "destPortCd": // 목적항구
			scwin.f_openPopUpGrid(ds_cntrInfo, rowIndex, "destPortCd", "destPortNm", 4, "F", "F");
        break;
	}
};


scwin.gr_commInfo_onbeforeedit = function (rowIndex, columnIndex, value) {
    var colId = gr_commInfo.getColumnID(columnIndex);

    if (colId == "cntrSizCd" || colId == "cntrTypCd" || colId == "fullEmptyClsCd") {
        scwin.orgCommVal = ds_commInfo.getCellData(rowIndex, colId);
    }	
};

scwin.gr_cntrInfo_onviewchange = async function (info) {
    var colid = info.colId;
    var colIndex = info.colIndex;
    var newValue = info.newValue;
    var olddata = info.oldValue;
    var row = info.rowIndex;

    // 팝업관련
	switch (colid) {
		case "dptWrkPlCd":
			scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "dptWrkPlCd", "dptWrkPlNm", olddata, 5, "T", "F");	
        break;

		case "arvWrkPlCd":
			scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "arvWrkPlCd", "arvWrkPlNm", olddata, 1, "T", "F");	

			// 수입본선,수입TS인 경우 : TO작업장변경시 같은 bl의 컨테이너번호의 TO작업장도 변경시킴
			var blNo	   = ds_cntrInfo.getCellData(row, "blNo");
			var arvWrkPlCd = ds_cntrInfo.getCellData(row, "arvWrkPlCd");		

			if (arvWrkPlCd != olddata) {
				if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR	// 수입본선
					|| scwin.odrKndCd == DsConstants.ODR_KND_CD_CY_IMP_TS_ODR		// 하선지경유TS(부두-->CY)
				) {	
					for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
						if (row != i && blNo == ds_cntrInfo.getCellData(i, "blNo")) { // blNo가 같은 경우만 해당
							ds_cntrInfo.setCellData(i, "arvWrkPlCd", arvWrkPlCd);
						}
					}
				}
			}
        break;

		case "currPosCd":
			scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "currPosCd", "currPosNm", olddata, 2, "T", "F");
        break;

		case "portCd":
			scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "portCd", "portNm", olddata, 3, "T", "F");
        break;

		case "destPortCd": // 목적항구
			scwin.f_openPopUpGridBefore(ds_cntrInfo, row, "destPortCd", "destPortNm", olddata, 4, "T", "F");
        break;

		case "cntrNo": // 컨테이너번호
			if (ds_cntrInfo.getCellData(row, colid) == "") {
				// 컨테이너정보에 따라서 품명정보의 입력수량 계산하기
				if (ds_cntrInfo.getCellData(row, colid) != olddata) {
					scwin.f_setCntrInfo(2);								
					scwin.f_calInputQty(); 
				}
			} else {
				if (scwin.chkInputQtyYn == "N") { // 컨테이너번호를 직접 입력한 경우	
					if (ds_cntrInfo.getCellData(row, colid) != olddata) {
						// 컨테이너번호 유효성체크
						scwin.f_checkCntrNo(ds_cntrInfo.getCellData(row, colid));

						for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
							if (ds_cntrInfo.getCellData(i, "cntrNo") == ds_cntrInfo.getCellData(row, colid)) {
								if (row != i && ds_cntrInfo.getRowStatus(i) != "D") {
									if (await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032, ["컨테이너목록", i, "컨테이너번호"])) { //@의 @번째 데이터에서 @은(는) 중복될 수 없습니다.
                                        ds_cntrInfo.setCellData(row, "cntrNo", olddata);
                                        return;
                                    }
								}
							}
						}

                        scwin.f_retrieveCntrBasisInfo(ds_cntrInfo.getCellData(row, colid));

					}
				}
			}
        break;

		case "temper":
			scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, row);
        break;
	}
};

