scwin._ds_commInfo_onbeforerowpositionchange = async function(newRowIndex) {
    if(scwin.retrieveYn == "N"){
	//	if( await $c.gus.cfValidate([gr_commInfo], null, true) ){
        // 유효성 체크 실행
        if(await $c.gus.cfValidateGrid(gr_commInfo, null, null, scwin.gr_commInfo_validConfig, "품명목록")) {
			if( await scwin.f_validateCommAndCntr() ){

			}else{
				return;
			}
		}else{
			return;
		}
	}
    ds_commInfo.setEventPause("onbeforerowpositionchange", true);
    ds_commInfo.setRowPosition(newRowIndex);
    ds_commInfo.setEventPause("onbeforerowpositionchange", false);
};
